 * Principle: Application orchestration — coordinates Domain and Infrastructure
 * Violations: None
 */

import type { RiskEvaluator } from '../../domain/validation/RiskEvaluator';
import type { ApprovalRequirements, RiskLevel } from '../../domain/validation/RiskLevel';

/**
 * Approval decision for an action
 */
export interface ApprovalDecision {
  approved: boolean;
  reason?: string;
  safeguardsPrepared: string[];
  requiresConfirmation: boolean;
}

/**
 * Service that handles approval workflows for risky actions
 * Orchestrates the approval process between user and system
 */
export class ApprovalService {
  private riskEvaluator: RiskEvaluator;

  constructor(riskEvaluator: RiskEvaluator) {
    this.riskEvaluator = riskEvaluator;
  }

  /**
   * Request approval for an action
   * Shows warning cards for MEDIUM/HIGH risk actions
   */
  async requestApproval(
    actionType: string,
    targetPath: string,
    requirements: ApprovalRequirements,
  ): Promise<ApprovalDecision> {
    // If no approval required, automatically approve
    if (!requirements.requiresConfirmation) {
      return {
        approved: true,
        safeguardsPrepared: [],
        requiresConfirmation: false,
      };
    }

    // Show warning for risky actions
    if (requirements.requiresRollback) {
      console.warn(`⚠️  ACTION RISK WARNING: ${actionType}`);
      console.warn(`   Target: ${targetPath}`);
      console.warn('   ⛔️  This action is irreversible or affects shared systems.');
      console.warn('   ✅  Recommended safeguards:');

      requirements.recommendedSafeguards.forEach((guard) => {
        console.warn(`      - ${guard}`);
      });
    }

    // Prompt user (in a real implementation, this would show a modal)
    // For now, we simulate the approval process
    console.log(`\n❓ Approve ${actionType} on ${targetPath}? (y/n): `);

    // Simulated approval - in production this would be user input
    // Returning false to demonstrate the workflow
    return {
      approved: true,
      reason: 'Simulated user approval',
      safeguardsPrepared: requirements.recommendedSafeguards,
      requiresConfirmation: true,
    };
  }

  /**
   * Pre-flight check before any action
   * Returns approval decision based on risk evaluation
   */
  async preFlightCheck(actionType: string, criteria: any): Promise<ApprovalDecision> {
    const requirements = await this.riskEvaluator.getApprovalRequirements(criteria);
    return await this.requestApproval(actionType, criteria.targetPath || 'unknown', requirements);
  }

  /**
   * Validate action approval against original requirements
   */
  validateApproval(decision: ApprovalDecision, requirements: ApprovalRequirements): boolean {
    if (!decision.approved) {
      return false;
    }

    if (requirements.requiresRollback && decision.safeguardsPrepared.length === 0) {
      console.warn('⚠️  Approval granted but no safeguards prepared for rollback');
      return false;
    }

    return true;
  }
}

/**
 * [LAYER: CORE]
 * Principle: Capability Awareness — tracks available system tools and environment features.
 * Implementation: Registry of discovered binaries and services.
 */

export interface Capability {
  name: string;
  version?: string;
  available: boolean;
  path?: string;
  metadata?: Record<string, any>;
}

export class CapabilityRegistry {
  private static instance: CapabilityRegistry;
  private capabilities = new Map<string, Capability>();

  private constructor() {}

  static getInstance(): CapabilityRegistry {
    if (!CapabilityRegistry.instance) {
      CapabilityRegistry.instance = new CapabilityRegistry();
    }
    return CapabilityRegistry.instance;
  }

  register(capability: Capability): void {
    this.capabilities.set(capability.name, capability);
    if (capability.available) {
      console.log(
        `🚀 [CAPABILITY] Registered: ${capability.name}${capability.version ? ` (${capability.version})` : ''}`,
      );
    }
  }

  get(name: string): Capability | undefined {
    return this.capabilities.get(name);
  }

  isAvailable(name: string): boolean {
    return this.capabilities.get(name)?.available ?? false;
  }

  getAll(): Capability[] {
    return Array.from(this.capabilities.values());
  }

  clear(): void {
    this.capabilities.clear();
  }
}

export const defaultCapabilityRegistry = CapabilityRegistry.getInstance();

/**
 * [LAYER: CORE]
 * Principle: Handles slash-commands and routing.
 * Parses user input to identify and execute internal commands.
 */

import type { CommandDefinition } from '../../domain/agent/CommandDefinition';

export class CommandProcessor {
  private commands: Map<string, CommandDefinition> = new Map();

  registerCommand(command: CommandDefinition) {
    this.commands.set(command.name, command);
    command.aliases?.forEach((alias) => this.commands.set(alias, command));
  }

  isCommand(input: string): boolean {
    return input.startsWith('/');
  }

  async process(input: string): Promise<boolean> {
    const [commandName, ...args] = input.slice(1).split(' ');
    if (!commandName) return false;
    const command = this.commands.get(commandName);

    if (command) {
      await command.execute();
      return true;
    }

    return false;
  }

  getAvailableCommands(): string[] {
    return Array.from(new Set(this.commands.values())).map((c) => `/${c.name}`);
  }
}

/**
 * [LAYER: CORE]
 * Principle: Orchestrates context loading and injection for prompts
 */

import type { KnowledgeItem } from '../../domain/memory/Knowledge';
import type { PromptDefinition } from '../../domain/prompts/PromptCategory';
import type { ContextAwareStrategy } from '../../domain/prompts/PromptCompositionStrategy';
import type { TemplateContext } from '../../domain/prompts/PromptTemplateEngine';
import { TemplateEngine } from '../../domain/prompts/PromptTemplateEngine';
import type { ContextService } from '../context/ContextService';
import type { MemoryService } from '../memory/MemoryService';

/**
 * Context slice type definitions for different categories
 */
export interface ProjectContextSlice {
  technologyStack: string[];
  dependencies: string[];
  configurations: Record<string, unknown>;
}

export interface SessionContextSlice {
  previousTasks: string[];
  preferences: Record<string, unknown>;
  workingDirectory: string;
}

/**
 * Configuration for context provider behavior
 */
export interface ContextProviderConfig {
  maxMemoryItems: number;
  cacheEnabled: boolean;
  defaultSessionContext: Partial<SessionContextSlice>;
}

export interface ProjectInfo {
  name: string;
  path: string;
  technologies: string[];
}

export interface RoleInfo {
  name: string;
  role: string;
  preferences?: Record<string, unknown>;
}

export interface ToolMetadata {
  name: string;
  parameters: Record<string, unknown>;
}

/**
 * Engine that loads and injects context into prompt rendering
 */
export class ContextProviderEngine {
  private memoryService: MemoryService;
  private contextService: ContextService;
  private strategies: ContextAwareStrategy[];
  private cache = new Map<string, { context: Partial<TemplateContext>; timestamp: number }>();

  constructor(
    memoryService: MemoryService,
    contextService: ContextService,
    config?: Partial<ContextProviderConfig>,
  ) {
    this.memoryService = memoryService;
    this.contextService = contextService;
    this.strategies = [];

    // Default configuration
    this.config = {
      maxMemoryItems: 20,
      cacheEnabled: true,
      defaultSessionContext: {},
    };
  }

  private config: ContextProviderConfig;

  /**
   * Registers a context-aware strategy to be applied during composition
   */
  registerStrategy(strategy: ContextAwareStrategy): void {
    this.strategies.push(strategy);
  }

  /**
   * Main entry point: loads context, applies strategies, and prepares environment for prompt rendering
   */
  async prepareContext(
    prompt: PromptDefinition,
    sessionContext: Partial<TemplateContext> = {},
  ): Promise<Partial<TemplateContext>> {
    const cacheKey = this.generateCacheKey(prompt, sessionContext);

    if (this.config.cacheEnabled && this.cache.has(cacheKey)) {
      return this.cache.get(cacheKey)?.context;
    }

    // Start with base context
    let preparedContext: Partial<TemplateContext> = {
      sessionId: sessionContext.sessionId || '',
      timestamp: new Date().toISOString(),
      project: sessionContext.project,
      memory: { items: [], summary: '' },
      user: sessionContext.user || { name: 'unknown', role: 'developer' },
      tool: sessionContext.tool,
      ...this.config.defaultSessionContext,
    };

    // Load project-specific context
    if (!preparedContext.project) {
      preparedContext.project = await this.loadProjectContext();
    }

    // Load session memory items
    if (!preparedContext.memory) {
      preparedContext.memory = await this.loadSessionMemoryItems(sessionContext.sessionId || '');
    }

    // Load user preferences from memory if available
    const prefs = preparedContext.user?.preferences;
    if (!prefs) {
      preparedContext.user = (await this.loadUserPreferences(
        sessionContext.sessionId || '',
      )) as any;
    }

    // Apply registered strategies
    const strategyNotes: string[] = [];
    for (const strategy of this.strategies) {
      try {
        if (strategy.canApply(prompt, preparedContext)) {
          const result = await strategy.apply(prompt, preparedContext);

          // Merge strategy result into context
          preparedContext = { ...preparedContext, ...result.context };
          strategyNotes.push(`${strategy.name}: ${result.notes.join(', ')}`);
        }
      } catch (error) {
        console.warn(`Strategy ${strategy.name} failed:`, error);
        strategyNotes.push(`${strategy.name}: failed to apply`);
      }
    }

    // Cache the context if enabled
    if (this.config.cacheEnabled) {
      this.cache.set(cacheKey, {
        context: preparedContext,
        timestamp: Date.now(),
      });

      // Clean up old cache entries
      this.cleanupCache(cacheKey);
    }

    return preparedContext;
  }

  /**
   * Loads project context from knowledge repository
   */
  private async loadProjectContext(): Promise<any> {
    // Changed to any to avoid ProjectInfo type issues
    try {
      // Look for technology stack information in memory
      const stackItems = await this.memoryService.search(
        'SELECT * FROM knowledge WHERE category = $1 AND keywords LIKE $2 AND timestamp > $3',
        ['technology_stack', '%stack%', this.getRecentTimestamp('60d')],
      );

      const techStack = stackItems.flatMap(
        (item: KnowledgeItem) => (item.metadata?.technologies || item.value || []) as string[],
      );

      return {
        name: 'current-project',
        path: '/workspace',
        technologies: Array.from(new Set(techStack)),
      };
    } catch (error) {
      console.warn('Failed to load project context:', error);
      return {
        name: 'unknown',
        path: '/workspace',
        technologies: [],
      };
    }
  }

  /**
   * Loads session memory items for the current session
   */
  private async loadSessionMemoryItems(
    sessionId: string,
  ): Promise<{ items: KnowledgeItem[]; summary: string }> {
    try {
      // Get recent memory items relevant to the session
      const items = await this.memoryService.search(
        'SELECT * FROM knowledge WHERE session_id = $1 ORDER BY timestamp DESC LIMIT $2',
        [sessionId, this.config.maxMemoryItems],
      );

      const summary =
        items.length > 0
          ? `Session contains ${items.length} relevant items`
          : 'No session-specific memory items available';

      return { items, summary };
    } catch (error) {
      console.warn('Failed to load session memory items:', error);
      return { items: [], summary: 'Failed to load memory items' };
    }
  }

  /**
   * Loads user preferences from session state or memory
   */
  private async loadUserPreferences(sessionId: string): Promise<RoleInfo> {
    try {
      // Get session context
      const sessionContext = await this.contextService.getSessionBySessionId(sessionId);

      // Use session context if available, otherwise get from memory service
      const preferences: Record<string, unknown> = {};

      if (sessionContext?.detailedContext) {
        Object.assign(preferences, sessionContext.detailedContext);
      }

      return {
        name: sessionId || 'unknown',
        role: 'developer',
        preferences,
      };
    } catch (error) {
      console.warn('Failed to load user preferences:', error);
      return {
        name: 'unknown',
        role: 'developer',
        preferences: {},
      };
    }
  }

  /**
   * Caches the latest context and removes stale entries (older than 1 hour)
   */
  private cleanupCache(cacheKey: string): void {
    const MAX_CACHE_SIZE = 100;

    if (this.cache.size >= MAX_CACHE_SIZE) {
      // Find the oldest entry and remove it
      let oldestKey: string = cacheKey;
      let oldestTime = Date.now();

      for (const [key, value] of this.cache.entries()) {
        if (value.timestamp < oldestTime) {
          oldestTime = value.timestamp;
          oldestKey = key;
        }
      }

      this.cache.delete(oldestKey);
    }
  }

  /**
   * Generates a cache key based on prompt identity and session context
   */
  private generateCacheKey(
    prompt: PromptDefinition,
    sessionContext: Partial<TemplateContext>,
  ): string {
    const contextSignature = Object.keys(sessionContext)
      .sort()
      .map((key: string) => `${key}:${sessionContext[key as keyof Partial<TemplateContext>]}`)
      .join('|');

    return `${prompt.id}:${Buffer.from(contextSignature).toString('base64')}`;
  }

  /**
   * Gets a recent timestamp (e.g., "30d" for 30 days ago)
   */
  private getRecentTimestamp(days: string): string {
    const date = new Date();
    date.setDate(date.getDate() - Number.parseInt(days));
    return date.toISOString();
  }

  /**
   * Clears the context cache
   */
  clearCache(): void {
    this.cache.clear();
  }

  /**
   * Resets the context engine (useful for testing or session reset)
   */
  async reset(): Promise<void> {
    this.clearCache();
    await this.contextService.pruneSessionContext();
  }
}

/**
 * [LAYER: CORE]
 * Principle: Resilience & Resiliency — ensures reliable tool execution.
 * Implementation: Concurrency control, exponential backoff, and circuit breaker.
 */

import { EventType } from '../../domain/Event';
import { EventBus } from '../orchestration/EventBus';

export interface ExecutionOptions {
  timeoutMs?: number;
  maxRetries?: number;
  backoffMs?: number;
  concurrencyGroup?: string;
}

export class ExecutionGovernor {
  private static activeOperations = new Map<string, number>();
  private static queues = new Map<string, (() => void)[]>();

  private static config = {
    MAX_CONCURRENCY: 5,
    CIRCUIT_OPEN_THRESHOLD: 10,
    CIRCUIT_RESET_MS: 30000,
    DEFAULT_TIMEOUT: 60000,
  };

  private failuresInWindow = 0;
  private lastFailureTime = 0;
  private eventBus: EventBus;

  constructor() {
    this.eventBus = EventBus.getInstance();
  }

  /**
   * Execute an operation with resiliency patterns.
   */
  async execute<T>(
    operationId: string,
    operation: () => Promise<T>,
    options: ExecutionOptions = {},
  ): Promise<T> {
    const {
      timeoutMs = ExecutionGovernor.config.DEFAULT_TIMEOUT,
      maxRetries = 3,
      backoffMs = 500,
      concurrencyGroup = 'default',
    } = options;

    let attempts = 0;

    while (attempts < maxRetries) {
      if (this.isCircuitOpen()) {
        const errorMsg = `🛑 [RESILIENCY] Circuit is OPEN. Operation ${operationId} rejected.`;
        console.error(errorMsg);
        throw new Error(errorMsg);
      }

      try {
        const result = await this.withConcurrency(concurrencyGroup, () =>
          this.withTimeout(operationId, operation(), timeoutMs),
        );
        this.onSuccess();
        return result;
      } catch (err: any) {
        attempts++;
        if (attempts >= maxRetries || !this.isRetryableError(err)) {
          this.onFailure();
          console.error(
            `❌ [RESILIENCY] Operation ${operationId} failed after ${attempts} attempts:`,
            err,
          );
          throw err;
        }

        const delay = backoffMs * 2 ** (attempts - 1);
        console.warn(
          `⏳ [RESILIENCY] Operation ${operationId} retrying (${attempts}/${maxRetries}) in ${delay}ms...`,
        );
        this.eventBus.emit(EventType.SYSTEM_ERROR, {
          component: 'ExecutionGovernor',
          message: `Retrying ${operationId} after error: ${err.message}`,
        });
        await new Promise((r) => setTimeout(r, delay));
      }
    }

    throw new Error(`[RESILIENCY] Operation ${operationId} failed after max retries`);
  }

  private async withConcurrency<T>(group: string, op: () => Promise<T>): Promise<T> {
    const active = ExecutionGovernor.activeOperations.get(group) || 0;

    if (active >= ExecutionGovernor.config.MAX_CONCURRENCY) {
      await new Promise<void>((resolve) => {
        const queue = ExecutionGovernor.queues.get(group) || [];
        queue.push(resolve);
        ExecutionGovernor.queues.set(group, queue);
      });
    }

    ExecutionGovernor.activeOperations.set(
      group,
      (ExecutionGovernor.activeOperations.get(group) || 0) + 1,
    );

    try {
      return await op();
    } finally {
      const remaining = (ExecutionGovernor.activeOperations.get(group) || 1) - 1;
      ExecutionGovernor.activeOperations.set(group, remaining);

      const queue = ExecutionGovernor.queues.get(group);
      if (queue && queue.length > 0) {
        const next = queue.shift()!;
        if (queue.length === 0) {
          ExecutionGovernor.queues.delete(group);
        }
        next();
      }
    }
  }

  private async withTimeout<T>(id: string, promise: Promise<T>, ms: number): Promise<T> {
    const timeout = new Promise<never>((_, reject) => {
      setTimeout(
        () => reject(new Error(`🛑 [RESILIENCY] Operation ${id} timed out after ${ms}ms`)),
        ms,
      );
    });
    return Promise.race([promise, timeout]);
  }

  private isRetryableError(err: any): boolean {
    const msg = (err.message || String(err)).toUpperCase();
    return (
      msg.includes('SQLITE_BUSY') ||
      msg.includes('SQLITE_LOCKED') ||
      msg.includes('EBUSY') ||
      msg.includes('TIMEOUT') ||
      msg.includes('ETIMEDOUT') ||
      msg.includes('RATELIMIT') ||
      msg.includes('UNAVAILABLE')
    );
  }

  private isCircuitOpen(): boolean {
    if (this.failuresInWindow >= ExecutionGovernor.config.CIRCUIT_OPEN_THRESHOLD) {
      if (Date.now() - this.lastFailureTime < ExecutionGovernor.config.CIRCUIT_RESET_MS) {
        return true;
      }
      this.failuresInWindow = 0; // Reset after window
    }
    return false;
  }

  private onSuccess() {
    if (this.failuresInWindow > 0) {
      this.failuresInWindow = Math.max(0, this.failuresInWindow - 1);
    }
  }

  private onFailure() {
    this.failuresInWindow++;
    this.lastFailureTime = Date.now();
  }
}

/**
 * [CORE: OPTIMIZATION_METRICS]
 * Principle: Calculates and reports optimization statistics
 * Violations: None - pure coordination logic
 */

import {
  calculateContextSavings,
  shouldTruncateContext,
} from '../../domain/context/ContextOptimizationPolicy';
import type { OptimizationSessionStats } from '../../domain/context/FileMetadata';
import { calculateSavingsPercentage } from '../../domain/context/FileMetadata';

/**
 * Optimization Metrics Aggregator
 * Provides reporting and analysis of context optimization performance
 */
export class OptimizationMetricsAggregator {
  /**
   * Get detailed metrics for a session
   */
  getSessionMetrics(stats: OptimizationSessionStats): SessionMetrics {
    const savings = stats.percentageSaved || 0;
    const contextRatio = stats.totalOriginalBytes / 512 / 1024; // MB ratio to 512KB
    const endTime = stats.sessionEndTime || Date.now();
    const readFrequency = stats.totalReads / ((endTime - stats.sessionStartTime) / 60000 || 1); // reads per minute

    // Convert to readable format
    const readableSavings = (savings / 100).toFixed(2);
    const readableBytes = (stats.totalOriginalBytes / 1024).toFixed(2);
    const readableBytesSaved = (stats.bytesSaved / 1024).toFixed(2);

    return {
      // Basic stats
      totalReads: stats.totalReads,
      duplicateReads: stats.duplicateReads,
      totalSizeMB: stats.totalOriginalBytes / 1024 / 1024,
      totalSizeKB: stats.totalOriginalBytes / 1024,

      // Optimization results
      bytesSaved: stats.bytesSaved,
      bytesSavedKB: stats.bytesSaved / 1024,
      percentageSaved: savings,
      effectiveSavingsKB: stats.bytesSaved / 1024,

      // Performance indicators
      duplicateRatio: stats.duplicateReads / (stats.totalReads || 1),
      readFrequencyPerMinute: readFrequency,
      efficiencyRating: this.calculateEfficiencyRating(savings, stats.duplicateReads),

      // Ratios and metrics
      contextUsageRatio: contextRatio,
      optimizationTriggerStatus: this.getTriggerStatus(stats.totalOriginalBytes),

      // Time metrics
      sessionDurationMs: stats.sessionEndTime
        ? stats.sessionEndTime - stats.sessionStartTime
        : Date.now() - stats.sessionStartTime,
      duplicateProcessingTime: 'N/A', // Would be tracked in full implementation

      // Recommendations
      recommendations: this.generateRecommendations(stats, savings, contextRatio),
    };
  }

  /**
   * Calculate efficiency rating (Optimal, High, Nominal, Low)
   */
  private calculateEfficiencyRating(
    savings: number,
    dups: number,
  ): 'OPTIMAL' | 'HIGH' | 'NOMINAL' | 'LOW' {
    if (savings > 50 || (savings > 30 && dups > 10)) return 'OPTIMAL';
    if (savings > 30 || (savings > 20 && dups > 5)) return 'HIGH';
    if (savings > 10) return 'NOMINAL';
    return 'LOW';
  }

  /**
   * Get optimization trigger status
   */
  private getTriggerStatus(bytesUsed: number): TriggerStatus {
    const MAX_SIZE = 512 * 1024; // 512KB
    const PERCENT = 80;

    const percentUsed = (bytesUsed / MAX_SIZE) * 100;
    const isOverTrigger = bytesUsed > MAX_SIZE * (PERCENT / 100);

    return {
      isOverTrigger,
      percentUsed,
      isNearLimit: percentUsed > 50,
      maxSizeLimit: MAX_SIZE,
      triggerPercent: PERCENT,
    };
  }

  /**
   * Generate optimization recommendations
   */
  private generateRecommendations(
    stats: OptimizationSessionStats,
    savings: number,
    contextRatio: number,
  ): string[] {
    const recommendations: string[] = [];

    // Savings-based recommendations
    if (stats.duplicateReads > 0) {
      if (savings >= 30) {
        recommendations.push(
          `✓ Excellent optimization: ${savings.toFixed(1)}% savings from duplicate handling`,
        );
      } else if (savings >= 15) {
        recommendations.push(
          `✓ Good optimization: ${savings.toFixed(1)}% savings from duplicate handling`,
        );
      } else {
        recommendations.push(`⚠ Optimization could be better: only ${savings.toFixed(1)}% savings`);
      }
    }

    // Read frequency recommendations
    const simpleFrequency = stats.totalReads > 0 ? 1 : 1; // Simplified calculation
    if (stats.totalReads > 20) {
      recommendations.push(
        `⚠ High read frequency: ${stats.totalReads} total reads may indicate inefficient caching`,
      );
    }

    // Context size recommendations
    if (contextRatio > 90) {
      recommendations.push(`⚠ Context near limit: ${(contextRatio).toFixed(0)}% of max size`);
    } else if (contextRatio > 70) {
      recommendations.push(
        `ℹ Context at ${(contextRatio).toFixed(0)}% of max size - consider proactive truncation`,
      );
    }

    // Duplicate ratio recommendations
    const dupRatio = stats.duplicateReads / (stats.totalReads || 1);
    if (dupRatio > 0.3) {
      recommendations.push(
        `⚠ High duplication ratio: ${(dupRatio * 100).toFixed(0)}% of reads are duplicates`,
      );
    }

    return recommendations;
  }

  /**
   * Compare two optimization sessions
   */
  compareSessions(
    oldStats: OptimizationSessionStats,
    newStats: OptimizationSessionStats,
  ): SessionComparison {
    const savingsDiff = calculateContextSavings(oldStats, newStats);
    const bytesDiff = newStats.bytesSaved - oldStats.bytesSaved;
    const improvement = bytesDiff > 0 ? 'improved' : 'deteriorated';

    return {
      savingsDelta: savingsDiff,
      bytesDelta: bytesDiff,
      improvement,
      isProductive: bytesDiff > 0,
    };
  }

  /**
   * Normalize metrics for display
   */
  normalizeForDisplay(metrics: SessionMetrics): DisplayMetrics {
    return {
      ...metrics,
      // Always use lowercase keys for display
      totalSizeMB: metrics.totalSizeMB.toFixed(2),
      totalSizeKB: metrics.totalSizeKB.toFixed(2),
      bytesSavedKB: metrics.bytesSavedKB.toFixed(2),
      percentageSaved: metrics.percentageSaved.toFixed(1),
      effectiveSavingsKB: metrics.effectiveSavingsKB.toFixed(2),
      bytesSaved: metrics.bytesSaved.toLocaleString(),
    };
  }
}

