import type { FileReuseDecision, PatternSessionStats } from '../../domain/context/FileReadPattern';
import { FileReuseStrategy } from '../../domain/context/FileReadPattern';
import { FileContextTracker } from '../context/FileContextTracker.ts';

/**
 * Configuration for pattern analysis optimization
 */
export interface PatternAnalysisConfig {
  maxReuseCandidates: number; // Max files to consider for reuse
  minReuseConfidence: number; // Minimum confidence threshold
  maxContextReusePerSession: number; // Max reuse count before rotation
  trackTimestampWindowMs: number; // Time window for recent pattern matching
}

/**
 * Default configuration for pattern analysis
 */
export const DEFAULT_PATTERN_CONFIG: PatternAnalysisConfig = {
  maxReuseCandidates: 15,
  minReuseConfidence: 0.7,
  maxContextReusePerSession: 3,
  trackTimestampWindowMs: 600000, // 10 minutes
};

/**
 * Determines which file contexts should be reused based on analysis
 */
export class PatternAnalysisService {
  private tracker = FileContextTracker.getInstance();

  constructor(private config: PatternAnalysisConfig = DEFAULT_PATTERN_CONFIG) {}

  /**
   * Analyze file availability and determine reuse decisions
   */
  analyzePatternAvailability(
    filePaths: string[],
    timestampWindowMs: number = this.config.trackTimestampWindowMs,
  ): FileReuseDecision[] {
    const decisions: FileReuseDecision[] = [];

    for (const filePath of filePaths) {
      const metadata = this.tracker.getMetadata(filePath);
      let decision: FileReuseDecision;

      if (!metadata) {
        // File not tracked - need to load
        decision = {
          filePath,
          strategy: FileReuseStrategy.NO_REUSE,
          shouldReuse: false,
          confidence: 0.2,
          reason: 'low_confidence',
          timestamp: Date.now(),
        };
      } else {
        const isStale = this.tracker.isStale(filePath);
        const hasSignature = !!metadata.signature;

        if (!isStale && hasSignature) {
          // SEMANTIC PINNING: File is tracked, has a signature, and is NOT stale
          decision = {
            filePath,
            strategy: FileReuseStrategy.FULL_REUSE,
            shouldReuse: true,
            confidence: 1.0,
            reason: 'semantic_match',
            timestamp: Date.now(),
          };
        } else if (isStale) {
          // File is stale - MUST reload
          decision = {
            filePath,
            strategy: FileReuseStrategy.NO_REUSE,
            shouldReuse: false,
            confidence: 0.1,
            reason: 'checkpoint_stale',
            timestamp: Date.now(),
          };
        } else {
          // Tracked but no signature yet or other reason
          decision = {
            filePath,
            strategy: FileReuseStrategy.PARTIAL_REUSE,
            shouldReuse: false,
            confidence: 0.4,
            reason: 'metadata_only',
            timestamp: Date.now(),
          };
        }
      }

      decisions.push(decision);
    }

    return decisions;
  }

  /**
   * Apply session-level optimization: prioritize some files, discard others
   */
  optimizeSession(decisions: FileReuseDecision[], stats: PatternSessionStats): FileReuseDecision[] {
    // Sort by confidence (highest first)
    const sorted = [...decisions].sort((a, b) => b.confidence - a.confidence);

    // Select top candidates
    const candidates = sorted.slice(0, this.config.maxReuseCandidates);
    const totalReuseCount = stats.totalReuseCount;

    // Filter based on reuse limits and confidence threshold
    return candidates
      .filter((decision) => decision.confidence >= this.config.minReuseConfidence)
      .filter((_decision, index) =>
        totalReuseCount !== 0 ? index < this.config.maxContextReusePerSession : true,
      );
  }

  /**
   * Update statistics after session optimization
   */
  updateStatistics(
    decisions: FileReuseDecision[],
    stats: PatternSessionStats,
  ): PatternSessionStats {
    const currentReuseCount = decisions.filter((d) => d.shouldReuse).length;

    return {
      totalFiles: stats.totalFiles + decisions.length,
      reuseCandidates: stats.reuseCandidates + currentReuseCount,
      discardedCandidates: stats.discardedCandidates + (decisions.length - currentReuseCount),
      averageReuseConfidence:
        stats.reuseCandidates > 0
          ? (stats.averageReuseConfidence * stats.reuseCandidates +
              decisions.reduce((sum, d) => sum + d.confidence, 0)) /
            (stats.reuseCandidates + decisions.length)
          : decisions.reduce((sum, d) => sum + d.confidence, 0) / decisions.length,
      totalReuseCount: stats.totalReuseCount + currentReuseCount,
      timestamp: Date.now(),
    };
  }

  /**
   * Generate optimization report for human-readable insights
   */
  generateReport(decisions: FileReuseDecision[], stats: PatternSessionStats): string {
    const reuseCount = decisions.filter((d) => d.shouldReuse).length;
    const discardCount = decisions.filter((d) => !d.shouldReuse).length;

    return `
Pattern Analysis Report:
- Total Files: ${stats.totalFiles}
- Reuse Candidates: ${reuseCount}
- Discarded: ${discardCount}
- Avg Confidence: ${(stats.averageReuseConfidence * 100).toFixed(1)}%
- Reuse Limit: ${this.config.maxContextReusePerSession}
- Confidence Threshold: ${(this.config.minReuseConfidence * 100).toFixed(0)}%
    `.trim();
  }
}

/**
 * [LAYER: CORE]
 * Principle: Algorithmic Governance — prevents runaway loops and excessive resource usage.
 * Implementation: Metrics-based threshold enforcement.
 */

export enum GovernanceAction {
  PROCEED = 'PROCEED',
  PAUSE = 'PAUSE',
  BLOCK = 'BLOCK',
}

export interface GovernanceResult {
  action: GovernanceAction;
  reason?: string;
  metrics: {
    toolCallCount: number;
    consecutiveFailures: number;
    totalDurationMs: number;
  };
}

export interface GovernorConfig {
  maxToolCalls: number;
  pauseThreshold: number;
  maxConsecutiveFailures: number;
  maxTotalDurationMs: number;
}

export class ResourceGovernor {
  private metrics = {
    toolCallCount: 0,
    consecutiveFailures: 0,
    totalDurationMs: 0,
  };

  private config: GovernorConfig;

  constructor(config?: Partial<GovernorConfig>) {
    this.config = {
      maxToolCalls: config?.maxToolCalls ?? 50,
      pauseThreshold: config?.pauseThreshold ?? 20,
      maxConsecutiveFailures: config?.maxConsecutiveFailures ?? 3,
      maxTotalDurationMs: config?.maxTotalDurationMs ?? 300000, // 5 minutes
    };
  }

  /**
   * Evaluates whether a tool execution should proceed.
   */
  shouldProceed(toolName: string): GovernanceResult {
    // 1. Check for absolute block on tool calls
    if (this.metrics.toolCallCount >= this.config.maxToolCalls) {
      return this.createResult(
        GovernanceAction.BLOCK,
        `Maximum tool call limit reached (${this.config.maxToolCalls})`,
      );
    }

    // 2. Check for consecutive failures (loop detection)
    if (this.metrics.consecutiveFailures >= this.config.maxConsecutiveFailures) {
      return this.createResult(
        GovernanceAction.BLOCK,
        `Too many consecutive failures (${this.metrics.consecutiveFailures}). Potential loop detected.`,
      );
    }

    // 3. Check for total duration limit
    if (this.metrics.totalDurationMs >= this.config.maxTotalDurationMs) {
      return this.createResult(
        GovernanceAction.BLOCK,
        `Total execution duration limit reached (${this.metrics.totalDurationMs}ms)`,
      );
    }

    // 4. Check for pause threshold (requires user confirmation)
    if (this.metrics.toolCallCount >= this.config.pauseThreshold) {
      return this.createResult(
        GovernanceAction.PAUSE,
        `Pause threshold reached (${this.metrics.toolCallCount} calls). Requesting user confirmation.`,
      );
    }

    return this.createResult(GovernanceAction.PROCEED);
  }

  /**
   * Records a tool invocation.
   */
  recordInvocation(toolName: string): void {
    this.metrics.toolCallCount++;
  }

  /**
   * Records a tool completion result.
   */
  recordResult(toolName: string, success: boolean, durationMs: number): void {
    this.metrics.totalDurationMs += durationMs;
    if (success) {
      this.metrics.consecutiveFailures = 0;
    } else {
      this.metrics.consecutiveFailures++;
    }
  }

  private createResult(action: GovernanceAction, reason?: string): GovernanceResult {
    return {
      action,
      reason,
      metrics: { ...this.metrics },
    };
  }

  getMetrics() {
    return { ...this.metrics };
  }

  reset(): void {
    this.metrics = {
      toolCallCount: 0,
      consecutiveFailures: 0,
      totalDurationMs: 0,
    };
  }
}

/**
 * [LAYER: CORE]
 * Principle: Implements risk-aware prompt composition strategy
 */

import type { PromptDefinition } from '../../domain/prompts/PromptCategory';
import { PromptCategory } from '../../domain/prompts/PromptCategory';
import type { PatternAwareStrategy } from '../../domain/prompts/PromptCompositionStrategy';
import {
  type RiskFactor,
  type RiskProfile,
  RiskTier,
  SafeguardFactory,
} from '../../domain/prompts/PromptRiskProfile';
import type { TemplateContext } from '../../domain/prompts/PromptTemplateEngine';

/**
 * Strategy that wraps prompts with risk assessment and safety instructions based on dangerLevel
 */
export class RiskAwareCompositionStrategy implements PatternAwareStrategy {
  readonly name = 'risk-aware-composition';

  private patternTemplate: string;

  constructor() {
    this.patternTemplate = this.getRiskAssessmentPattern();
  }

  canApply(prompt: PromptDefinition, context: Partial<TemplateContext>): boolean {
    // Apply to prompts with explicit danger level or high-risk categories
    return !!(prompt.dangerLevel || this.isHighRiskCategory(prompt.category));
  }

  async apply(
    prompt: PromptDefinition,
    context: Partial<TemplateContext>,
  ): Promise<{ prompt: string; notes: string[] }> {
    const notes: string[] = [];

    // Assess risk level
    const riskProfile = this.assessRisk(prompt, context);

    // Select appropriate safeguards
    const safeguards = SafeguardFactory.getSafeguardsForTier(riskProfile.tier);
    const escalationStage = riskProfile.escalation_stage || 'before_tool';

    notes.push(`Risk tier: ${riskProfile.tier}`);
    notes.push(`Safeguards: ${safeguards.map((s) => s.type).join(', ')}`);

    // Wrap prompt with risk assessment instructions
    const wrappedPrompt = this.wrapPromptWithRiskAssessment(
      prompt.content,
      riskProfile,
      safeguards,
      escalationStage,
      context,
    );

    return { prompt: wrappedPrompt, notes };
  }

  /**
   * Assess risk based on prompt metadata and context
   */
  private assessRisk(prompt: PromptDefinition, context: Partial<TemplateContext>): RiskProfile {
    const dangerLevel = prompt.dangerLevel || 'low';

    // Map danger levels to risk tiers
    const tierMap: Record<string, RiskTier> = {
      critical: RiskTier.HIGH,
      high: RiskTier.HIGH,
      medium: RiskTier.MEDIUM,
      low: RiskTier.LOW,
    };

    const tier = tierMap[dangerLevel] || RiskTier.MEDIUM;

    // Build assumptions list
    const assumptions = this.buildAssumptions(prompt, context);

    return {
      promptId: prompt.id,
      tier,
      safeguarding: SafeguardFactory.getSafeguardsForTier(tier),
      factors: this.identifyRiskFactors(prompt, context),
      assumptions,
      escalation_stage: tier === RiskTier.HIGH ? 'before_tool' : 'before_tool',
      recommended_tools: this.getRecommendedTools(tier),
    };
  }

  /**
   * Determine escalation strategy based on risk tier
   */
  private determineEscalationStrategy(): 'before_tool' | 'after_tool' | 'on_failure' {
    const strategies = ['before_tool', 'after_tool', 'on_failure'];
    return strategies[Math.floor(Math.random() * strategies.length)] as
      | 'before_tool'
      | 'after_tool'
      | 'on_failure';
  }

  /**
   * Generate assumptions from prompt context
   */
  private buildAssumptions(prompt: PromptDefinition, context: Partial<TemplateContext>): string[] {
    const assumptions: string[] = [];

    if (!context.project?.name) {
      assumptions.push('Project name not available');
    }

    if (!context.sessionId) {
      assumptions.push('Session ID not available');
    }

    if (
      prompt.category === PromptCategory.SYSTEM_CORE ||
      prompt.category === PromptCategory.SECURITY_PATTERNS
    ) {
      assumptions.push('Production system at risk if error occurs');
    }

    if (!context.project?.technologies || (context.project.technologies as string[]).length === 0) {
      assumptions.push('Technology stack not detected');
    }

    return assumptions;
  }

  /**
   * Identify risk factors based on prompt properties
   */
  private identifyRiskFactors(
    prompt: PromptDefinition,
    context: Partial<TemplateContext>,
  ): RiskFactor[] {
    const factors: RiskFactor[] = [];

    // Build derived risk factors
    const isHighRisk = ['critical', 'high'].includes(prompt.dangerLevel || '');

    if (prompt.dangerLevel && isHighRisk) {
      factors.push({
        factor: 'sensitivity',
        value: prompt.dangerLevel,
        severity: 'high',
      });
    }

    if (context.project?.technologies) {
      const techArray = context.project.technologies as any[];
      factors.push({
        factor: 'scope',
        value: `${(techArray as string[]).length} technologies`,
        severity: 'medium',
      });
    }

    if (
      prompt.category === PromptCategory.TOOL_PROTOCOLS ||
      prompt.category === PromptCategory.SECURITY_PATTERNS
    ) {
      factors.push({
        factor: 'system_impact',
        value: 'system-level changes',
        severity: 'high',
      });
    }

    if (prompt.content.includes('DELETE') || prompt.content.includes('DROP')) {
      factors.push({
        factor: 'reversibility',
        value: 'destructive operations',
        severity: 'high',
      });
    }

    return factors;
  }

  /**
   * Get recommended tools based on risk tier
   */
  private getRecommendedTools(tier: RiskTier): string[] | undefined {
    switch (tier) {
      case RiskTier.LOW:
        return [];
      case RiskTier.MEDIUM:
        return ['pre-commit-hooks', 'semantic-release', 'docker-compose'];
      case RiskTier.HIGH:
        return ['backups', 'sandbox-environments', 'rollback-plans', 'communication'];
      default:
        return [];
    }
  }

  /**
   * Get the risk assessment pattern template from claude-code-prompts
   */
  private getRiskAssessmentPattern(): string {
    return `---
# Risk Assessment for This Prompt

RISK EVALUATION
---
Risk Level: {{risk.tier}}
Confidence: {{confidence}}

RISK FACTORS
---
{% for factor in risk.factors %}
- {{factor.factor}}: {{factor.value}} (severity: {{factor.severity}})
{% endfor %}

SAFEGUARDS REQUIRED
---
{% for safeguard in risk.safeguarding %}
- [{{safeguard.required ? 'X' : ' '}}] {{safeguard.description}} (type: {{safeguard.type}})
{% endfor %}

ASSUMPTIONS
---
{% for assumption in risk.assumptions %}
- {{assumption}}
{% endfor %}

ASSUMED TOOLS / COMMANDS
---
{% if risk.recommended_tools %}
{% for tool in risk.recommended_tools %}
- {{tool}}
{% endfor %}
{% else %}
None recommended
{% endif %}

VERIFICATION REQUIREMENTS
---
{{risk.assumptions.length > 2 ? 'Required: Run comprehensive tests, backup operations, and rollback preparation.' : 'Required: Run basic checks and documentation.'}}

OUTPUT REQUIREMENTS
---
1. Document risk tier and rationale
2. List all safeguards applied
3. Report verification results
4. Note any deviations from assumptions`;
  }

  /**
   * Wrap the prompt content with the risk assessment pattern
   */
  private wrapPromptWithRiskAssessment(
    promptContent: string,
    riskProfile: RiskProfile,
    safeguards: any[],
    escalationStage: string,
    context: Partial<TemplateContext>,
  ): string {
    // Template context for this specific wrapping
    const wrapperContext = {
      risk: {
        tier: riskProfile.tier,
        confidence: 0.85, // Default confidence, could be dynamic
        factors: riskProfile.factors,
        safeguarding: safeguards,
        assumptions: riskProfile.assumptions,
        recommended_tools: riskProfile.recommended_tools,
      },
      escalation_stage: escalationStage,
    };

    // Merge original prompt with assessment
    return `# Risk Assessment Precondition

${this.patternTemplate}

---

${promptContent}`;
  }

  /**
   * Determine if a category is high-risk by default
   */
  private isHighRiskCategory(category: string): boolean {
    const HIGH_RISK_CATEGORIES = [
      PromptCategory.TOOL_PROTOCOLS,
      PromptCategory.SECURITY_PATTERNS,
      PromptCategory.AGENT_ORCHESTRATION,
      PromptCategory.VERIFICATION_CHECKPOINTS,
      PromptCategory.UTILITY_OPERATIONS,
    ];

    return HIGH_RISK_CATEGORIES.includes(category as PromptCategory);
  }
}

