/**
 * [LAYER: CORE]
 * Principle: Centralized tracking of file context, state, and optimization.
 * Combined logic: Migration from Capabilities + Cline-inspired State Tracking.
 *
 * Orchestrates file watching, state management, stale detection,
 * and duplicate read optimization (Two-Finger Pattern).
 */

import { EventBus } from '../../core/orchestration/EventBus';
import { EventType } from '../../domain/Event';
import type { OptimizationConfig } from '../../domain/context/ContextOptimizationPolicy';
import { defaultOptimizationConfig } from '../../domain/context/ContextOptimizationPolicy';
import { FileChangeType } from '../../domain/context/FileChange';
import type {
  FileOperationSource,
  FileState,
  FileMetadataEntry as StateMetadata,
} from '../../domain/context/FileContextContract';
import type {
  DuplicateReadMetadata,
  FileOptimizationDecision,
  OptimizationSessionStats,
  ReadEntry,
} from '../../domain/context/FileMetadata';
import { aggregateReadMetadata, isReadDuplicate } from '../../domain/context/FileMetadata';
import type { FileReadResult, FileReadSource } from '../../domain/context/FileOperation';
import type {
  LivePathContext,
  RuleEvaluationContext,
  ToolIntent,
} from '../../domain/context/RuleContextContract';
import { Core } from '../../infrastructure/database/sovereign/Core';
import type {
  FileWatcherAdapter,
  FileWatcherEvent,
} from '../../infrastructure/watcher/FileWatcherAdapter';

export class FileContextTracker {
  private static instance: FileContextTracker | null = null;

  // --- State Tracking (Cline-inspired) ---
  private stateMetadata: Map<string, StateMetadata> = new Map();
  private watcher: FileWatcherAdapter | null = null;

  // --- Optimization Tracking (Legacy Capabilities) ---
  private readBuffer: ReadEntry[] = [];
  private optimizationMetadata: Map<string, DuplicateReadMetadata> = new Map();
  private config: OptimizationConfig;
  private sessionStartTimestamp: number;
  private optimizationCallback?: (decision: FileOptimizationDecision) => void;

  constructor(config?: Partial<OptimizationConfig>) {
    this.config = {
      ...defaultOptimizationConfig,
      ...config,
    };
    this.sessionStartTimestamp = Date.now();
  }

  static getInstance(config?: Partial<OptimizationConfig>): FileContextTracker {
    if (!FileContextTracker.instance) {
      FileContextTracker.instance = new FileContextTracker(config);
    }
    return FileContextTracker.instance;
  }

  // === WATCHER INTEGRATION ===

  /**
   * Initialize the tracker with a watcher
   */
  async setWatcher(watcher: FileWatcherAdapter): Promise<void> {
    this.watcher = watcher;
    this.watcher.onFileChange(async (event) => this.handleFileChangeEvent(event));

    // Initial sync from DB
    await this.sync();
  }

  /**
   * Sync persistent state from modular Sovereign DB
   */
  async sync(): Promise<void> {
    const db = await Core.db();
    const rows = await (db as any)
      .selectFrom('file_context' as any)
      .selectAll()
      .execute();

    for (const row of rows as any[]) {
      this.stateMetadata.set(row.path, {
        path: row.path,
        state: row.state as FileState,
        source: row.source as FileOperationSource,
        lastReadDate: row.lastReadDate,
        lastEditDate: row.lastEditDate,
        signature: row.signature,
        externalEditDetected: Boolean(row.externalEditDetected),
      });
    }
    console.log(`📡 [ContextTracker] Synced ${rows.length} files from SovereignDb`);
  }

  /**
   * Handle events from the file watcher
   */
  private async handleFileChangeEvent(event: FileWatcherEvent): Promise<void> {
    const existing = this.stateMetadata.get(event.path);
    if (!existing) return;

    if (event.type === FileChangeType.MODIFIED) {
      // If we get here, it wasn't a self-edit (handled by markAsEditedByAgent)
      existing.state = 'modified_externally';
      existing.externalEditDetected = true;
      existing.lastEditDate = event.timestamp;

      // Persist the staleness immediately
      await this.persistState(existing);

      console.warn(`⚠️ External modification detected on ${event.path}. Context is now STALE.`);
    } else if (event.type === FileChangeType.DELETED) {
      existing.state = 'deleted';
    }
  }

  // === OPTIMIZATION LOGIC (Merged) ===

  /**
   * Register an optimization event callback
   */
  onOptimization(callback: (decision: FileOptimizationDecision) => void): void {
    this.optimizationCallback = callback;
  }

  /**
   * Record a file read operation with optimization
   * @returns The optimized file read result
   */
  async recordRead(
    filePath: string,
    content: string,
    source: FileReadSource,
  ): Promise<FileReadResult> {
    const entry: ReadEntry = {
      filePath,
      content,
      timestamp: Date.now(),
      contentHash: await this.calculateHash(content),
      source,
      originalLength: content.length,
    };

    // Update State Tracking
    await this.recordState(filePath, 'read_tool', 'read', entry.contentHash);

    return this.processReadEntry(entry);
  }

  /**
   * Process a single read entry (Optimization)
   */
  private processReadEntry(entry: ReadEntry): FileReadResult {
    const duplicateMetadata = this.getFileDuplicateMetadata(entry.filePath);
    const isDuplicate = this.detectDuplicateRead(entry, duplicateMetadata);

    let result: FileReadResult;

    if (isDuplicate) {
      if (this.config.enableTwoFinger) {
        result = this.applyTwoFingerPattern(entry.filePath);

        if (this.optimizationCallback) {
          this.optimizationCallback({
            filePath: entry.filePath,
            keepOriginal: false,
            applyTwoFingerPattern: true,
            duplicateWindowMs: this.config.duplicateWindowMs,
            savingsThreshold: this.config.savingsThreshold,
            calculatedSavings: this.calculateSavingsPercentage(
              duplicateMetadata.firstReadContentHash.length,
              43,
            ),
            reason: `duplicate_within_${this.config.duplicateWindowMs}ms_window`,
          });
        }
      } else {
        result = {
          ...entry,
          optimizedLength: entry.originalLength,
          wasOptimized: false,
          hash: entry.contentHash,
          sizeBytes: entry.originalLength,
        };
      }
      this.updateOptimizationMetadata(entry.filePath, entry.timestamp, duplicateMetadata);
    } else {
      result = {
        ...entry,
        optimizedLength: entry.originalLength,
        wasOptimized: false,
        hash: entry.contentHash,
        sizeBytes: entry.originalLength,
      };

      this.readBuffer.push(entry);

      duplicateMetadata.firstReadTimestamp = entry.timestamp;
      duplicateMetadata.firstReadContentHash = entry.contentHash;
      duplicateMetadata.duplicateCount = 1;
      duplicateMetadata.subsequentReadTimestamps = [];
      duplicateMetadata.isDuplicate = false;

      this.optimizationMetadata.set(entry.filePath, duplicateMetadata);
    }

    return result;
  }

  // === STATE TRACKING LOGIC (Merged) ===

  /**
   * Record a state change (Record of Truth)
   */
  async recordState(
    path: string,
    source: FileOperationSource,
    type: 'read' | 'edit' | 'delete',
    signature?: string,
  ): Promise<void> {
    const existing = this.stateMetadata.get(path);
    const now = Date.now();

    const entry: StateMetadata = {
      path,
      state: type === 'delete' ? 'deleted' : 'active',
      source,
      lastReadDate: type === 'read' ? now : existing?.lastReadDate || null,
      lastEditDate: type === 'edit' ? now : existing?.lastEditDate || null,
      externalEditDetected: false,
      signature: signature || existing?.signature,
    };

    this.stateMetadata.set(path, entry);
    await this.persistState(entry);

    if (type === 'edit' && source === 'codemarie_edited' && this.watcher) {
      this.watcher.markAsEditedByAgent(path);
    }
  }

  /**
   * Persist state entry to modular Sovereign DB
   */
  private async persistState(entry: StateMetadata): Promise<void> {
    const db = await Core.db();

    // Check if exists first for upsert simulation in broccoliq (Kysely)
    const existing = await (db as any)
      .selectFrom('file_context' as any)
      .where('path', '=', entry.path)
      .executeTakeFirst();

    if (existing) {
      await (db as any)
        .updateTable('file_context' as any)
        .set({
          state: entry.state,
          source: entry.source,
          lastReadDate: entry.lastReadDate,
          lastEditDate: entry.lastEditDate,
          signature: entry.signature,
          externalEditDetected: entry.externalEditDetected ? 1 : 0,
        })
        .where('path', '=', entry.path)
        .execute();
    } else {
      await (db as any)
        .insertInto('file_context' as any)
        .values({
          path: entry.path,
          state: entry.state,
          source: entry.source,
          lastReadDate: entry.lastReadDate,
          lastEditDate: entry.lastEditDate,
          signature: entry.signature,
          externalEditDetected: entry.externalEditDetected ? 1 : 0,
        })
        .execute();
    }
  }

  /**
   * Get metadata for a file
   */
  getMetadata(path: string): StateMetadata | undefined {
    return this.stateMetadata.get(path);
  }

  /**
   * Check if context for a file is stale
   */
  isStale(path: string): boolean {
    const metadata = this.stateMetadata.get(path);
    return metadata
      ? metadata.state === 'modified_externally' || metadata.state === 'stale'
      : false;
  }

  // === HELPERS ===

  private getFileDuplicateMetadata(filePath: string): DuplicateReadMetadata {
    const existing = this.optimizationMetadata.get(filePath);
    return (
      existing || {
        filePath,
        firstReadTimestamp: 0,
        subsequentReadTimestamps: [],
        firstReadContentHash: '',
        duplicateCount: 0,
        isDuplicate: false,
      }
    );
  }

  private detectDuplicateRead(entry: ReadEntry, metadata: DuplicateReadMetadata): boolean {
    if (metadata.duplicateCount === 0) return false;
    const timeSinceFirstRead = Date.now() - metadata.firstReadTimestamp;
    const timeWindowExceeded = timeSinceFirstRead > this.config.duplicateWindowMs;
    return !timeWindowExceeded && entry.contentHash === metadata.firstReadContentHash;
  }

  private updateOptimizationMetadata(
    filePath: string,
    timestamp: number,
    metadata: DuplicateReadMetadata,
  ): void {
    metadata.lastReadTimestamp = timestamp;
    metadata.duplicateCount++;
    metadata.subsequentReadTimestamps.push(timestamp);
    metadata.isDuplicate = true;
    this.optimizationMetadata.set(filePath, metadata);
    if (metadata.subsequentReadTimestamps.length > 100) {
      metadata.subsequentReadTimestamps.shift();
    }
  }

  private applyTwoFingerPattern(filePath: string): FileReadResult {
    return {
      filePath,
      content: 'Duplicate file read notice',
      timestamp: Date.now(),
      source: 'context_optimization',
      originalLength:
        this.optimizationMetadata.get(filePath)?.firstReadContentHash.length ||
        filePath.length + 43,
      optimizedLength: 43,
      wasOptimized: true,
      optimizationReason: 'two_finger_pattern',
      hash: `duplicate-notice-${Date.now()}`,
      sizeBytes: 43,
    };
  }

  private calculateSavingsPercentage(originalLength: number, optimizedLength: number): number {
    if (originalLength === 0) return 0;
    return ((originalLength - optimizedLength) / originalLength) * 100;
  }

  private async calculateHash(content: string): Promise<string> {
    try {
      const encoder = new TextEncoder();
      const data = encoder.encode(content);
      const hashBuffer = await globalThis.crypto.subtle.digest('SHA-256', data);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      return hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
    } catch (error) {
      let hash = 0;
      for (let i = 0; i < content.length; i++) {
        hash = (hash << 5) - hash + content.charCodeAt(i);
        hash = (hash & hash) >>> 0;
      }
      return hash.toString(36);
    }
  }

  /**
   * Get optimization statistics for the current session
   */
  getSessionStats(): OptimizationSessionStats {
    const { duplicateMetadata } = aggregateReadMetadata(this.readBuffer);
    const applicableFiles = Array.from(duplicateMetadata.keys());
    const totalOriginalBytes = this.readBuffer.reduce((sum, e) => sum + e.originalLength, 0);

    return {
      totalReads: this.readBuffer.length,
      duplicateReads: applicableFiles.length,
      totalOriginalBytes,
      totalOptimizedBytes: totalOriginalBytes,
      bytesSaved: 0,
      percentageSaved: 0,
      applicableFiles,
      duplicatesProcessed: 0,
      sessionStartTime: this.sessionStartTimestamp,
    };
  }

  clearBuffer(): void {
    this.readBuffer = [];
    this.optimizationMetadata.clear();
    this.stateMetadata.clear();
  }
}

/**
 * [LAYER: CORE]
 * Principle: Intelligent extraction of path context for rule activation.
 * Inspired by Cline's RuleContextBuilder.
 *
 * Extracts possible file paths from messages, tabs, and tool operations
 * to provide a ranked list of relevant candidates for rule evaluation.
 */

import type {
  LivePathContext,
  RuleEvaluationContext,
  ToolIntent,
} from '../../domain/context/RuleContextContract.ts';

export class RuleContextBuilder {
  private static readonly MAX_CANDIDATES = 100;

  /**
   * Builds the comprehensive evaluation context
   */
  static async buildContext(
    lastMessage?: string,
    visibleTabs: string[] = [],
    completedTools: { tool: string; path?: string }[] = [],
    pendingIntents: ToolIntent[] = [],
  ): Promise<LivePathContext> {
    const candidates = new Set<string>();

    // 1. Extract from latest message (High Confidence)
    if (lastMessage) {
      const pathsIdentified = RuleContextBuilder.extractPathsFromText(lastMessage);
      pathsIdentified.forEach((p) => candidates.add(p));

      const mentions = RuleContextBuilder.extractMentions(lastMessage);
      mentions.forEach((m) => candidates.add(m));
    }

    // 2. Extract from visible tabs (Current Focus)
    visibleTabs.forEach((p) => candidates.add(p));

    // 3. Extract from completed operations (Recent History)
    completedTools.forEach((op) => {
      if (op.path) candidates.add(op.path);
    });

    // 4. Extract from pending tool intents (Future Intent)
    pendingIntents.forEach((intent) => {
      if (intent.path) candidates.add(intent.path);
      if (intent.content) {
        const patchPaths = RuleContextBuilder.extractPathsFromPatch(intent.content);
        patchPaths.forEach((p) => candidates.add(p));
      }
    });

    return {
      paths: Array.from(candidates).sort().slice(0, RuleContextBuilder.MAX_CANDIDATES),
      lastMessageText: lastMessage,
      visibleTabs,
      completedOperations: completedTools.map((op) => `${op.tool}:${op.path || ''}`),
      pendingOperations: pendingIntents,
    };
  }

  /**
   * Extract potential paths from plain text using regex
   */
  private static extractPathsFromText(text: string): string[] {
    // Regex looking for common path patterns, including [MODIFY] [file](file:///...)
    const pathRegex = /(?:[a-zA-Z]:\\|[\\\/])?(?:[\w\-. ]+[\\\/])*[\w\-. ]+\.[\w\-]{2,}/g;
    const markdownPathRegex = /\[.*?\]\(file:\/\/\/(.*?)\)/g;

    const results: string[] = [];

    let m: RegExpExecArray | null;
    while ((m = pathRegex.exec(text))) {
      results.push(RuleContextBuilder.normalizePath(m[0]!));
    }

    while ((m = markdownPathRegex.exec(text))) {
      results.push(RuleContextBuilder.normalizePath(m[1]!));
    }

    return results;
  }

  /**
   * Extract paths from @mentions (e.g. "Check @src/core/context/Tracker.ts")
   */
  private static extractMentions(text: string): string[] {
    const mentionRegex = /@([\w\-. \/]+\.[\w\-]{2,})/g;
    const results: string[] = [];
    let m: RegExpExecArray | null;
    while ((m = mentionRegex.exec(text))) {
      results.push(RuleContextBuilder.normalizePath(m[1]!));
    }
    return results;
  }

  /**
   * Extract paths from patch headers (e.g. *** Add File: path/to/file.ts)
   */
  private static extractPathsFromPatch(patch: string): string[] {
    const paths: string[] = [];
    const fileHeaderRegex = /^\*\*\* (?:Add|Update|Delete) File: (.+?)(?:\n|$)/gm;
    let m: RegExpExecArray | null;
    while ((m = fileHeaderRegex.exec(patch))) {
      paths.push(RuleContextBuilder.normalizePath((m[1] || '').trim()));
    }
    return paths;
  }

  /**
   * Normalize path to POSIX style and remove leading slash
   */
  private static normalizePath(filePath: string): string {
    return filePath.replace(/\\/g, '/').replace(/^\//, '').trim();
  }
}

/**
 * [LAYER: CORE]
 * Principle: Orchestrate external sync between local and remote
 * Prework Status: Not applicable (new file)
 *
 * Coordinates bidirectional state synchronization with external services.
 * Handles conflicts, conflict resolution, and sync status tracking.
 */

import type {
  RollbackStrategy,
  StateChange,
  StateChangePhase,
  StateChangeResult,
} from '../../domain/state/StateChangeProtocol';
import type { BuildInProof } from '../../domain/system/FileMetadata';

/**
 * External sync configuration
 */
export interface ExternalSyncConfig {
  /**
   * Active external sync services
   */
  services: string[];

  /**
   * Conflict resolution strategy
   */
  conflictResolution: 'local' | 'remote' | 'auto';
}

/**
 * Sync status
 */
export enum SyncStatus {
  SYNCING = 'syncing', // Currently syncing
  IDLE = 'idle', // No sync needed
  COMMITTED = 'committed', // Changes committed successfully
  CONFLICT = 'conflict', // Conflict detected
  FAILED = 'failed', // Sync failed
  OUT_OF_SYNC = 'out_of_sync', // Local and remote have different states
}

/**
 * Sync event
 */
export interface SyncEvent {
  type: 'start' | 'complete' | 'conflict' | 'error' | 'source_change';
  service: string;
  changesCount: number;
  local?: BuildInProof;
  remote?: BuildInProof;
  error?: string;
  timestamp: number;
}

/**
 * Conflict information
 */
export interface ConflictDetails {
  key: string;
  localValue: unknown;
  remoteValue: unknown;
  timestamp: number;
  detectedAt: number;
  source: 'local' | 'remote' | 'both';
}

/**
 * ExternalSyncAdapter
 *
 * Orchestrates bidirectional state synchronization with external services.
 * Handles conflict detection, resolution, and status tracking.
 *
 * Key responsibilities:
 * - Sync state changes to external services
 * - Manage state conflicts between local and remote
 * - Track sync status and events
 * - Handle external source change notifications
 * - Provide conflict resolution strategies
 */
export class ExternalSyncAdapter {
  private static instance: ExternalSyncAdapter | null = null;

  private currentStatus: SyncStatus = SyncStatus.IDLE;
  private currentEvents: SyncEvent[] = [];
  private conflicts: Map<string, ConflictDetails[]> = new Map();
  private statusObservers = new Map<string, Set<(status: SyncStatus) => Promise<void>>>();
  private syncStrategy: 'local' | 'remote' | 'auto';

  private constructor(config: ExternalSyncConfig, rollbackStrategy?: RollbackStrategy) {
    this.syncStrategy = config.conflictResolution;
    // rollbackStrategy would be used for conflict rollback
    console.log(`🔌 ExternalSyncAdapter initialized (strategy: ${this.syncStrategy})`);
  }

  /**
   * Get singleton instance
   */
  static getInstance(config?: ExternalSyncConfig): ExternalSyncAdapter {
    if (!ExternalSyncAdapter.instance) {
      ExternalSyncAdapter.instance = new ExternalSyncAdapter(
        config || {
          services: [],
          conflictResolution: 'auto',
        },
      );
    }
    return ExternalSyncAdapter.instance;
  }

  /**
   * Register status observer
   */
  registerStatusObserver(key: string, observer: (status: SyncStatus) => Promise<void>): void {
    if (!this.statusObservers.has(key)) {
      this.statusObservers.set(key, new Set());
    }
    this.statusObservers.get(key)?.add(observer);
    console.log(`✅ Status observer registered for key: ${key}`);
  }

  /**
   * Unregister status observer
   */
  unregisterStatusObserver(key: string, observer: (status: SyncStatus) => Promise<void>): void {
    this.statusObservers.get(key)?.delete(observer);
  }

  /**
   * Handle local state change (before persistence)
   */
  async onLocalChange(change: StateChange): Promise<boolean> {
    // First, sync to active services
    if (this.syncStrategy === 'local' || this.syncStrategy === 'auto') {
      try {
        await this.syncChanges([change], 'local');
      } catch (error: any) {
        console.error('❌ Local sync failed:', error);
        // Continue anyway
      }
    }

    return true;
  }

  /**
   * Handle remote state change (after receiving from remote)
   */
  async onRemoteChange(change: StateChange): Promise<boolean> {
    // Check for conflicts
    const conflict = await this.checkForConflict(change);

    if (conflict) {
      // Handle conflict
      return await this.resolveConflict(conflict);
    }

    // No conflict, accept change
    return true;
  }

  /**
   * Sync changes to external services
   */
  private async syncChanges(
    changes: StateChange[],
    source: 'local' | 'remote',
  ): Promise<SyncEvent> {
    this.updateStatus(SyncStatus.SYNCING);

    const event: SyncEvent = {
      type: 'start',
      service: 'all',
      changesCount: changes.length,
      timestamp: Date.now(),
    };

    try {
      // Get current status for proof
      event.local = await this.getCurrentStatusProof();

      // Simulate sync (would use concrete adapter in production)
      this.currentEvents.push({
        ...event,
        type: 'complete' as const,
        changesCount: changes.length,
      });

      this.updateStatus(SyncStatus.COMMITTED);
      return event;
    } catch (error: any) {
      const errorEvent: SyncEvent = {
        ...event,
        type: 'error' as const,
        error: error.message,
        timestamp: Date.now(),
      };

      this.currentEvents.push(errorEvent);
      this.updateStatus(SyncStatus.FAILED);
      return errorEvent;
    }
  }

  /**
   * Check for conflict between local and remote
   */
  private async checkForConflict(change: StateChange): Promise<ConflictDetails | null> {
    // Check if remote version exists for this key
    const remoteValue = await this.getRemoteValue(change.key);

    if (!remoteValue) {
      return null; // No conflict, remote doesn't have this
    }

    const conflict: ConflictDetails = {
      key: change.key,
      localValue: change.oldValue,
      remoteValue: remoteValue,
      timestamp: Date.now(),
      detectedAt: Date.now(),
      source: 'both',
    };

    // Track conflict
    this.conflicts.set(change.key, [...(this.conflicts.get(change.key) || []), conflict]);

    return conflict;
  }

  /**
   * Resolve a conflict
   */
  private async resolveConflict(conflict: ConflictDetails): Promise<boolean> {
    // Apply conflict resolution strategy
    switch (this.syncStrategy) {
      case 'local':
        // Accept local, reject remote
        return await this.resolveLocalWins(conflict);

      case 'remote':
        // Accept remote, reject local
        return await this.resolveRemoteWins(conflict);

      case 'auto':
        // Auto-resolve based on metadata
        return await this.resolveAuto(conflict);

      default:
        return false;
    }
  }

  /**
   * Resolve: local wins
   */
  private async resolveLocalWins(conflict: ConflictDetails): Promise<boolean> {
    console.log(`⏬ Conflict resolution: local wins (${conflict.key})`);
    // Remove conflict reference
    this.conflicts
      .get(conflict.key)
      ?.splice(this.conflicts.get(conflict.key)?.indexOf(conflict), 1);
    return true;
  }

  /**
   * Resolve: remote wins
   */
  private async resolveRemoteWins(conflict: ConflictDetails): Promise<boolean> {
    console.log(`⏫ Conflict resolution: remote wins (${conflict.key})`);
    // This would apply the remote value
    // Remove conflict reference
    this.conflicts
      .get(conflict.key)
      ?.splice(this.conflicts.get(conflict.key)?.indexOf(conflict), 1);
    return true;
  }

  /**
   * Resolve: auto (based on timestamp)
   */
  private async resolveAuto(conflict: ConflictDetails): Promise<boolean> {
    // Use `new Date()` timestamp from the change
    const localIsNewer = Date.now() > this.getTimestamp(conflict.localValue);
    const remoteIsNewer = Date.now() > this.getTimestamp(conflict.remoteValue);

    console.log(
      `⚖️  Auto resolution: ${conflict.key} (local: ${localIsNewer}, remote: ${remoteIsNewer})`,
    );

    // Accept newer change
    if (localIsNewer) {
      this.conflicts
        .get(conflict.key)
        ?.splice(this.conflicts.get(conflict.key)?.indexOf(conflict), 1);
    } else {
      this.conflicts
        .get(conflict.key)
        ?.splice(this.conflicts.get(conflict.key)?.indexOf(conflict), 1);
      // Apply remote value
    }

    return true;
  }

  /**
   * Get current status proof
   */
  private async getCurrentStatusProof(): Promise<BuildInProof> {
    return {
      status: this.currentStatus,
      eventsCount: this.currentEvents.length,
      conflictsCount: this.conflicts.size,
      timestamp: Date.now(),
    };
  }

  /**
   * Get remote value for key
   */
  private async getRemoteValue(key: string): Promise<unknown> {
    // Simulate remote retrieval
    return undefined;
  }

  /**
   * Update status and notify observers
   */
  private async updateStatus(newStatus: SyncStatus): Promise<void> {
    if (this.currentStatus === newStatus) {
      return;
    }

    const previousStatus = this.currentStatus;
    this.currentStatus = newStatus;

    // Notify all observers
    for (const observers of this.statusObservers.values()) {
      for (const observer of observers) {
        try {
          await observer(newStatus);
        } catch (error: any) {
          console.error('❌ Status observer error:', error);
        }
      }
    }

    console.log(`🔄 Sync status: ${previousStatus} → ${newStatus}`);
  }

  /**
   * Get current status
   */
  getStatus(): SyncStatus {
    return this.currentStatus;
  }

  /**
   * Get sync events
   */
  getEvents(): SyncEvent[] {
    return [...this.currentEvents];
  }

  /**
   * Get conflicts
   */
  getConflicts(): ConflictDetails[] {
    const conflicts: ConflictDetails[] = [];
    for (const keyConflicts of this.conflicts.values()) {
      conflicts.push(...keyConflicts);
    }
    return conflicts;
  }

  /**
   * Clear all conflicts
   */
  clearConflicts(): void {
    this.conflicts.clear();
    console.log('🗑️  Conflicts cleared');
  }

  /**
   * Reset to IDLE state
   */
  reset(): void {
    this.currentStatus = SyncStatus.IDLE;
    this.currentEvents = [];
    this.conflicts.clear();
    console.log('🔄 ExternalSyncAdapter reset');
  }

  /**
   * Enable/disable specific service
   */
  toggleService(service: string, enabled: boolean): void {
    console.log(`🔌 Service ${service} set to ${enabled ? 'enabled' : 'disabled'}`);
    // Implementation would use concrete service adapters
  }

  /**
   * Get sync statistics
   */
  getStatistics(): {
    eventsCount: number;
    conflictsCount: number;
    status: SyncStatus;
    services: string[];
  } {
    return {
      eventsCount: this.currentEvents.length,
      conflictsCount: this.conflicts.size,
      status: this.currentStatus,
      services: [], // Would be populated by actual service adapters
    };
  }

  private getTimestamp(value: unknown): number {
    if (typeof value === 'object' && value !== null) {
      const date = (value as any).date;
      if (typeof date === 'number') {
        return date;
      }
      if (date instanceof Date) {
        return date.getTime();
      }
    }
    return 0;
  }
}

