/**
 * [LAYER: CORE]
 * Principle: Architectural Guard — monitors and enforces layer boundaries.
 * Uses structured logging for production-grade observability.
 */

import * as crypto from 'node:crypto';
import { EventType } from '../../domain/Event';
import type { IntegrityScanner } from '../../domain/integrity/IntegrityScanner';
import type { LogService } from '../../domain/logging/LogService';
import type {
  IntegrityReport,
  IntegrityViolation,
  ViolationType,
} from '../../domain/memory/Integrity';
import { RiskLevel } from '../../domain/validation/RiskLevel';
import { Core } from '../../infrastructure/database/sovereign/Core';
import { SafetyGuard } from '../capabilities/SafetyGuard';
import { EventBus } from '../orchestration/EventBus';
import type { HealingService } from './HealingService';

export class IntegrityService implements IntegrityScanner {
  private eventBus: EventBus = EventBus.getInstance();

  constructor(
    private scanner?: IntegrityScanner,
    private healingService?: HealingService,
    private logService?: LogService,
  ) {}

  async scan(projectRoot: string): Promise<IntegrityReport> {
    if (!this.scanner) {
      return {
        violations: [],
        scannedAt: new Date().toISOString(),
        fileCount: 0,
        renderCount: 0,
      };
    }

    const report = await this.scanner.scan(projectRoot);
    await this.reportViolations(report);

    // Phase 2: Critical - Replace silent error swallowing with proper logging
    try {
      await this.recordHistory(report);
    } catch (historyError) {
      const errorMessage =
        historyError instanceof Error ? historyError.message : 'Unknown history recording error';
      if (this.logService) {
        this.logService.error(
          'Failed to record integrity scan history',
          { error: errorMessage, report },
          { component: 'IntegrityService' },
        );
      }
    }

    return report;
  }

  async scanFile(filePath: string, projectRoot: string): Promise<IntegrityReport> {
    if (!this.scanner) return { violations: [], scannedAt: new Date().toISOString() };
    const report = await this.scanner.scanFile(filePath, projectRoot);

    // Pass 11: Proactive structural analysis (Coupling/Anchor detection)
    if (this.healingService) {
      const proactiveHeal = await this.healingService.analyzeStructuralHealth(filePath);
      if (proactiveHeal) {
        // If we found a proactive proposal, add it to the report's violations
        // as a 'warn' severity for awareness.
        report.violations.push(proactiveHeal.violation);
        // Direct save to repository (already offloaded to pool)
        await this.healingService.processViolations([proactiveHeal.violation]);
      }
    }

    await this.reportViolations(report);
    return report;
  }

  /**
   * Pass 7: Throughput-optimized reporter for background worker scans.
   */
  public reportViolationsThroughput(report: IntegrityReport): void {
    this.reportViolations(report);
  }

  private async reportViolations(report: IntegrityReport): Promise<void> {
    if (report.violations.length > 0) {
      if (this.logService) {
        this.logService.warn(
          `Found ${report.violations.length} architectural violations`,
          { violationCount: report.violations.length },
          { component: 'IntegrityService' },
        );
      }

      // Pass 4: Trigger Architectural Alarm if errors (not warnings) found
      const hasErrors = report.violations.some((v) => v.severity === 'error');
      if (hasErrors) {
        SafetyGuard.triggerAlarm();
      }

      for (const violation of report.violations) {
        this.eventBus.emit(EventType.ERROR_OCCURRED, {
          source: 'IntegrityService',
          violationType: violation.type,
          file: violation.file,
          message: violation.message,
        });
      }

      // Pass 5: Proactive Healing Integration
      if (this.healingService) {
        try {
          await this.healingService.processViolations(report.violations);
        } catch (healingError) {
          const errorMessage =
            healingError instanceof Error ? healingError.message : 'Unknown healing process error';
          if (this.logService) {
            this.logService.error(
              'Failed to process integrity violations',
              { error: errorMessage, violationCount: report.violations.length },
              { component: 'IntegrityService' },
            );
          }
        }
      }
    } else {
      // No violations: Clear the alarm
      SafetyGuard.clearAlarm();
    }
  }

  private async recordHistory(report: IntegrityReport): Promise<void> {
    const pool = Core.pool;
    await pool.push({
      type: 'insert',
      table: 'joy_history' as any,
      values: {
        id: crypto.randomUUID(),
        violation_count: report.violations.length,
        file_count: report.fileCount || 0,
        timestamp: Date.now(),
      } as any,
    });
    await pool.flush();
  }
}

/**
 * [LAYER: CORE]
 * Principle: Integrity Hook — captures file save events and triggers architectural audits.
 * Pass 13: Autonomous Self-Healing Integration.
 */

import { HealingStatus } from '../../domain/healing/Healing';
import type { HealingRepository } from '../../domain/healing/HealingRepository';
import { type Hook, HookPhase } from '../../domain/hooks/HookContract';
import type { WorkerIntegrityAdapter } from '../../infrastructure/WorkerIntegrityAdapter';
import { RefactorTools } from '../../infrastructure/tools/RefactorTools';
import { JoyMapGenerator } from '../../infrastructure/tools/generate_joy_map';
import type { HealingService } from './HealingService';
import type { IntegrityService } from './IntegrityService';

export class JoyZoningHook implements Hook {
  public readonly name = 'JoyZoningGuard';
  public readonly phase = HookPhase.POST_EXECUTION;
  public readonly priority = 10;
  private static isAuditing = false;
  private auditQueue: Set<string> = new Set();
  private auditTimeout: any = null;
  private refactorTools: RefactorTools;
  private joyMap: JoyMapGenerator;

  constructor(
    private integrityService: IntegrityService,
    private workerAdapter: WorkerIntegrityAdapter,
    private healingService: HealingService,
    private healingRepository: HealingRepository,
    private projectRoot: string,
  ) {
    this.refactorTools = new RefactorTools(this.integrityService);
    this.joyMap = new JoyMapGenerator();
  }

  async execute(params: { toolName: string; input: any; result?: any }): Promise<void> {
    const filePath = params.input?.path || params.input?.filePath || (params.result as any)?.path;
    if (!filePath || !filePath.endsWith('.ts')) return;
    this.auditQueue.add(filePath);
    if (this.auditTimeout) {
      clearTimeout(this.auditTimeout);
    }
    this.auditTimeout = setTimeout(async () => {
      await this.runAuditBatch();
    }, 2000);
  }

  private async runAuditBatch(): Promise<void> {
    if (JoyZoningHook.isAuditing || this.auditQueue.size === 0) return;
    JoyZoningHook.isAuditing = true;
    const batch = Array.from(this.auditQueue);
    this.auditQueue.clear();
    try {
      for (const filePath of batch) {
        const report = await this.integrityService.scanFile(filePath, this.projectRoot);
        if (report.violations.length > 0) {
          const violationId = report.violations[0]?.id;
          if (violationId) {
            const proposals = await this.healingRepository.getProposalsForViolation(violationId);
            for (const proposal of proposals) {
              if (proposal.confidence === 1.0 && proposal.status === HealingStatus.PENDING) {
                await this.healingService.applyProposal(proposal.id);
              }
            }
          }
        }
        await this.integrityService.reportViolationsThroughput(report);
      }
      await this.joyMap.generate(this.projectRoot);
    } catch (err) {
      console.error('❌ [JoyZoning] Audit batch failed:', err);
    } finally {
      JoyZoningHook.isAuditing = false;
    }
  }
}

/**
 * [LAYER: CORE]
 * Principle: Autonomous Recovery — manages the loop between integrity detection and refactoring.
 * Uses structured logging for production-grade observability.
 */

import { EventType } from '../../domain/Event';
import {
  type HealingProposal,
  HealingStatus,
  type HealingTask,
} from '../../domain/healing/Healing';
import type { HealingRepository } from '../../domain/healing/HealingRepository';
import type { VerificationProvider } from '../../domain/healing/VerificationProvider';
import type { LogService } from '../../domain/logging/LogService';
import type { IntegrityReport, IntegrityViolation } from '../../domain/memory/Integrity';
import type { LockScope } from '../../domain/safety/LockScope';
import { JobType, type QueueProvider } from '../../domain/system/QueueProvider';
import { LockOrchestrator, LockTimeoutStrategy } from '../manager/LockOrchestrator.ts';
import type { SnapshotService } from '../memory/SnapshotService';
import { EventBus } from '../orchestration/EventBus';

export class SelfHealingService {
  private eventBus: EventBus;
  private queue?: QueueProvider;
  private snapshotService?: SnapshotService;
  private verificationProvider?: VerificationProvider;

  constructor(
    private repository: HealingRepository,
    private logService: LogService,
    deps?: {
      queue: QueueProvider;
      snapshotService: SnapshotService;
      verificationProvider: VerificationProvider;
    },
  ) {
    this.eventBus = EventBus.getInstance(logService);
    if (deps) {
      this.queue = deps.queue;
      this.snapshotService = deps.snapshotService;
      this.verificationProvider = deps.verificationProvider;
    }
  }

  /**
   * Triages an integrity report and enqueues healing tasks for critical violations.
   */
  async triage(report: IntegrityReport): Promise<number> {
    if (report.violations.length === 0) return 0;

    let tasksEnqueued = 0;

    const lockOrchestrator = LockOrchestrator.getInstance();

    for (const violation of report.violations) {
      if (violation.severity === 'error') {
        // [HARDENING] Deduplication - check for existing proposals
        const existing = await this.repository.getProposalsForViolation(violation.id);
        if (existing.length > 0) continue;

        // [HARDENING] Guarded Triage - use distributed lock
        const scope: LockScope = {
          taskId: 'self-healing',
          operation: `triage_${violation.id}`,
          timeoutMs: 30000,
          autoRelease: true,
        };

        try {
          await lockOrchestrator.executeInLock(
            scope,
            async () => {
              const specialistId = this.assignSpecialist(violation);

              if (this.queue && this.snapshotService) {
                const snapshotId = await this.snapshotService.capture(violation.file);

                await this.queue.enqueue({
                  type: JobType.CODE_HEAL,
                  payload: {
                    violationId: violation.id,
                    violation,
                    specialistId,
                    snapshotId,
                  },
                });
              }

              tasksEnqueued++;
              this.logService.info(
                `Enqueued healing task for ${violation.type} on ${violation.file}`,
                { violationType: violation.type, file: violation.file },
                { component: 'SelfHealingService' },
              );
            },
            LockTimeoutStrategy.BACKOFF,
          );
        } catch (error) {
          this.logService.warn(
            `Lock acquisition failed for violation ${violation.id}. Skipping triage for now.`,
          );
        }
      }
    }

    return tasksEnqueued;
  }

  /**
   * Logic to assign the correct specialist agent to a violation.
   */
  private assignSpecialist(violation: IntegrityViolation): string {
    switch (violation.type) {
      case 'cross_layer_import':
      case 'unauthorized_io':
        return 'agent-architect';
      default:
        return 'agent-refactorer';
    }
  }

  /**
   * Records a healing proposal (usually called by the QueueWorker after LLM generation).
   */
  async recordProposal(proposal: HealingProposal): Promise<void> {
    await this.repository.saveProposal(proposal);

    this.logService.info(
      'New proposal generated and persisted for violation',
      { violationId: proposal.violationId, proposalId: proposal.id },
      { component: 'SelfHealingService' },
    );

    this.eventBus.emit(EventType.ERROR_OCCURRED, {
      source: 'SelfHealingService',
      type: 'proposal_generated',
      proposalId: proposal.id,
      violation: proposal.violation.message,
    });

    // Loop Closure — verify and close the violation
    if (this.verificationProvider) {
      const result = await this.verificationProvider.verifyResolution(proposal.violationId);
      if (result.isResolved) {
        this.logService.info(
          'Loop closed! Violation verified as resolved',
          { violationId: proposal.violationId },
          { component: 'SelfHealingService' },
        );
        await this.repository.updateProposalStatus(proposal.id, HealingStatus.APPLIED);
      } else {
        this.logService.warn(
          'Refactor applied but violation persists. TRIGGERING ATOMIC ROLLBACK.',
          { violationId: proposal.violationId },
          { component: 'SelfHealingService' },
        );

        // [HARDENING] Atomic Rollback — restore to previous snapshot
        if (this.snapshotService) {
          await this.snapshotService.undo(proposal.violation.file);
          this.logService.info(`Atomic rollback successful for ${proposal.violation.file}`);
        }

        await this.repository.updateProposalStatus(proposal.id, HealingStatus.FAILED);
      }
    }
  }
}

/**
 * [LAYER: CORE]
 * Principle: System Diagnostics & Integrity Management.
 * Implementation: Automated health checks and infrastructure remediation.
 */

import * as path from 'node:path';
import { EventType } from '../../domain/Event';
import type { Filesystem } from '../../domain/system/Filesystem';
import { EventBus } from '../orchestration/EventBus';

export interface HealthStatus {
  healthy: boolean;
  issues: DiagnosticIssue[];
  timestamp: number;
}

export interface DiagnosticIssue {
  component: string;
  severity: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
  message: string;
  remediable: boolean;
  remediationAction?: string;
}

export class SovereignDoctor {
  private fs: Filesystem;
  private eventBus: EventBus;
  private workspaceRoot: string;

  constructor(fs: Filesystem, workspaceRoot: string) {
    this.fs = fs;
    this.eventBus = EventBus.getInstance();
    this.workspaceRoot = workspaceRoot;
  }

  /**
   * Performs a comprehensive diagnostic scan of the system.
   */
  async diagnose(): Promise<HealthStatus> {
    const issues: DiagnosticIssue[] = [];

    // 1. Check for stale lock files
    await this.checkLockIntegrity(issues);

    // 2. Check for infrastructure accessibility
    await this.checkInfrastructureHealth(issues);

    // 3. Check for workspace configuration
    await this.checkWorkspaceIntegrity(issues);

    const healthy =
      issues.filter((i) => i.severity === 'HIGH' || i.severity === 'CRITICAL').length === 0;

    const status = {
      healthy,
      issues,
      timestamp: Date.now(),
    };

    if (!healthy) {
      this.eventBus.publish(EventType.SYSTEM_ERROR, {
        component: 'SovereignDoctor',
        message: `System health check failed: ${issues.length} issues detected`,
      });
    }

    return status;
  }

  /**
   * Attempts to remediate detectable issues.
   */
  async remediate(
    issues: DiagnosticIssue[],
  ): Promise<{ successCount: number; failureCount: number }> {
    let successCount = 0;
    let failureCount = 0;

    for (const issue of issues) {
      if (issue.remediable && issue.remediationAction === 'CLEAR_LOCKS') {
        try {
          await this.clearStaleLocks();
          successCount++;
        } catch {
          failureCount++;
        }
      }
      // Add more remediation logic here
    }

    return { successCount, failureCount };
  }

  private async checkLockIntegrity(issues: DiagnosticIssue[]): Promise<void> {
    // Example: scan for .lock files that are older than 1 hour
    try {
      const entries = this.fs.readdir(this.workspaceRoot);
      for (const entry of entries) {
        if (entry.name.endsWith('.lock')) {
          const lockPath = path.join(this.workspaceRoot, entry.name);
          const stats = this.fs.stat(lockPath);
          const ageHours = (Date.now() - stats.mtimeMs) / (1000 * 60 * 60);

          if (ageHours > 1) {
            issues.push({
              component: 'Infrastructure/Locks',
              severity: 'MEDIUM',
              message: `Stale lock file detected: ${entry.name} (Age: ${ageHours.toFixed(1)}h)`,
              remediable: true,
              remediationAction: 'CLEAR_LOCKS',
            });
          }
        }
      }
    } catch (error) {
      // Ignore directory read errors
    }
  }

  private async checkInfrastructureHealth(issues: DiagnosticIssue[]): Promise<void> {
    try {
      this.fs.exists(this.workspaceRoot);
    } catch (error) {
      issues.push({
        component: 'Infrastructure/Filesystem',
        severity: 'CRITICAL',
        message: `Filesystem adapter failure or workspace root inaccessible: ${this.workspaceRoot}`,
        remediable: false,
      });
    }
  }

  private async checkWorkspaceIntegrity(issues: DiagnosticIssue[]): Promise<void> {
    // Check for critical missing files
    const criticalFiles = ['package.json', 'tsconfig.json'];
    for (const file of criticalFiles) {
      if (!this.fs.exists(path.join(this.workspaceRoot, file))) {
        issues.push({
          component: 'Workspace/Integrity',
          severity: 'HIGH',
          message: `Critical workspace file missing: ${file}`,
          remediable: false,
        });
      }
    }
  }

  private async clearStaleLocks(): Promise<void> {
    const entries = this.fs.readdir(this.workspaceRoot);
    for (const entry of entries) {
      if (entry.name.endsWith('.lock')) {
        const lockPath = path.join(this.workspaceRoot, entry.name);
        const stats = this.fs.stat(lockPath);
        const ageHours = (Date.now() - stats.mtimeMs) / (1000 * 60 * 60);
        if (ageHours > 1) {
          await this.fs.unlink(lockPath);
        }
      }
    }
  }
}

import { HookPhase } from '../../domain/hooks/HookContract';
import type { Hook, PreToolCancellationProtocol } from '../../domain/hooks/HookContract';

/**
 * Custom error for pre-tool usage cancellation
 */
export class PreToolCancellationError extends Error {
  constructor(
    public toolName: string,
    public protocol: PreToolCancellationProtocol,
  ) {
    super(
      `Pre-tool hook cancelled execution of "${toolName}": ${protocol.reason || 'No reason provided'}`,
    );
    this.name = 'PreToolCancellationError';
  }
}

/**
 * [LAYER: CORE]
 * Principle: Orchestration — coordinates the execution of hooks across phases.
 */
export class HookOrchestrator {
  private hooks: Map<HookPhase, Hook[]> = new Map();

  /**
   * Register a new hook
   */
  register(hook: Hook): void {
    const list = this.hooks.get(hook.phase) || [];
    list.push(hook);
    // Sort by priority (descending)
    list.sort((a, b) => b.priority - a.priority);
    this.hooks.set(hook.phase, list);
    console.log(`🧲 Registered hook: ${hook.name} (${hook.phase})`);
  }

  /**
   * Execute a hook chain
   *
   * @param toolName - Name of the tool being processed
   * @param input - Input data for the hook chain
   * @param toolResult - Result of the tool execution (for POST_EXECUTION hooks)
   * @returns Final result after all hooks in chain
   * @throws PreToolCancellationError if pre-tool hooks cancel
   */
  async chain<T>(toolName: string, input: T, toolResult?: any): Promise<any> {
    // Phase 1: PRE_TOOL_USE hooks (for cancellation)
    const preHooks = this.hooks.get(HookPhase.PRE_TOOL_USE) || [];

    if (preHooks.length > 0) {
      console.log(`🚀 Executing PRE_TOOL_USE hooks for "${toolName}"...`);
    }

    for (const hook of preHooks) {
      try {
        const result = await hook.execute({ toolName, input });

        // Check for cancellation protocol
        if (result?.shouldCancel) {
          console.warn(`⚠️  Pre-tool hook "${hook.name}" triggered cancellation: ${result.reason}`);

          // Fail fast - don't execute tool
          throw new PreToolCancellationError(toolName, result);
        }
      } catch (error: any) {
        if (error instanceof PreToolCancellationError) throw error;
        // Catch other errors but continue (isolation)
        console.error(`❌ Pre-tool hook "${hook.name}" failed:`, error);
      }
    }

    // Phase 2: TOOL_EXECUTION
    const toolHooks = this.hooks.get(HookPhase.TOOL_EXECUTION) || [];
    let currentInput = input;

    if (toolHooks.length > 0) {
      console.log(`⚙️  Executing TOOL_EXECUTION hooks for "${toolName}"...`);
    }

    for (const hook of toolHooks) {
      try {
        if (hook.isBackground) {
          hook.execute({ toolName, input: currentInput }).catch((err) => {
            console.error(`❌ Background TOOL_EXECUTION hook "${hook.name}" failed:`, err);
          });
        } else {
          currentInput = await hook.execute({ toolName, input: currentInput });
        }
      } catch (error: any) {
        console.error(`❌ Tool execution hook "${hook.name}" failed:`, error);
        // Continue to next hook (isolation)
      }
    }

    // Phase 3: POST_EXECUTION
    const postHooks = this.hooks.get(HookPhase.POST_EXECUTION) || [];
    let currentResult = toolResult;

    if (postHooks.length > 0) {
      console.log(`✅ Executing POST_EXECUTION hooks for "${toolName}"...`);
    }

    for (const hook of postHooks) {
      try {
        if (hook.isBackground) {
          hook.execute({ toolName, input, result: currentResult }).catch((err) => {
            console.error(`❌ Background POST_EXECUTION hook "${hook.name}" failed:`, err);
          });
        } else {
          currentResult = await hook.execute({ toolName, input, result: currentResult });
        }
      } catch (error: any) {
        console.error(`❌ Post-execution hook "${hook.name}" failed:`, error);
        // Continue to next hook (isolation)
      }
    }

    return currentResult || currentInput;
  }

  /**
   * Get all registered hooks for debugging
   */
  getDiagnostics(): any {
    const diagnostics: any = {};
    for (const [phase, list] of this.hooks) {
      diagnostics[phase] = list.map((h) => h.name);
    }
    return diagnostics;
  }
}

/**
 * [LAYER: CORE]
 * Principle: Orchestrate domain and infrastructure adapters
 * Prework Status: Not applicable (new file)
 *
 * Central registry for LLM provider adapters, managing 40+ provider support
 * with dynamic model discovery, caching, and provider-specific strategies.
 */

import type {
  AdapterConfig,
  ApiStream,
  LLMAdapter,
  Message,
  ModelInfo,
  PromptStrategy,
} from '../../domain/agent/LLMProviderAdapter';
import { PromptStrategy as EnumPromptStrategy } from '../../domain/agent/LLMProviderAdapter';
import type { ToolDefinition } from '../../domain/agent/ToolDefinition';
import type { LogService } from '../../domain/logging/LogService';
import { CloudflareAdapter } from '../../infrastructure/llm/providers/CloudflareProvider';
import { OpenAIEmbeddingAdapter } from '../../infrastructure/llm/providers/OpenAIEmbeddingAdapter';

/**
 * Provider information interface
 */
export interface ProviderInfo {
  id: string;
  name: string;
  capabilities: {
    supportsStreaming: boolean;
    supportsPromptCache: boolean;
    supportsReasoning: boolean;
    supportsEmbeddings: boolean;
  };
  defaultModel: string;
}

/**
 * Model cache entry
 */
interface ModelCacheEntry {
  data: ModelInfo;
  timestamp: number;
}

/**
 * LLMProviderRegistry
 *
 * Manages LLM provider adapters, model information caching, and provider orchestration.
 * Provides a unified interface for DietCode to work with multiple LLM providers.
 */
export class LLMProviderRegistry {
  private static instance: LLMProviderRegistry | null = null;
  private static readonly MODEL_CACHE_TTL_MS = 60 * 60 * 1000; // 1 hour

  private providers = new Map<string, LLMAdapter>();
  private models = new Map<string, ModelCacheEntry>();
  private providerInfos = new Map<string, ProviderInfo>();
  private isLoadingModels = new Set<string>();

  private constructor() {}

  /**
   * Get singleton instance
   */
  static getInstance(): LLMProviderRegistry {
    if (!LLMProviderRegistry.instance) {
      LLMProviderRegistry.instance = new LLMProviderRegistry();
    }
    return LLMProviderRegistry.instance;
  }

  /**
   * Register a provider adapter
   */
  registerProvider(providerId: string, adapter: LLMAdapter): void {
    if (this.providers.has(providerId)) {
      console.warn(`⚠️  Overriding existing provider: ${providerId}`);
    }

    this.providers.set(providerId, adapter);
    console.log(`✅ Provider registered: ${providerId}`);

    // Start model info loading if needed
    this.loadProviderModels(providerId);
  }

  /**
   * Get an adapter for a specific provider
   */
  getAdapter(providerId: string): LLMAdapter | undefined {
    return this.providers.get(providerId);
  }

  /**
   * Register a provider info (metadata)
   */
  registerProviderInfo(info: ProviderInfo): void {
    this.providerInfos.set(info.id, info);
  }

  /**
   * Get provider info
   */
  getProviderInfo(providerId: string): ProviderInfo | undefined {
    return this.providerInfos.get(providerId);
  }

  /**
   * Get model info with caching
   */
  async getModelInfo(providerId: string, modelId: string): Promise<ModelInfo | undefined> {
    const cacheKey = `${providerId}_${modelId}`;
    const cached = this.models.get(cacheKey);

    // Return cached if not expired
    if (cached && Date.now() - cached.timestamp < LLMProviderRegistry.MODEL_CACHE_TTL_MS) {
      return cached.data;
    }

    // Load fresh model info
    return this.loadProviderModels(providerId);
  }

  /**
   * Load model information for a provider (lazy loading with caching)
   */
  private async loadProviderModels(providerId: string): Promise<ModelInfo | undefined> {
    // Avoid duplicate loads
    if (this.isLoadingModels.has(providerId)) {
      return undefined;
    }

    this.isLoadingModels.add(providerId);

    try {
      const adapter = this.getAdapter(providerId);
      if (!adapter) {
        return undefined;
      }

      // Invalidate old cache for this provider
      for (const [key, entry] of this.models.entries()) {
        if (key.startsWith(`${providerId}_`)) {
          this.models.delete(key);
        }
      }

      // Load model info from adapter
      const modelInfo = adapter.getModelInfo();

      if (modelInfo) {
        this.models.set(`${providerId}_${modelInfo.id}`, {
          data: modelInfo,
          timestamp: Date.now(),
        });

        console.log(`✅ Provider models loaded: ${providerId} (${modelInfo.name})`);
      }

      return modelInfo;
    } catch (error: any) {
      console.error(`❌ Failed to load models for ${providerId}:`, error);
      throw error;
    } finally {
      this.isLoadingModels.delete(providerId);
    }
  }

  /**
   * Create an adapter from configuration
   */
  async createProviderFromConfig(providerId: string, config: AdapterConfig): Promise<LLMAdapter> {
    switch (providerId.toLowerCase()) {
      case 'openai':
        // Note: This would require OpenAIAdapter implementation
        // For now, returning stub
        throw new Error(
          'OpenAI adapter not implemented yet. Please implement src/infrastructure/llm/OpenAIAdapter.ts',
        );

      case 'anthropic':
        // Note: Would require AnthropicAdapter implementation
        throw new Error(
          'Anthropic adapter not implemented yet. Please implement src/infrastructure/llm/AnthropicAdapter.ts',
        );

      case 'openrouter':
        // Note: Would require OpenRouterAdapter implementation
        throw new Error(
          'OpenRouter adapter not implemented yet. Please implement src/infrastructure/llm/OpenRouterAdapter.ts',
        );

      case 'cloudflare':
        if (!config.apiKey && !(config as any).apiToken) {
          throw new Error('Cloudflare requires an API token');
        }
        return new CloudflareAdapter({
          accountId: (config as any).accountId || process.env.CLOUDFLARE_ACCOUNT_ID || '',
          apiToken: config.apiKey || (config as any).apiToken,
          model: config.model,
        });

      default:
        throw new Error(`Unknown provider: ${providerId}`);
    }
  }

  /**
   * Check if a provider supports embeddings
   */
  canProvideEmbeddings(providerId: string): boolean {
    const adapter = this.getAdapter(providerId);
    if (!adapter) {
      return false;
    }

    // Check if embedText method exists
    return typeof adapter.embedText === 'function';
  }

  /**
   * Get all registered provider IDs
   */
  getAllProviderIds(): string[] {
    return Array.from(this.providers.keys());
  }

  /**
   * Get all registered providers
   */
  getAllProviders(): Map<string, LLMAdapter> {
    return new Map(this.providers);
  }

  /**
   * Get provider count
   */
  getProviderCount(): number {
    return this.providers.size;
  }

  /**
   * Clear all model caches (useful after provider change)
   */
  clearModelCaches(): void {
    this.models.clear();
    console.log('🗑️  Model caches cleared');
  }

  /**
   * Get provider prompt strategy
   */
  getPromptStrategy(providerId: string): PromptStrategy {
    const adapter = this.getAdapter(providerId);
    if (!adapter) {
      return EnumPromptStrategy.NATIVE;
    }

    const strategy = adapter.getPromptStrategy();
    return strategy;
  }

  /**
   * Create a composite adapter that chains multiple providers (fallback strategy)
   */
  createCompositeAdapter(
    primaryProviders: string[],
    fallbackProviders: string[],
    config: AdapterConfig,
  ): CompositeLLMAdapter {
    return new CompositeLLMAdapter(
      primaryProviders.map((id) => this.getAdapter(id)!),
      fallbackProviders.map((id) => this.getAdapter(id)!),
      config,
    );
  }
}

/**
 * Composite LLM Adapter (fallback chain)
 */
class CompositeLLMAdapter implements LLMAdapter {
  private primaryChain: LLMAdapter[];
  private fallbackChain: LLMAdapter[];
  private config: AdapterConfig;

  constructor(primaryChain: LLMAdapter[], fallbackChain: LLMAdapter[], config: AdapterConfig) {
    this.primaryChain = primaryChain;
    this.fallbackChain = fallbackChain;
    this.config = config;
  }

  createMessage(system: string, messages: Message[], tools?: ToolDefinition[]): ApiStream {
    const primaryChain = this.primaryChain;
    const fallbackChain = this.fallbackChain;

    return {
      async *[Symbol.asyncIterator]() {
        // Try primary chain first
        for (const adapter of primaryChain) {
          try {
            const stream = adapter.createMessage(system, messages, tools);
            for await (const chunk of stream) {
              yield chunk;
            }
            return;
          } catch (error: any) {
            console.warn(
              `⚠️  Primary adapter failed (${adapter.constructor.name}): ${error.message}`,
            );
          }
        }

        // Fallback to secondary chain
        for (const adapter of fallbackChain) {
          try {
            console.log(`🔄  Falling back to ${adapter.constructor.name}`);
            const stream = adapter.createMessage(system, messages, tools);
            for await (const chunk of stream) {
              yield chunk;
            }
            return;
          } catch (error: any) {
            console.warn(
              `❌  Fallback adapter failed (${adapter.constructor.name}): ${error.message}`,
            );
          }
        }

        throw new Error('All provider adapters failed');
      },
    };
  }

  getModelInfo(): ModelInfo {
    if (this.primaryChain.length === 0) {
      throw new Error('No primary adapters configured');
    }
    return this.primaryChain[0]?.getModelInfo();
  }

  async embedText?(text: string): Promise<number[]> {
    for (const adapter of this.primaryChain) {
      if (adapter.embedText) {
        return await adapter.embedText(text);
      }
    }

    for (const adapter of this.fallbackChain) {
      if (adapter.embedText) {
        return await adapter.embedText(text);
      }
    }

    throw new Error('No provider supports embeddings');
  }

  getThinkingBudgetTokenLimit(): number {
    if (this.primaryChain.length === 0) return 0;
    return this.primaryChain[0]?.getThinkingBudgetTokenLimit();
  }

  getPromptStrategy(): PromptStrategy {
    if (this.primaryChain.length === 0) return EnumPromptStrategy.NATIVE;
    return this.primaryChain[0]?.getPromptStrategy();
  }
}

/**
 * Auto-register OpenAI embeddings registry
 */
export function initializeOpenAIEmbeddings(apiKey: string) {
  const registry = LLMProviderRegistry.getInstance();
  const embeddingAdapter = new OpenAIEmbeddingAdapter({
    apiKey,
    model: 'text-embedding-3-small',
  });

  registry.registerProvider('openai', embeddingAdapter);
  registry.registerProviderInfo({
