import { MetabolicMonitor } from '../../infrastructure/monitoring/MetabolicMonitor';
import type { SovereignWorkerProxy } from '../../infrastructure/queue/SovereignWorkerProxy';
import type { CheckpointPersistenceAdapter } from '../../infrastructure/task/CheckpointPersistenceAdapter';
import type { SemanticIntegrityAnalyser } from '../../infrastructure/task/SemanticIntegrityAnalyser';
import type { TaskConsistencyValidator } from '../../infrastructure/task/TaskConsistencyValidator';
import { MetabolicBrain } from '../brain/MetabolicBrain';
import type { OperationalScheduler } from '../task/OperationalScheduler';
import type { SovereignSelector } from '../task/SovereignSelector';

/**
 * Coordinates axiomatic verification across task execution
 * Central orchestrator for compliance enforcement
 */
export class DriftDetectionOrchestrator {
  private checkpointAdapter: CheckpointPersistenceAdapter;
  private semanticAnalyzer: SemanticIntegrityAnalyser;
  private consistencyValidator: TaskConsistencyValidator;
  private entityManager: TaskEntityManager;

  private currentCheckpointId: CheckpointId | null = null;
  private currentAxiomProfile: AxiomProfile = {
    status: ComplianceState.CLEARED,
    failingAxioms: [],
    axiomResults: {
      [IntegrityAxiom.STRUCTURAL]: true,
      [IntegrityAxiom.RESONANCE]: true,
      [IntegrityAxiom.PURITY]: true,
      [IntegrityAxiom.STABILITY]: true,
      [IntegrityAxiom.INTERFACE_INTEGRITY]: true,
      [IntegrityAxiom.COGNITIVE_SIMPLICITY]: true,
    },
  };
  private lastCheckpointTimestamp: Date = new Date();
  private checkpointTokenCount: Map<string, number> = new Map();

  private selector: SovereignSelector;
  private scheduler: OperationalScheduler;
  private workerProxy?: SovereignWorkerProxy;
  private brain = new MetabolicBrain();
  private monitor = MetabolicMonitor.getInstance();

  constructor(
    persistenceAdapter: CheckpointPersistenceAdapter,
    semanticAnalyzer: SemanticIntegrityAnalyser,
    consistencyValidator: TaskConsistencyValidator,
    entityManager: TaskEntityManager,
    selector: SovereignSelector,
    scheduler: OperationalScheduler,
    workerProxy?: SovereignWorkerProxy,
  ) {
    this.checkpointAdapter = persistenceAdapter;
    this.semanticAnalyzer = semanticAnalyzer;
    this.consistencyValidator = consistencyValidator;
    this.entityManager = entityManager;
    this.selector = selector;
    this.scheduler = scheduler;
    this.workerProxy = workerProxy;

    this.currentCheckpointId = null;
    this.lastCheckpointTimestamp = new Date();
    this.checkpointTokenCount = new Map<string, number>();
  }

  /**
   * Initialize task with initial axiomatic verification
   */
  async initializeTask(taskMd: string, initialCheck: number): Promise<ImplementationSnapshot> {
    const taskValidation = await this.consistencyValidator.validateTask(taskMd);
    const currentTask = await this.entityManager.getCurrentTask();
    const taskId = currentTask?.id || this.entityManager.getTaskId(taskMd);

    if (!currentTask) {
      throw new Error('No current task found for initialization');
    }

    const bundle = await this.selector.generateProvenanceBundle(currentTask);
    const audit = this.selector.evaluate(bundle);

    if (!audit.pass) {
      this.log(LogLevel.ERROR, 'Sovereign Gate: Negative-Audit Failed', { reasons: audit.reasons });
      await this.entityManager.setCurrentTask({ ...currentTask, state: TaskState.FAILED });
      throw new Error(`Task rejected by Sovereign Selector: ${audit.reasons.join('; ')}`);
    }

    const readyTask = this.scheduler.transition(currentTask, TaskState.READY);
    await this.entityManager.setCurrentTask(readyTask);

    const snapshot = await this.createCheckpoint(taskMd, initialCheck, 'initialization', {
      validation: taskValidation,
      taskId,
    });

    this.monitor.setTaskId(taskId);
    this.monitor.recordVerification(true);
    this.currentCheckpointId = snapshot.checkpointId;
    this.currentAxiomProfile = snapshot.semanticHealth.axiomProfile;

    return snapshot;
  }

  /**
   * Periodic checkpoint persistence
   */
  async checkAndPersistCheckpoints(
    tokensProcessed: number,
  ): Promise<ImplementationSnapshot | null> {
    const criteria = this.getCurrentCriteria();

    if (
      !this.currentCheckpointId ||
      tokensProcessed - (this.checkpointTokenCount.get('current') || 0) >=
        criteria.checkpointInterval
    ) {
      const task = await this.entityManager.getCurrentTask();

      if (task) {
        const taskId = task.id ?? '';

        const updatedSnapshot = await this.createCheckpoint('periodic-sync', 1.0, 'demographic', {
          taskId,
        });

        this.checkpointTokenCount.set(String(taskId), 0);
        this.currentCheckpointId = updatedSnapshot.checkpointId;
        this.currentAxiomProfile = updatedSnapshot.semanticHealth.axiomProfile;

        this.log(LogLevel.INFO, `Checkpoint created at token ${tokensProcessed}`, {
          checkpointId: updatedSnapshot.checkpointId,
          status: updatedSnapshot.semanticHealth.axiomProfile.status,
        });

        return updatedSnapshot;
      }
    }

    return null;
  }

  /**
   * Create checkpoint with axiomatic verification
   */
  async createCheckpoint(
    markdownContent: string,
    validationScore: number,
    trigger: string,
    context: { validation?: any; taskId?: string } = {},
  ): Promise<ImplementationSnapshot> {
    const task = await this.entityManager.getCurrentTask();
    if (!task) throw new Error('No active task to checkpoint');

    let semanticIntegrity: any;

    if (this.workerProxy) {
      this.log(LogLevel.INFO, 'Offloading Axiomatic Verification to background worker');
      const result = await this.workerProxy.executeSingle<any, any>(JobType.SEMANTIC_SCORING, {
        content: markdownContent,
        tokenHashes: [],
      });
      if (result.success) {
        semanticIntegrity = result.payload;
      } else {
        semanticIntegrity = this.semanticAnalyzer.assessIntegrityAlignment(markdownContent, [], {
          objective: task.objective,
          layer: task.id?.includes('domain') ? 'domain' : 'unknown',
        });
      }
    } else {
      semanticIntegrity = this.semanticAnalyzer.assessIntegrityAlignment(markdownContent, [], {
        objective: task.objective,
        layer: task.id?.includes('domain') ? 'domain' : 'unknown',
      });
    }

    const isAxiomCompliant = semanticIntegrity.axiomProfile.status === ComplianceState.CLEARED;

    if (task.state === TaskState.SHADOW_SIM || task.state === TaskState.READY) {
      if (!isAxiomCompliant) {
        const firstViolation = semanticIntegrity.violations?.[0];
        const locationDetail = firstViolation?.location
          ? ` at Line ${firstViolation.location.lineNumber} (${firstViolation.location.codeSnippet})`
          : '';

        this.log(LogLevel.ERROR, `SRP Gate: Axiomatic Coverage Failed${locationDetail}`, {
          status: semanticIntegrity.axiomProfile.status,
          failingAxioms: semanticIntegrity.axiomProfile.failingAxioms,
        });
        throw new Error(
          `Axiomatic Compliance Failed: ${firstViolation?.message || 'Unknown violation'}. Refusing entry to SOVEREIGN_DOING.`,
        );
      }

      task.simAxiomProfile = semanticIntegrity.axiomProfile;
      const doingTask = this.scheduler.transition(task, TaskState.SOVEREIGN_DOING);
      await this.entityManager.setCurrentTask(doingTask);
    }

    const heartbeat = this.brain.calculateHeartbeat();
    const selfHealing = this.scheduler.evaluateSelfHealing(heartbeat);

    if (selfHealing.action === 'ROLLBACK' && this.currentCheckpointId) {
      this.log(LogLevel.WARN, 'Self-Healing TRIGGERED: Emergency Rollback', {
        reason: selfHealing.reason,
      });
      await this.restoreFromCheckpoint(this.currentCheckpointId, task.id || '');
      const retryTask = this.scheduler.transition(task, TaskState.SHADOW_SIM);
      await this.entityManager.setCurrentTask(retryTask);
    } else if (selfHealing.action === 'SUSPEND') {
      this.log(LogLevel.ERROR, 'Self-Healing TRIGGERED: Task Suspension', {
        reason: selfHealing.reason,
      });
      const failedTask = this.scheduler.transition(task, TaskState.FAILED);
      await this.entityManager.setCurrentTask(failedTask);
      throw new Error(`Task suspended by Self-Healing Protocol: ${selfHealing.reason}`);
    }

    const spec: any = {
      checkpointId:
        trigger === 'initialization' || trigger === 'demographic'
          ? generateCheckpointId()
          : this.currentCheckpointId || generateCheckpointId(),
      semanticHealth: semanticIntegrity,
      outputHash: markdownContent,
      outputSizeBytes: markdownContent.length,
      state: (await this.entityManager.getCurrentTask())?.state || TaskState.SOVEREIGN_DOING,
      tokensProcessed: 0,
      trigger: trigger as CheckpointTrigger,
      previousSnapshotId: this.currentCheckpointId,
      userConfirmationRequired: false,
    };

    const taskId = task.id || String(context.taskId ?? '');
    const snapshot = await this.checkpointAdapter.createCheckpoint(taskId, spec, []);

    await this.monitor.flushToDatabase(taskId);
    this.monitor.recordVerification(true);

    this.currentCheckpointId = snapshot.checkpointId;
    this.currentAxiomProfile = snapshot.semanticHealth.axiomProfile;

    return snapshot;
  }

  /**
   * Evaluate compliance state and provide recommendation
   */
  async evaluateDrift(taskMd: string): Promise<{
    recommendation: DriftDetectionRecommendation;
    snapshot: ImplementationSnapshot;
  }> {
    const criteria = this.getCurrentCriteria();
    const recommendation = computeDriftRecommendation(
      this.currentAxiomProfile,
      criteria,
      TaskState.SOVEREIGN_DOING,
    );

    const emojiRating = this.getEmojiForAction(recommendation.correctiveAction);

    if (this.currentAxiomProfile.status !== ComplianceState.CLEARED) {
      const snapshot = await this.createCheckpoint(taskMd, 1.0, 'demographic', {
        taskId: (await this.entityManager.getCurrentTask())?.id,
      });

      const firstViolation = snapshot.semanticHealth.violations?.[0];
      const detailedMsg = firstViolation?.location
        ? `${recommendation.explanation} (Line ${firstViolation.location.lineNumber}: ${firstViolation.location.codeSnippet})`
        : recommendation.explanation;

      this.log(LogLevel.WARN, `${emojiRating} Axiomatic Status: ${detailedMsg}`, {
        status: this.currentAxiomProfile.status,
        mitigation: recommendation.correctiveAction,
      });

      return {
        recommendation,
        snapshot,
      };
    }

    this.log(LogLevel.INFO, `${emojiRating} Axiomatic Status: ${recommendation.explanation}`, {
      status: this.currentAxiomProfile.status,
    });

    return {
      recommendation,
      snapshot: await this.createCheckpoint(taskMd, 1.0, 'demographic', {
        taskId: (await this.entityManager.getCurrentTask())?.id,
      }),
    };
  }

  /**
   * Triggers a project-wide architectural integrity audit (Axiom 3.0)
   */
  async runSovereignAudit(): Promise<ProjectIntegrityReport> {
    this.log(LogLevel.INFO, 'Initiating Project-Wide Sovereign Audit (Axiom 3.0)');
    const report = await this.semanticAnalyzer.runProjectAudit('./src');

    this.log(LogLevel.WARN, 'Sovereign Audit Complete', {
      totalFiles: report.totalFilesScanned,
      blockedCount: report.blockedFilesCount,
    });

    return report;
  }

  /**
   * Restore state from checkpoint
   */
  async restoreFromCheckpoint(
    checkpointId: CheckpointId,
    taskId: string,
  ): Promise<ImplementationSnapshot> {
    const snapshot = await this.checkpointAdapter.restoreCheckpoint(taskId, checkpointId);

    this.currentCheckpointId = checkpointId;
    this.currentAxiomProfile = snapshot.semanticHealth.axiomProfile;
    this.lastCheckpointTimestamp = snapshot.timestamp;

    this.log(LogLevel.INFO, `State restored from checkpoint ${checkpointId}`, {
      checkpointId,
      status: snapshot.semanticHealth.axiomProfile.status,
    });

    return snapshot;
  }

  /**
   * Get axiomatic assessment between two checkpoints
   */
  async compareCheckpoints(
    checkpointId1: CheckpointId,
    checkpointId2: CheckpointId,
  ): Promise<{
    delta: DriftVector;
    vector: any;
    organismality: number;
  }> {
    const taskId = 'active-task';
    const checkpoints = await this.checkpointAdapter.getLastCheckpoints(taskId, 2);

    if (checkpoints.length < 2) {
      throw new Error('Need at least 2 checkpoints to compare');
    }

    const earlier = checkpoints[1];
    const later = checkpoints[0];

    if (!earlier || !later) {
      throw new Error('Checkpoints missing during comparison');
    }

    const isAxiomCompliant = later.semanticHealth.axiomProfile.status === ComplianceState.CLEARED;
    const topicDivergence = isAxiomCompliant ? 0.0 : 1.0;
    const delta = calculateDriftDelta(earlier, later);

    const vector = {
      axiomStatus: later.semanticHealth.axiomProfile.status,
      topicDivergence,
      scopeCreep: delta.scopeCreep,
    };

    const organismality = Math.max(delta.topicDivergence, delta.scopeCreep);

    return { delta, vector, organismality };
  }

  /**
   * Get monitoring metrics
   */
  async getMonitoringMetrics(): Promise<{
    checkpointStats: any;
    driftHistory: any[];
    dataAge: any;
  }> {
    const checkpointStats = await this.checkpointAdapter.getCheckpointAgeMetrics();
    const tasks = await this.checkpointAdapter.listTasks(100);

    const driftHistory: any[] = tasks.map((task) => ({
      task_id: task.task_id,
      title: task.title,
      updated_at: task.updated_at,
    }));

    return {
      checkpointStats,
      driftHistory,
      dataAge: {
        oldestSnapshot: checkpointStats.oldestSnapshot,
        newestSnapshot: checkpointStats.newestSnapshot,
        totalTasks: checkpointStats.totalTasks,
        totalCheckpoints: checkpointStats.totalCheckpoints,
      },
    };
  }

  private getCurrentCriteria(): DriftDetectionCriteria {
    const env = (process.env.NODE_ENV as any) || 'development';
    return (
      this.cachedCriteria[env] || this.cachedCriteria.development || createDefaultDriftCriteria()
    );
  }

  private cachedCriteria: Record<string, DriftDetectionCriteria> = {
    development: {
      checkpointInterval: 500,
      autoRestoreOnCriticalDrift: true,
      maxCheckpointCacheSize: 100,
      logDriftPredictions: true,
      enableDriftPrediction: true,
      enabledAxioms: [IntegrityAxiom.STRUCTURAL, IntegrityAxiom.RESONANCE],
    },
    staging: {
      checkpointInterval: 1000,
      autoRestoreOnCriticalDrift: true,
      maxCheckpointCacheSize: 50,
      logDriftPredictions: false,
      enableDriftPrediction: true,
      enabledAxioms: [IntegrityAxiom.STRUCTURAL, IntegrityAxiom.RESONANCE, IntegrityAxiom.PURITY],
    },
    production: {
      checkpointInterval: 2000,
      autoRestoreOnCriticalDrift: true,
      maxCheckpointCacheSize: 30,
      logDriftPredictions: false,
      enableDriftPrediction: false,
      enabledAxioms: [
        IntegrityAxiom.STRUCTURAL,
        IntegrityAxiom.RESONANCE,
        IntegrityAxiom.PURITY,
        IntegrityAxiom.STABILITY,
      ],
    },
  };

  private log(level: LogLevel, message: string, data?: any): void {
    const levelPrefix = `[${level}] [DriftDetectionOrchestrator]`;
    const dataString = data ? ` | ${JSON.stringify(data)}` : '';
    console.log(`${levelPrefix} ${message}${dataString}`);
  }

  private getEmojiForAction(action: string): string {
    if (action === CorrectionType.DRIFT_CORRECTION) return '✅';
    if (action === CorrectionType.PAUSE_FOR_REVIEW) return '⚠️';
    return '❓';
  }
}

/**
 * Entity manager for current task operations
 */
export class TaskEntityManager {
  private currentTask: TaskEntity | null = null;
  constructor(private persistenceAdapter: CheckpointPersistenceAdapter) {}

  async setCurrentTask(task: TaskEntity): Promise<void> {
    await this.persistenceAdapter.persistTask(task);
    this.currentTask = task;
  }

  async getCurrentTask(): Promise<TaskEntity | null> {
    if (!this.currentTask) {
      this.currentTask = await this.persistenceAdapter.getTask('');
    }
    return this.currentTask;
  }

  getTaskId(markdown: string): string {
    return `task-${crypto.createHash('md5').update(markdown).digest('hex').slice(0, 8)}`;
  }
}

/**
 * [LAYER: CORE]
 * Central EventBus for system-wide lifecycle tracking and observability.
 * Uses structured logging for production-grade observability.
 */

import { EventEmitter } from 'node:events';
import type { EventType, SystemEvent } from '../../domain/Event';
import { LogLevel } from '../../domain/logging/LogLevel';
import type { LogService } from '../../domain/logging/LogService';

export class EventBus {
  private static instance?: EventBus;
  private emitter: EventEmitter = new EventEmitter();
  private logService: LogService;

  private constructor(logService: LogService) {
    this.emitter.setMaxListeners(100);
    this.logService = logService;
  }

  static getInstance(logService: LogService): EventBus;
  static getInstance(): EventBus;
  static getInstance(logService?: LogService): EventBus {
    if (!EventBus.instance) {
      EventBus.instance = new EventBus(
        logService ||
          new Proxy({} as any, {
            get: () => () => {},
          }),
      );
    }
    return EventBus.instance;
  }

  /**
   * Injects a log service for structured logging output.
   */
  static setLogService(logService: LogService): void {
    if (EventBus.instance) {
      EventBus.instance.logService = logService;
    }
  }

  /**
   * Dispatches an event to all listeners.
   * Logs structured event data for observability.
   */
  emit(
    type: EventType,
    data: Record<string, any> = {},
    metadata: SystemEvent['metadata'] = {},
  ): void {
    const event: SystemEvent = {
      id: globalThis.crypto.randomUUID(),
      type,
      timestamp: new Date().toISOString(),
      data,
      metadata,
    };

    // Emit event to listeners
    this.emitter.emit(type, event);
    this.emitter.emit('*', event);

    // Log structured event for observability
    this.logService.info(
      `${type} event emitted`,
      { id: event.id, data },
      {
        component: 'EventBus',
        correlationId: metadata?.correlationId,
        sessionId: metadata?.sessionId,
      },
    );
  }

  /**
   * Subscribes to a specific event type.
   */
  on(type: EventType | '*', listener: (event: SystemEvent) => void): void {
    this.emitter.on(type, listener);
  }

  /**
   * Removes event listener for cleanup.
   */
  off(type: EventType | '*', listener: (event: SystemEvent) => void): void {
    this.emitter.off(type, listener);
  }

  /**
   * Internal method to emit temporary event for logging without triggering all listeners.
   */
  private temporaryEmit(type: EventType, data: Record<string, any>): void {
    this.logService.debug(`${type} event received (temporary)`, data, { component: 'EventBus' });
  }
  /**
   * Alias for emit for backward compatibility.
   */
  publish(
    type: EventType,
    data: Record<string, any> = {},
    metadata: SystemEvent['metadata'] = {},
  ): void {
    this.emit(type, data, metadata);
  }
}

/**
 * [LAYER: CORE]
 * Principle: Orchestration — coordinates the tool execution lifecycle.
 */

import { EventType } from '../../domain/Event';
import type {
  SafetyAwareToolContext,
  SafetyAwareToolOptions,
} from '../../domain/capabilities/SafetyAwareToolExecution';
import type { ToolRouter } from '../../domain/capabilities/ToolRouter';
import type { FileReadResult } from '../../domain/context/FileOperation';
import type { RiskEvaluator } from '../../domain/validation/RiskEvaluator';
import { RiskLevel } from '../../domain/validation/RiskLevel';
import type { RollbackProtocol } from '../../domain/validation/RollbackProtocol';
import { SafetyGuard } from '../capabilities/SafetyGuard';
import type { ToolManager } from '../capabilities/ToolManager';
import type { SnapshotService } from '../memory/SnapshotService';
import type { ContextOptimizationServiceOrchestrator } from './ContextOptimizationService';
import { EventBus } from './EventBus';

/**
 * Safe tool execution options
 */
export interface SafeExecutionOptions {
  targetPath?: string;
  requireApprovalForHighRisk?: boolean;
  backupBeforeModification?: boolean;
  autoBackup?: boolean;
  preserveSnapshots?: boolean;
}

/**
 * Unified tool execution result with safety envelope
 */
export type UnifiedToolExecutionResult = {
  toolName: string;
  result: any;
  success: boolean;
  riskLevel: string;
  approved: boolean;
  safeguardsApplied: string[];
  executionTime: number;
  metadata: {
    toolRoute?: { toolName: string; matchesCriteria: boolean };
    snapshotId?: string;
  };
};

/**
 * ExecutionService orchestrates tool execution with unified SafetyGuard integration
 * Pattern: Modern Unified Safety - single SafetyGuard instance wraps all tool executions
 */
export class ExecutionService {
  private safetyGuard?: SafetyGuard;
  private rollbackManager?: RollbackProtocol;
  private toolManager?: ToolManager;
  private toolRouter?: ToolRouter;
  private eventBus: EventBus;
  private snapshotService: SnapshotService;
  private eventData?: { sessionId?: string; timestamp?: string };
  private contextOptimization?: ContextOptimizationServiceOrchestrator;

  /**
   * Initialize ExecutionService with unified safety capabilities
   * @param snapshotService Snapshot service for pre-execution capture
   * @param executionOptions Execution configuration options
   */
  constructor(snapshotService: SnapshotService, executionOptions?: SafeExecutionOptions) {
    this.snapshotService = snapshotService;
    this.eventBus = EventBus.getInstance();
    this.eventData = executionOptions as { sessionId?: string; timestamp?: string } | undefined;

    // Apply options if provided
    if (executionOptions?.preserveSnapshots) {
      console.log('📦 Snapshots enabled for tool execution');
    }
  }

  /**
   * Enable context optimization service
   * Integrates the two-finger pattern context optimization system
   *
   * @param orchestrator Context optimization orchestrator
   */
  enableContextOptimization(orchestrator: ContextOptimizationServiceOrchestrator): void {
    this.contextOptimization = orchestrator;
    console.log('🚀 Context optimization enabled');
  }

  /**
   * Read a file with context optimization
   * Automatically applies the two-finger pattern for duplicate file reads
   *
   * @param filePath Path to the file to read
   * @returns Promise resolving to optimized file read result
   */
  async readFileOptimized(filePath: string): Promise<FileReadResult> {
    if (!this.contextOptimization) {
      console.warn('⚠️  Context optimization not enabled. Falling back to direct file read.');
      // Fallback to direct file read (would need file system adapter here)
      return {
        filePath,
        content: 'Context optimization not enabled',
        timestamp: Date.now(),
        source: 'fallback',
        originalLength: filePath.length,
        optimizedLength: filePath.length,
        wasOptimized: false,
        hash: `fallback-${Date.now()}`,
        sizeBytes: filePath.length,
      };
    }

    const result = await this.contextOptimization.readFileOptimized(filePath);

    if (result.wasOptimized) {
      console.log(`⚡ Optimized read: ${filePath} (${result.optimizationReason})`);
      this.eventBus.publish(
        EventType.CONTEXT_OPTIMIZATION,
        {
          filePath,
          wasOptimized: true,
          reason: result.optimizationReason,
        },
        { sessionId: this.eventData?.sessionId },
      );
    }

    return result.result;
  }

  /**
   * Start a context optimization session
   * Should be called at the beginning of a tool execution session
   *
   * @param sessionId Unique session identifier
   */
  startOptimizationSession(sessionId: string): void {
    if (this.contextOptimization) {
      this.contextOptimization.startSession(sessionId);
      console.log(`📊 Started optimization session: ${sessionId}`);
    }
  }

  /**
   * End a context optimization session and generate report
   * Should be called at the end of a tool execution session
   *
   * @returns Optimization report (optional)
   */
  async endOptimizationSession(): Promise<any> {
    if (!this.contextOptimization) {
      return null;
    }

    const report = await this.contextOptimization.generateReport();

    if (report.contextTruncated) {
      console.log('⚠️  Context optimization triggered truncation');
    }

    console.log('📊 Optimization session completed:', {
      efficiency: report.metrics.efficiencyRating,
      savings: `${report.metrics.percentageSaved.toFixed(1)}%`,
      signatures: report.signatureCount,
      messages: report.recommendations.slice(0, 2),
    });

    return report;
  }

  /**
   * Get context optimization summary for diagnostics
   *
   * @returns Context summary or null if optimization not enabled
   */
  getContextSummary() {
    if (!this.contextOptimization) {
      return null;
    }
    return this.contextOptimization.getContextSummary();
  }

  /**
   * Enable unified SafetyGuard and ToolManager integration
   * Pattern: Gatekeeper Pattern - all tool executions pass through SafetyGuard
   *
   * @param riskEvaluator Risk evaluation engine from Domain
   * @param rollbackManager Backup/rollback manager (implements RollbackProtocol)
   * @param toolManager Tool manager for tool execution
   * @param toolRouter Optional tool routing for smart tool selection
   */
  enableUnifiedSafetyIntegration(
    riskEvaluator: RiskEvaluator,
    rollbackManager: RollbackProtocol,
    toolManager: ToolManager,
    toolRouter?: ToolRouter,
  ): void {
    this.toolManager = toolManager;
    this.toolRouter = toolRouter;
    this.rollbackManager = rollbackManager;
    this.safetyGuard = new SafetyGuard(riskEvaluator, this.eventBus as any); // EventBus isn't LogService, I should use a proper logger here.

    console.log('🛡️  Unified SafetyGuard integration enabled');
    console.log('🔧 Tool routing:', toolRouter ? 'Enabled' : 'Disabled');
    console.log('📦 Snapshots:', this.snapshotService ? 'Enabled' : 'Disabled');
  }

  /**
   * Execute a tool with unified safety envelope
   * Pattern: Safety-Instrumented Execution - wraps tool execution with full safety envelope
   *
   * @param executionOptions Safety configuration options
   * @param toolName Optional tool name
   * @param input Optional input parameters
   * @returns Promise resolving to unified execution result with safety metadata
   */
  async executeWithUnifiedSafety(
    executionOptions?: SafeExecutionOptions,
    toolName?: string,
    input?: Record<string, any>,
  ): Promise<UnifiedToolExecutionResult> {
    const startTime = Date.now();
    const correlationId = globalThis.crypto.randomUUID();

    // Phase 1: Setup and Validation
    this.eventBus.publish(
      EventType.TOOL_CALL_START,
      {
        toolName: toolName || 'default-tool',
        input,
      },
      { correlationId, sessionId: this.eventData?.sessionId },
    );

    if (!this.safetyGuard || !this.toolManager) {
      throw new Error(
        'Unified safety integration not enabled. Call enableUnifiedSafetyIntegration() first.',
      );
    }

    // Phase 2: Route to appropriate tool (if router available)
    let toolRouteInfo: UnifiedToolExecutionResult['metadata']['toolRoute'];

    if (this.toolRouter) {
      try {
        const routeResult = await this.toolRouter.route({
          operationType: toolName || 'default-tool',
          target: executionOptions?.targetPath,
          parameters: input,
        });

        if (routeResult.matchesCriteria) {
          toolRouteInfo = {
            toolName: routeResult.tool.name,
            matchesCriteria: routeResult.matchesCriteria,
          };
          console.log(`🧭 Tool routed: ${toolName || 'default-tool'} → ${routeResult.tool.name}`);
        }
      } catch (routeError) {
        console.warn(`⚠️  Tool routing failed, using original tool: ${routeError}`);
      }
    }

    // Phase 3: Execute with safety-enveloped tool manager
    let toolResult: any;
    try {
      toolResult = await this.toolManager.executeWithSafety(
        toolName || 'default-tool',
        input,
        executionOptions,
      );

      this.eventBus.publish(
        toolResult.success ? EventType.TOOL_CALL_SUCCESS : EventType.TOOL_CALL_FAILURE,
        {
          toolName: toolName || 'default-tool',
          result: toolResult,
          safetyCheck: toolResult.safetyCheck,
        },
        { correlationId, sessionId: this.eventData?.sessionId },
      );

      return this.buildUnifiedResult(toolResult, toolRouteInfo, startTime);
    } catch (toolExecutionError: any) {
      const executionTime = Date.now() - startTime;

      // Phase 4: Error handling with safety envelope
      console.error(`❌ Tool execution failed: ${toolExecutionError.message}`);
      this.eventBus.publish(
        EventType.TOOL_CALL_FAILURE,
        {
          toolName: toolName || 'default-tool',
          error: toolExecutionError.message,
        },
        { correlationId },
      );

      // Attempt rollback if safety guard was configured
      if (executionOptions?.targetPath && this.safetyGuard) {
        console.log(`♻️  Attempting rollback for ${executionOptions.targetPath}...`);
        try {
          await (this.rollbackManager as any).rollbackByPath(executionOptions.targetPath);
          console.log('✅ Rollback completed');
        } catch (rollbackError) {
          console.error(`💥 Rollback failed: ${rollbackError}`);
        }
      }

      return this.buildUnifiedResult(
        {
          toolName: toolName || 'default-tool',
          toolResult: {
            content: `Tool execution failed: ${toolExecutionError.message}`,
            isError: true,
          },
          success: false,
          safetyCheck: {
            evaluated: true,
            riskLevel: RiskLevel.HIGH,
            approved: false,
            requiresConfirmation: false,
            rollbackPrepared: false,
            safeguardsApplied: ['Tool execution failed', `Error: ${toolExecutionError.message}`],
          },
          execution: {
            startTime,
            endTime: Date.now(),
            durationMs: Date.now() - startTime,
          },
        },
        toolRouteInfo,
        startTime,
      );
    }
  }

  /**
   * Build unified execution result from tool context
   *
   * @param toolResult Tool execution result from SafetyGuard
   * @param toolRouteInfo Optional routing information
   * @param startTime Execution start time
   * @returns Unified execution result
   */
  private buildUnifiedResult(
    toolResult: SafetyAwareToolContext,
    toolRouteInfo?: UnifiedToolExecutionResult['metadata']['toolRoute'],
    startTime: number = Date.now(),
  ): UnifiedToolExecutionResult {
    const executionTime = Date.now() - startTime;

    const result: UnifiedToolExecutionResult = {
      toolName: toolResult.toolName,
      result: toolResult.toolResult,
      success: toolResult.success,
      riskLevel: toolResult.safetyCheck.riskLevel,
      approved: toolResult.safetyCheck.approved,
      safeguardsApplied: toolResult.safetyCheck.safeguardsApplied,
      executionTime,
      metadata: {
        toolRoute: toolRouteInfo,
      },
    };

    // Log result summary
    console.log(`✅ Tool execution completed in ${executionTime}ms`);
    console.log(
      `📊 Safety: ${toolResult.safetyCheck.riskLevel} - Approved: ${toolResult.safetyCheck.approved}`,
    );
    if (toolResult.safetyCheck.requiresConfirmation) {
      console.log(`⚠️  Requires user confirmation: ${toolResult.safetyCheck.requiresConfirmation}`);
    }

    return result;
  }

  /**
   * Check if unified safety integration is enabled
   */
  isSafetyIntegrationEnabled(): boolean {
    return (
      this.safetyGuard !== undefined &&
      this.toolManager !== undefined &&
      this.rollbackManager !== undefined
    );
  }

  /**
   * Safety integration diagnostics
   *
   * @param overrideShell Internal parameter for shell-specific behavior (not exposed externally)
   */
  getDiagnostics(overrideShell?: never): any {
    return {
      safetyGuardEnabled: this.safetyGuard !== undefined,
      toolManagerEnabled: this.toolManager !== undefined,
      toolRouterEnabled: this.toolRouter !== undefined,
      rollbackManagerEnabled: this.rollbackManager !== undefined,
      isFullyIntegrated: this.isSafetyIntegrationEnabled(),
    };
  }

  /**
   * Get consolidated optimization diagnostics
   * @returns Combined diagnostics from safety integration and context optimization
   */
  getConsolidatedDiagnostics(_overrideShell?: never): any {
    return {
      safetyIntegration: this.isSafetyIntegrationEnabled() ? 'enabled' : 'disabled',
      safetyIntegrations: this.getDiagnostics(),
      contextOptimization: this.contextOptimization
        ? {
            enabled: true,
            summary: this.getContextSummary(),
          }
        : {
            enabled: false,
          },
      systemStatus: {
        fullyIntegrated: this.isSafetyIntegrationEnabled() && !!this.contextOptimization,
      },
    };
  }
}

/**
 * [LAYER: CORE]
 * Principle: Orchestration — handles seamless transitions between orchestrators
 * Violations: None
 */

import { EventType } from '../../domain/Event';
import type { SessionRepository } from '../../domain/context/SessionRepository';
import type { LogService } from '../../domain/logging/LogService';
import { EventBus } from './EventBus';

/**
 * Handover context containing transferable state
 */
export interface HandoverContext {
  sessionId: string;
  transferredState: Map<string, any>;
  correlationId: string;
  transferTimestamp: number;
}

/**
 * HandoverService manages seamless state transfer between orchestrators
 * Pattern: State Transfer — preserves runtime context during transition
 */
export class HandoverService {
  private eventBus: EventBus;
  private sessionRepository: SessionRepository;
  private eventData?: { sessionId?: string; timestamp?: string };

  constructor(
    sessionRepository: SessionRepository,
    eventData?: { sessionId?: string; timestamp?: string },
  ) {
    this.sessionRepository = sessionRepository;
    this.eventBus = EventBus.getInstance();
    this.eventData = eventData;
  }

  /**
   * Execute handover with comprehensive state verification
   *
   * @param orchestratorToSwitchFrom Origin orchestrator transitioning away
   * @param orchestratorToSwitchTo Target orchestrator receiving state
   * @returns Promise resolving to handover result with verification
   */
  async executeHandover(
    orchestratorToSwitchFrom: string,
    orchestratorToSwitchTo: string,
  ): Promise<void> {
    const correlationId = globalThis.crypto.randomUUID();
    const transferTimestamp = Date.now();

    console.log(`🔄 Initiating handover: ${orchestratorToSwitchFrom} → ${orchestratorToSwitchTo}`);
    console.log(`   Correlation ID: ${correlationId}`);

    try {
      // Phase 1: Extract transferable state from source
      const handoverContext: HandoverContext = {
        sessionId: this.eventData?.sessionId || '',
        transferredState: new Map<string, any>(),
        correlationId,
        transferTimestamp,
      };

      // Phase 2: Validate session exists
      if (!handoverContext.sessionId) {
        throw new Error('No active session available for handover');
      }

      // Phase 3: Transfer session state (domain-level operation)
      await this.sessionRepository.updateSessionAgent(
        handoverContext.sessionId,
        orchestratorToSwitchTo,
      );
      await this.sessionRepository.updateSessionStatus(handoverContext.sessionId, 'busy', {
        previousOrchestrator: orchestratorToSwitchFrom,
        transferTimestamp,
        correlationId,
      });

      // Phase 4: Publish completion event
      this.eventBus.publish(
        EventType.ERROR_OCCURRED,
        {
          source: 'HandoverService',
          message: 'Handover completed successfully',
          correlationId,
        },
        { correlationId, from: orchestratorToSwitchFrom, to: orchestratorToSwitchTo },
      );

      console.log(`✅ Handover completed: ${orchestratorToSwitchFrom} → ${orchestratorToSwitchTo}`);
    } catch (handoverError: any) {
      this.eventBus.publish(EventType.ERROR_OCCURRED, {
        source: 'HandoverService',
        message: `Handover failed: ${handoverError.message}`,
        correlationId,
      });

      console.error(`❌ Handover failed: ${handoverError.message}`);
      throw handoverError;
    }
  }

  /**
   * Get session verification status
   *
   * @param sessionId Session identifier
   */
  async getSessionStatus(sessionId: string): Promise<any> {
    const session = await this.sessionRepository.getSession(sessionId);

    return {
      exists: session !== undefined,
      activeOrchestrator: session?.activeOrchestrator,
      lastUpdated: session?.lastUpdated,
      handoverHistory: session?.metadata.handoverHistory,
    };
  }

  /**
   * Handover diagnostics
   */
  getDiagnostics(): any {
    return {
      sessionRepository: this.sessionRepository !== undefined,
      eventBus: this.eventBus !== undefined,
      currentSession: this.eventData?.sessionId,
    };
  }
}

