  return {
    axiomProfile: {
      status: ComplianceState.BLOCKED,
      failingAxioms: [IntegrityAxiom.STRUCTURAL],
      axiomResults: {
        [IntegrityAxiom.STRUCTURAL]: false,
        [IntegrityAxiom.RESONANCE]: false,
