        git = { branch, dirty, lastCommitHash: hash };
      }
    } catch (e) {
      this.logService.error('Failed to gather git context', e, { component: 'NodeSystemAdapter' });
    }

    let dependencies: Record<string, string> = {};
    const pkgPath = path.join(projectRoot, 'package.json');
    if (this.filesystem.exists(pkgPath)) {
      try {
        const pkg = JSON.parse(this.filesystem.readFile(pkgPath));
        dependencies = { ...pkg.dependencies, ...pkg.devDependencies };
      } catch (e) {
        this.logService.error('Failed to parse package.json', e, {
          component: 'NodeSystemAdapter',
        });
      }
    }

    return {
      git,
      dependencies,
      projectRoot,
    };
  }

  async detectCapability(
    name: string,
    checkCommand: string,
  ): Promise<{ available: boolean; version?: string }> {
    try {
      const output = execSync(checkCommand).toString().trim();
      return { available: true, version: output };
    } catch {
      return { available: false };
    }
  }

  // ─── Enhanced Binary/Stream Operations ────────────────────────────

  /**
   * Read first N bytes as Uint8Array.
   * For binary detection and magic byte checks.
   */
  async readFileBuffer(path: string, length = 1024): Promise<Uint8Array> {
    return this.filesystem.readFileBuffer(path, length);
  }

  /**
   * Read file as async stream for hashing.
   * Processes file in chunks to avoid memory issues.
   */
  async *readFileAsStream(path: string): AsyncGenerator<Buffer, void, undefined> {
    yield* this.filesystem.readFileAsStream(path);
  }

  // ─── Error Handling ───────────────────────────────────────────────

  private logError(err: Error | any): void {
    this.logService.error(
      'Filesystem operation failed',
      { message: err.message, path: err.path },
      { component: 'NodeSystemAdapter' },
    );
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Implementation of visual communication (Terminal) using Node.js APIs.
 * Uses structured logging for production-grade observability.
 */

import * as readline from 'node:readline';
import chalk from 'chalk';
import type { LogService } from '../domain/logging/LogService';
import type { TerminalInterface } from '../domain/system/TerminalInterface';

export class NodeTerminalAdapter implements TerminalInterface {
  private rl: readline.Interface;

  constructor(private logService: LogService) {
    this.rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });
  }

  logClaude(text: string) {
    // Hardened rendering: handle potential empty strings and multi-line breaks
    const cleanText = text.trim() ? text : '(No response)';
    // To properly integrate with LogService, we'd normally emit structured logs
    // But TerminalInterface methods are presentation-layer contracts
    // These are kept as console methods for CLI adaptability
    console.log(chalk.green('\nClaude:'), cleanText);
  }

  logToolUse(name: string, input: any) {
    // presentation method
    console.log(chalk.yellow(`\nTool Use: ${name}`), JSON.stringify(input, null, 2));
  }

  logError(message: string) {
    // presentation method
    console.error(chalk.red('\nError:'), message);
  }

  logUsage(command: string) {
    // presentation method
    console.log(`Usage: bun run ${command} <prompt>`);
  }

  async promptUser(): Promise<string> {
    return new Promise((resolve) => {
      this.rl.question(chalk.blue('\n> '), (answer) => {
        resolve(answer);
      });
    });
  }

  close() {
    this.rl.close();
  }

  clear() {
    process.stdout.write('\x1Bc');
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Adapters and integrations — connects prompt files to domain contracts.
 */

import * as fs from 'node:fs';
import * as path from 'node:path';
import type { LogService } from '../domain/logging/LogService';
import { PromptCategory } from '../domain/prompts/PromptCategory';
import type { PromptDefinition } from '../domain/prompts/PromptCategory';
import { TemplateEngine } from '../domain/prompts/PromptTemplateEngine';
import type { TemplateContext } from '../domain/prompts/PromptTemplateEngine';
import type { TemplateRenderOptions } from '../domain/prompts/PromptTemplateEngine';
import type { Filesystem } from '../domain/system/Filesystem';

export class PromptLoader {
  private categoryMap: Map<string, PromptCategory> = this.initializeCategoryMap();

  constructor(
    private filesystem: Filesystem,
    private logService: LogService,
  ) {}

  /**
   * Basic category identification heuristic for unknown markdown files.
   */
  private initializeCategoryMap(): Map<string, PromptCategory> {
    return new Map([
      ['system', PromptCategory.SYSTEM_CORE],
      ['agent', PromptCategory.AGENT_ORCHESTRATION],
      ['tool', PromptCategory.TOOL_PROTOCOLS],
      ['memory', PromptCategory.MEMORY_CYCLES],
      ['verification', PromptCategory.VERIFICATION_CHECKPOINTS],
      ['utility', PromptCategory.UTILITY_OPERATIONS],
      ['security', PromptCategory.SECURITY_PATTERNS],
    ]);
  }

  /**
   * Loads and parses a single markdown prompt file.
   */
  async loadMarkdownFile(filepath: string): Promise<PromptDefinition> {
    const raw = this.filesystem.readFile(filepath);
    const { frontmatter, content } = this.parseTealiumMark(raw);

    return {
      id: this.generateId(filepath),
      category: this.classifyByMetadata(frontmatter, filepath),
      name: frontmatter.name || this.extractName(filepath),
      description: frontmatter.description || '',
      content: content,
      metadata: {
        source: filepath,
        formattedDate: frontmatter.date,
        tags: frontmatter.tags || [],
        version: frontmatter.version || '1.0.0',
        license: frontmatter.license || 'Apache-2.0',
        ...this.applyDietCodeMetadata(frontmatter),
      },
    };
  }

  /**
   * Parses the Tealium Mark format:
   * - Frontmatter in YAML (--- \n content \n ---)
   * - Supported template syntax: {{VAR}}, {% IF condition %}, {% INCLUDE file %}
   */
  private parseTealiumMark(content: string): { frontmatter: any; content: string } {
    const frontmatterRegex = /^---\s*\n([\s\S]*?)\n---\s*\n/;
    const match = content.match(frontmatterRegex);

    if (!match) {
      return { frontmatter: {}, content };
    }

    const frontmatterBlock = match[1]!;
    const bodyContent = content.substring(match[0].length);

    const frontmatter: any = {};

    // Parse YAML-style frontmatter
    frontmatterBlock.split('\n').forEach((line: string) => {
      const [key, ...valueParts] = line.split(':');
      if (key && valueParts.length > 0) {
        const value = valueParts.join(':').trim();
        frontmatter[key.trim()] = value.includes(',')
          ? value.split(',').map((v: string) => v.trim())
          : value;
      }
    });

    return { frontmatter, content: bodyContent };
  }

  private generateId(filepath: string): string {
    return `prompt_${path.basename(filepath, '.md')}_${Date.now().toString(36)}`;
  }

  private classifyByMetadata(frontmatter: any, filepath: string): PromptCategory {
    // Check for explicit category
    if (frontmatter.category && this.categoryMap.has(frontmatter.category.toLowerCase())) {
      return this.categoryMap.get(frontmatter.category.toLowerCase())!;
    }

    // Heuristic classification based on filename/content
    const contentLower = filepath.toLowerCase();
    if (contentLower.includes('memory') || contentLower.includes('consolidate')) {
      return PromptCategory.MEMORY_CYCLES;
    }
    if (
      contentLower.includes('tool') ||
      contentLower.includes('shell') ||
      contentLower.includes('file')
    ) {
      return PromptCategory.TOOL_PROTOCOLS;
    }
    if (
      contentLower.includes('verify') ||
      contentLower.includes('security') ||
      contentLower.includes('risk')
    ) {
      return PromptCategory.VERIFICATION_CHECKPOINTS;
    }
    if (contentLower.includes('agent') || contentLower.includes('orchestrate')) {
      return PromptCategory.AGENT_ORCHESTRATION;
    }

    // Default to SYSTEM_CORE
    return PromptCategory.SYSTEM_CORE;
  }

  private extractName(filepath: string): string {
    return path
      .basename(filepath, '.md')
      .replace(/_/g, ' ')
      .replace(/-/g, ' ')
      .split(' ')
      .map((word: string) => word.charAt(0).toUpperCase() + word.slice(1))
      .join(' ');
  }

  private applyDietCodeMetadata(frontmatter: any): Record<string, any> {
    const metadata: any = {};

    // Check for DietCode-specific metadata
    if (frontmatter.dietcode_feature) {
      metadata.dietcodeFeature = frontmatter.dietcode_feature;
    }

    if (frontmatter.memory_depth) {
      metadata.recommendedMemoryDepth = Number.parseInt(frontmatter.memory_depth);
    }

    if (frontmatter.danger_level) {
      metadata.dangerLevel = frontmatter.danger_level;
    }

    if (frontmatter.feedback_loop) {
      metadata.parentId = frontmatter.feedback_loop;
      metadata.expectedFlow = frontmatter.expected_flow || 'post_execution';
    }

    return metadata;
  }

  /**
   * Validates prompt safety and compliance.
   * Enforces strict constraints to prevent malicious behavior.
   */
  validatePrompt(prompt: PromptDefinition): boolean {
    // Rule 1: Content size limits
    if (prompt.content.length > 100000) {
      this.logService.warn(`[${prompt.id}] Prompt exceeds size limit (100KB)`, {
        promptId: prompt.id,
        size: prompt.content.length,
      });
      return false;
    }

    // Rule 2: Deny certain dangerous patterns
    const dangerousPatterns = [
      'eval(',
      'Function(',
      'process.exit(',
      'child_process.exec',
      'system.exec',
      'eval_',
    ];

    for (const pattern of dangerousPatterns) {
      if (prompt.content.includes(pattern)) {
        this.logService.warn(`[${prompt.id}] Contains dangerous pattern: ${pattern}`, {
          promptId: prompt.id,
          pattern,
        });
        return false;
      }
    }

    // Rule 3: Remove interactive controls if not explicitly intended
    if (
      prompt.content.includes('<button') ||
      prompt.content.includes('<input') ||
      prompt.content.includes('onclick=')
    ) {
      this.logService.warn(
        `[${prompt.id}] Contains interactive HTML elements (allowed only in secure contexts)`,
        { promptId: prompt.id },
      );
    }

    return true;
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Adapters and integrations — reactive prompt modification middleware.
 */

import type { EventBus } from '../core/orchestration/EventBus';
import type { SystemEvent } from '../domain/Event';
import { EventType } from '../domain/Event';
import type { LogService } from '../domain/logging/LogService';
import type { PromptDefinition } from '../domain/prompts/PromptCategory';

export type PromptModifier = (prompt: string, event: SystemEvent) => string;

export class PromptMiddlewareManager {
  private middlewareMap: Map<EventType, PromptModifier>;

  constructor(
    private eventBus: EventBus,
    private logService: LogService,
  ) {
    this.middlewareMap = new Map();
    this.initializeMiddlewareRegistry();
  }

  /**
   * Registers middleware functions for specific event types.
   * Middleware runs in reverse insertion order (last registered = highest priority).
   */
  registerMiddleware(eventType: EventType, modifier: PromptModifier): void {
    this.middlewareMap.set(eventType, modifier);
  }

  /**
   * Initializes the standard middleware registry with context-aware augmentations.
   */
  private initializeMiddlewareRegistry(): void {
    // 1. Snapshot-Induced Safety Warnings
    this.registerMiddleware(EventType.SNAPSHOT_CREATED, (prompt: string, event: SystemEvent) => {
      const filePath = event.data.filePath || 'unknown';
      const admonition = `
---
## [SUSPENSION ALERT]: Snapshot Created
**Action Disallowed:** File previously edited has been backed up to preview.
**Recommendation:** Smart verification of semantic equivalence before revert.
**Reference:** ${filePath}

Please verify schema integrity before proceeding.
---
        `.trim();

      return `${admonition}\n\n${prompt}`;
    });

    // 2. Memory Learning Pattern Injectors
    this.registerMiddleware(EventType.KNOWLEDGE_GAINED, (prompt: string, event: SystemEvent) => {
      const newItem = event.data.item;
      if (!newItem) return prompt;

      const insight = `
---
## [MEMORY INSIGHT]: Project Continuity Detected
**Capacity:** ${this.extrapolateCapacity(newItem)}
**Confidence:** ${Math.round(newItem.confidence * 100)}%

**Key Learnings:**
- ${this.summarizeLearning(newItem)}

**Recommendation:** Apply to relevant codebase patterns ${this.suggestApplication(newItem.key)}
---
        `.trim();

      return `${insight}\n\n${prompt}`;
    });

    // 3. Tool Success Rate Decay Prevention
    this.registerMiddleware(EventType.TOOL_CALL_FAILURE, (prompt: string, event: SystemEvent) => {
      const toolName = event.data.tool;
      const error = event.data.error || 'Unknown error';

      const correction = `
---
## [RECURSION DETECTED]: Previous Failure
**Tool:** ${toolName}
**Error:** ${error}
**Recall:** Fix broken invocations before recursive reattempt.

**Immediate Fixes:**
1. Verify command syntax against tool definitions
2. Check file permissions and path existence
3. Validate parameter types and constraints
4. Attempt dry-run mode if available

Refocus on stable subsystems before proceeding.
---
        `.trim();

      return `${correction}\n\n${prompt}`;
    });

    // 4. Context Relevance Detection
    this.registerMiddleware(EventType.CONTEXT_LOADED, (prompt: string, event: SystemEvent) => {
      const contextScope = event.data.scope || 'unknown';
      const discoveryType = event.data.discoveryType || 'unknown';

      const guidance = `
---
## [PROJECT CONTEXT]: Environment State
**Scope:** ${contextScope}
**Discovery Strategy:** ${discoveryType}

**Context Flags:**
${this.renderContextFlags(event.data, discoveryType)}

**Agent Guidance:** Align response strategy with discovered context patterns.
---
        `.trim();

      return `${guidance}\n\n${prompt}`;
    });

    // 5. Implementation Lifecycle Events
    this.registerMiddleware(
      EventType.IMPLEMENTATION_STARTED,
      (prompt: string, event: SystemEvent) => {
        const task = event.data.task;
        const suggestedStart = `
---
## [INITIALIZATION SEQUENCE]: Task Started
**Task ID:** ${event.id.substring(0, 8)}
**Instruction:** ${task}

**Recommended Sequence:**
1. Parse intent: Determine required modifications
2. Draft implementation plan: Modularize scope
3. Validate preconditions: Check dependencies and environment
4. Execute: Apply changes iteratively
5. Verify: Test modifications against requirements

Focus on extraction of penetrant logic before persistent commitment.
---
        `.trim();

        return `${suggestedStart}\n\n${prompt}`;
      },
    );

    // 6. Tool Success Tracking
    this.registerMiddleware(EventType.TOOL_CALL_SUCCESS, (prompt: string, event: SystemEvent) => {
      // Only apply feedback for critical tools
      if (event.data.tool === 'null') return prompt;

      const efficiency = `
---
## [OPERATIONAL VERIFICATION]: Tool Executed
**Tool:** ${event.data.tool}
**Result:** ${event.data.result ? this.summarizeResult(event.data.result) : 'Completed'}

**Observation:** Tool completed in detached mode. Trigger successful.
**Impact:** Updates applied to authoritative source.
---
        `.trim();

      return `${efficiency}\n\n${prompt}`;
    });
  }

  /**
   * Called when an event occurs during prompt assembly or execution.
   * Applies relevant middleware in reverse-registered order.
   */
  async modifyPromptOnEvent(
    promptBuffer: string,
    eventType: EventType,
    event: SystemEvent,
  ): Promise<string> {
    const modifiers = [...this.middlewareMap.entries()];

    // Filter for relevant modifiers (exact match or wildcard *)
    const relevantModifiers = modifiers.filter(
      ([type]) => type === eventType || (type as string) === '*',
    );

    if (relevantModifiers.length === 0) return promptBuffer;

    // Apply modifiers in reverse insertion order (last registered = highest priority)
    let modifiedPrompt = promptBuffer;

    for (const [eventType, modifier] of relevantModifiers.reverse()) {
      try {
        modifiedPrompt = modifier(modifiedPrompt, event);
      } catch (error) {
        // Log but don't discard prompt
        this.logService.error(`Middleware failed for ${eventType}:`, error, {
          component: 'PromptMiddlewareManager',
        });
      }
    }

    return modifiedPrompt;
  }

  /**
   * POST-COMMIT Prompt Adjustment
   * Hook into EventBus to post-process prompts immediately after LLM response.
   */
  async postProcessLLMResponse(
    originalQuery: string,
    llmResponse: string,
    events: SystemEvent[],
  ): Promise<string> {
    // Remove initial prompt from analysis (focus on response)
    const analysisPrompt = llmResponse;

    // Remove echo from query (if LLM echoed user input)
    const query = originalQuery.replace(/^(?:You are analyzing:|Input:|Query:)\s*/i, '');

    // Cascade through events in reverse chronological order
    let modifiedResponse = analysisPrompt;

    for (const event of events.reverse()) {
      const modifier = this.middlewareMap.get(event.type);
      if (modifier) {
        modifiedResponse = modifier(modifiedResponse, event);
      }
    }

    return modifiedResponse;
  }

  /**
   * INTERNAL: Heuristics for context augmentation
   */
  private extrapolateCapacity(item: any): string {
    if (item.confidence > 0.95) return 'Critical';
    if (item.confidence > 0.8) return 'High';
    if (item.confidence > 0.6) return 'Medium';
    return 'Low';
  }

  private summarizeLearning(item: any): string {
    const keyPart = item.key || item.id || '';
    const valuePart = item.value || item.value.value;

    if (this.lengthOf(valuePart) > 100) {
      return `${valuePart.substring(0, 100)}...`;
    }

    return valuePart;
  }

  private suggestApplication(key: string): string {
    if (key.includes('architecture')) return 'across modules';
    if (key.includes('api')) return 'in integration layer';
    if (key.includes('test')) return 'in test suite';
    if (key.includes('performance')) return 'where latency matters';
    return 'where applicable';
  }

  private renderContextFlags(eventData: any, discoveryType: string): string {
    const flags = [];

    if (discoveryType.includes('incremental')) {
      flags.push('✅ Recent changes indexed');
    }
    if (discoveryType.includes('retrieval')) {
      flags.push('✅ Semantic search active');
    }
    if (eventData.maxFiles) {
      flags.push(`⛔ File stats limited to ${eventData.maxFiles}`);
    }
    if (eventData.optimization === 'aggressive') {
      flags.push('⚡ Pruning applied aggressively');
    }

    return flags.join('\n');
  }

  private summarizeResult(result: any): string {
    if (typeof result === 'string') {
      if (result.length > 50) return `${result.substring(0, 50)}...`;
      return result;
    }

    if (typeof result === 'object' && result.lines) {
      return `${result.lines} line${result.lines > 1 ? 's' : ''} applied`;
    }

    return `${JSON.stringify(result).substring(0, 50)}...`;
  }

  private lengthOf(str: string): number {
    // Simple length calculation
    return str ? str.length : 0;
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Adapters and integrations — orchestrates multi-source prompt loading and merging.
 */

import * as path from 'node:path';
import { ContextProviderEngine } from '../core/capabilities/ContextProviderEngine';
import { RiskAwareCompositionStrategy } from '../core/capabilities/RiskAwareCompositionStrategy';
import type { ContextService } from '../core/context/ContextService';
import type { MemoryService } from '../core/memory/MemoryService';
import type { EventBus } from '../core/orchestration/EventBus';
import type { SystemEvent } from '../domain/Event';
import { EventType } from '../domain/Event';
import type { LogService } from '../domain/logging/LogService';
import type { KnowledgeItem } from '../domain/memory/Knowledge';
import type { ConflictResolution, PromptAudit } from '../domain/prompts/PromptAudit';
import { ConflictResolutionStrategy, ConflictType } from '../domain/prompts/PromptAudit';
import { PromptCategory } from '../domain/prompts/PromptCategory';
import type { PromptCollection, PromptDefinition } from '../domain/prompts/PromptCategory';
import { PromptSource, PromptSource as PromptSourceEnum } from '../domain/prompts/PromptIndex';
import type { PromptIndex, PromptSourceConfig } from '../domain/prompts/PromptIndex';
import { RiskTier } from '../domain/prompts/PromptRiskProfile';
import { TemplateEngine } from '../domain/prompts/PromptTemplateEngine';
import type {
  TemplateContext,
  TemplateRenderOptions,
} from '../domain/prompts/PromptTemplateEngine';
import type { Filesystem } from '../domain/system/Filesystem';
import type { PromptLoader } from './PromptLoader';

export class PromptRegistryAdapter {
  private currentIndex: PromptIndex;
  private activeContext: Record<string, any> = {};
  private conflictLogger: ConflictLogger;
  private contextProvider: ContextProviderEngine;
  private riskStrategy: RiskAwareCompositionStrategy;

  constructor(
    private filesystem: Filesystem,
    private eventBus: EventBus,
    private memoryService: MemoryService,
    private contextService: ContextService,
    private promptLoader: PromptLoader,
    private listSources: ListPromptsSourcesFunction,
    private loadSource: LoadPromptSourceFunction,
    private logService: LogService,
  ) {
    this.currentIndex = {
      version: '1.0.0',
      lastUpdated: new Date().toISOString(),
      rootSources: [],
      collections: [],
      auditTrail: [],
    };

    // Initialize context provider engine
    this.contextProvider = new ContextProviderEngine(memoryService, contextService);

    // Initialize risk-aware composition strategy
    this.riskStrategy = new RiskAwareCompositionStrategy();

    // Register risk strategy with context provider (broad type to avoid inference issues)
    (this.contextProvider as any).registerStrategy(this.riskStrategy);

    this.conflictLogger = new ConflictLogger(this.eventBus);
  }

  /**
   * Multi-source acquisition protocol.
   * Integrates prompts in strict priority order:
   * 1. Local Project Overrides (.dietcode/prompts/)
   * 2. User Repository Overrides (~/.claude-code-prompts/)
   * 3. Embedded Standard Collection (DietCode repo)
   */
  async acquireAll(context: SystemContext): Promise<PromptIndex> {
    const sources = await this.discoverSources();

    // Mark each source with priority
    const storedSources: PromptSourceConfig[] = sources.map((source, index) => ({
      origin: source.origin,
      path: source.path,
      priority: index + 1,
      loadedAt: new Date().toISOString(),
    }));

    // Merge all sources
    const merged = await this.mergeIndexedSets(storedSources);
    this.currentIndex.rootSources = storedSources.map((s) => s.origin);
    this.currentIndex.collections = merged.collections;
    this.currentIndex.lastUpdated = new Date().toISOString();

    // Emit event indicating successful load
    this.eventBus.publish(
      EventType.PROMPT_REGISTERED,
      {
        promptCount: merged.collections.reduce((sum, c) => sum + c.promptDefinitions.length, 0),
      },
      { sessionId: context.sessionId },
    );

    return this.currentIndex;
  }

  private async discoverSources(): Promise<Array<{ origin: PromptSourceEnum; path: string }>> {
    const sources: Array<{ origin: PromptSourceEnum; path: string }> = [];

    // Order matters: Project > User > Embedded
    const paths = [
      { origin: PromptSourceEnum.LOCAL_OVERRIDE, path: process.cwd() },
      { origin: PromptSourceEnum.USER_DEFINED, path: process.env.HOME || '/Users/dietcode' },
      { origin: PromptSourceEnum.REPOSITORY_BASE, path: process.cwd() },
    ];

    for (const { origin, path: basePath } of paths) {
      const promptPath = path.join(basePath, '.claude-code-prompts');

      try {
        const stats = this.filesystem.stat(promptPath);
        if (stats.isDirectory) {
          sources.push({ origin, path: promptPath });
        }
      } catch {
        // Path doesn't exist, skip
      }
    }

    return sources;
  }

  /**
   * Merges multiple sources into a unified prompt index using Conflict Resolver rules.
   */
  private async mergeIndexedSets(sources: PromptSourceConfig[]): Promise<PromptIndex> {
    const mergedCollections = new Map<string, PromptCollection>();
    const auditTrail: PromptAudit[] = [];

    for (const source of sources) {
      // Load chain for this source
      const loadChain: PromptAudit['loadChain'] = [
        {
          stepNumber: 1,
          sourcePath: source.path,
          action: 'MERGE',
          timestamp: new Date().toISOString(),
        },
      ];

      try {
        // Discover prompts in this source
        const promptPaths = await this.listPromptsFromSource(source.path);

        for (const promptPath of promptPaths) {
          const prompt = await this.loadSource(promptPath);

          // Initialize audit
          const promptAudit: PromptAudit = {
            promptId: prompt.id,
            source: source.origin,
            loadChain: [
              ...loadChain,
              {
                stepNumber: 2,
                sourcePath: promptPath,
                action: 'NEW_PROMPT',
                timestamp: new Date().toISOString(),
              },
            ],
            conflictHistory: [],
            integrityHash: this.calculateIntegrityHash(prompt),
            compliance: this.validateCompliance(prompt),
          };

          const existing = mergedCollections.get(prompt.id);

          if (!existing) {
            // Brand new prompt
            const newCollection = this.createCollectionWithPrompt(source.path, prompt);
            mergedCollections.set(prompt.id, newCollection);
            auditTrail.push(promptAudit);
          } else {
            // Conflict detected — apply resolution strategy
            const resolution = this.resolvePromptConflict(existing, prompt, source.priority);

            if (resolution.action === ConflictResolutionStrategy.OVERRIDE) {
              // Replace existing with incoming
              const overrideCollection = this.createCollectionWithPrompt(source.path, prompt);
              mergedCollections.set(prompt.id, overrideCollection);

              promptAudit.loadChain.push({
                stepNumber: 3,
                sourcePath: promptPath,
                action: 'OVERRIDE',
                timestamp: new Date().toISOString(),
              });
            } else {
              // Annotate existing with conflicting source metadata
              const annotated = this.annotatePrompt(existing, prompt, resolution);
              mergedCollections.set(prompt.id, annotated);

              // Track as conflict (but don't change the prompt)
              promptAudit.conflictHistory.push({
                id: crypto.randomUUID(),
                timestamp: new Date().toISOString(),
                type: ConflictType.PRIORITY_VIOLATION,
                resolution: resolution.action,
                affectedPrompts: [prompt.id],
                metadata: { incomingSource: source.origin, existingPriority: source.priority },
              });
            }

            auditTrail.push(promptAudit);
          }
        }
      } catch (error) {
        this.logService.error(`Failed to load prompts from ${source.path}:`, error, {
          component: 'PromptRegistryAdapter',
        });
        this.eventBus.publish(EventType.PROMPT_LOAD_ERROR, {
          path: source.path,
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    }

    return {
      version: '1.0.0',
      lastUpdated: new Date().toISOString(),
      rootSources: sources.map((s) => s.origin),
      collections: Array.from(mergedCollections.values()),
      auditTrail,
    };
  }

  private async listPromptsFromSource(sourcePath: string): Promise<readonly string[]> {
    try {
      return await this.listSources(sourcePath);
    } catch {
      return [];
    }
  }

  private resolvePromptConflict(
    existing: PromptCollection,
    incoming: PromptDefinition,
    incomingPriority: number,
  ): RoundResolutionResponse {
    // Lower priority number = higher priority
    const strategy =
      incomingPriority === 1
        ? ConflictResolutionStrategy.OVERRIDE
        : ConflictResolutionStrategy.KEEP_EXISTING;

    return {
      action: strategy,
      reason: this.getResolutionReason(strategy, incomingPriority),
    };
  }

  private createCollectionWithPrompt(
    sourcePath: string,
    prompt: PromptDefinition,
  ): PromptCollection {
    return {
      id: crypto.randomUUID(),
      category: prompt.category,
      name: prompt.name,
      version: '1.0.0',
      publisher: 'claude-code-prompts',
      licensing: 'Apache-2.0',
      subcollections: [sourcePath],
      promptDefinitions: [prompt],
    };
  }

  private annotatePrompt(
    existing: PromptCollection,
    incoming: PromptDefinition,
    resolution: RoundResolutionResponse,
  ): PromptCollection {
    return {
      ...existing,
      promptDefinitions: existing.promptDefinitions.map((p) =>
        p.id === incoming.id
          ? {
              ...p,
              metadata: {
                ...(p.metadata ?? {}),
                conflicts: p.metadata?.conflicts ?? {},
                lastConflictResolution: resolution.action,
              },
            }
          : p,
      ),
    };
  }

  private calculateIntegrityHash(prompt: PromptDefinition): string {
    // Simple hash based on content length + last modified time
    const source = prompt.metadata?.source ?? '';
    return `${prompt.content.length}-${new Date(source).getTime()}`;
  }

  private validateCompliance(prompt: PromptDefinition): PromptAudit['compliance'] {
    const violations: string[] = [];
    let valid = true;

    if (prompt.content.length > 100000) {
      violations.push('Prompt exceeds 100KB size limit');
      valid = false;
    }

    if (prompt.category === PromptCategory.SYSTEM_CORE && prompt.metadata?.dangerLevel) {
      violations.push('System core prompt cannot have dangerLevel metadata');
      valid = false;
    }

    return {
      valid,
      violations,
      category: prompt.category,
      hasInteractiveElements:
        prompt.content.includes('<button') || prompt.content.includes('<input'),
      exceedsSizeLimit: prompt.content.length > 100000,
    };
  }

  private getResolutionReason(action: ConflictResolutionStrategy, priority: number): string {
    switch (action) {
      case ConflictResolutionStrategy.OVERRIDE:
        return `Higher priority source (priority ${priority})`;
      case ConflictResolutionStrategy.KEEP_EXISTING:
        return `Existing prompt maintained (priority ${priority})`;
      case ConflictResolutionStrategy.PRUNE:
        return 'Duplicate removed';
      default:
        return 'Default resolution';
    }
  }

  private findPromptById(promptId: string): PromptDefinition | null {
    for (const collection of this.currentIndex.collections) {
      const found = collection.promptDefinitions.find((p) => p.id === promptId);
      if (found) return found;
    }
    return null;
  }

  /**
   * Retrieves memory requirements for a specific prompt.
   */
  async getMemoryRequirement(promptId: string): Promise<MemoryRequirement | null> {
    const prompt = this.findPromptById(promptId);
    if (!prompt) return null;

    const feature = prompt.metadata?.dietcodeFeature;
    switch (feature) {
      case 'MEMORY_CHECKPOINT':
        return {
          action: 'FETCH_CONSOLIDATED',
          targetScope: 'codebase',
          maxEntries: prompt.metadata?.recommendedMemoryDepth ?? 20,
          priority: 'critical',
        };
      case 'CONTEXT_PROTOCOL':
        return {
          action: 'FETCH_RECENT',
          targetScope: 'project',
          maxEntries: 10,
          priority: 'medium',
        };
      default:
        return null;
    }
  }

  /**
   * Retrieves verification requirements for a specific prompt.
   */
  async getVerificationRequirement(promptId: string): Promise<VerificationRequirement | null> {
    const prompt = this.findPromptById(promptId);
    if (!prompt || !prompt.dangerLevel) return null;

    const permissionTier = this.determinePermissionTier(prompt.dangerLevel);

    return {
      action: prompt.dangerLevel === 'high' ? 'RUN_SECURITY_CHECK' : 'RUN_HEALTH_CHECK',
      checkType: permissionTier,
      requiresSnapshot: prompt.dangerLevel !== 'low',
      verificationService: 'ValidationService',
      escalationStage: 'before_tool',
    };
  }

  private determinePermissionTier(
    dangerLevel: string,
  ): 'permission_tier_1' | 'permission_tier_2' | 'permission_tier_3' | 'permission_tier_4' {
    const level = dangerLevel.toLowerCase();

    switch (level) {
      case 'critical':
        return 'permission_tier_4';
      case 'high':
      case 'medium':
        return 'permission_tier_3';
      default:
        return 'permission_tier_1';
    }
  }

  /**
   * Renders a prompt with enhanced risk-aware context and composition.
   */
  async renderPrompt(
    promptId: string,
    sessionContext: Partial<TemplateContext>,
  ): Promise<{ rendered: string; template: PromptDefinition | null; metadata: any }> {
    const prompt = this.findPromptById(promptId);

    if (!prompt) {
      return { rendered: '', template: null, metadata: { error: 'Prompt not found' } };
    }

    const startTime = Date.now();

    // Step 1: Prepare enhanced context using ContextProviderEngine
    const enhancedContext = await this.contextProvider.prepareContext(prompt, sessionContext);

    // Step 2: Apply risk-aware composition strategy if applicable
    const riskNotes: string[] = [];
    if (this.riskStrategy.canApply(prompt, enhancedContext)) {
      const compositionResult = await this.riskStrategy.apply(prompt, enhancedContext);
      riskNotes.push(...compositionResult.notes);
    }

    // Step 2.5: Ensure risk assessment is available (for PromptRegistryAdapter usage)
    if ((this.riskStrategy as any).assessRisk) {
      const promptRisk = (this.riskStrategy as any).assessRisk(prompt, enhancedContext);
      // Use the assessment for other purposes if needed
    }

    // Step 3: Compile and render the final prompt
    const engine = new TemplateEngine();
    const options: TemplateRenderOptions = {
      trace: false,
      strict: true,
      defaultValues: {
        sessionId: enhancedContext.sessionId ?? '',
        timestamp: enhancedContext.timestamp ?? new Date().toISOString(),
      },
    };

    const promptContent = prompt.content;
    const rendered = engine.render(promptContent, enhancedContext as TemplateContext, options);
    const renderTimeMs = Date.now() - startTime;

    return {
      rendered,
      template: prompt,
      metadata: {
        promptId,
        category: prompt.category,
        variableCount: this.countVariables(promptContent),
        templateSizeKb: Math.round(rendered.length / 1024),
        renderTimeMs,
        enabledStrategies: ['context-provider', 'risk-aware-composition'],
        strategyNotes: riskNotes,
        memoryItemsLoaded: enhancedContext.memory?.items.length ?? 0,
      },
    };
  }

  /**
   * Generates a risk profile for a specific prompt execution.
   */
  async assessPromptRisk(promptId: string): Promise<{
    profile: any;
    recommendations: string[];
  }> {
    const prompt = this.findPromptById(promptId);

    if (!prompt) {
      return {
        profile: null,
        recommendations: ['Prompt not found, cannot assess risk'],
      };
    }

    const context = await this.contextProvider.prepareContext(prompt, {});
    const riskProfile = (this.riskStrategy as any).assessRisk(prompt, context);

    const recommendations =
      riskProfile.tier === RiskTier.HIGH
        ? [
            'Request explicit user approval before proceeding',
            'Prepare backup strategy',
            'Run tests in isolation environment',
            'Document rollback procedure',
          ]
        : riskProfile.tier === RiskTier.MEDIUM
          ? [
              'Test thoroughly before merging',
              'Prepare rollback script',
              'Communicate expected impact',
            ]
          : [
              'Standard testing applies',
              'Document any unexpected behavior',
              'Monitor commit history',
            ];

    return {
      profile: riskProfile,
      recommendations,
    };
  }

  /**
   * Returns a list of all prompts in a specific category.
   */
  findPromptsByCategory(category: PromptCategory): PromptDefinition[] {
    const results: PromptDefinition[] = [];
    for (const collection of this.currentIndex.collections) {
      results.push(...collection.promptDefinitions.filter((p) => p.category === category));
    }
    return results;
  }

  private countVariables(template: string): number {
    const matches = template.match(/\{\{[^}]+\}\}/g);
    return matches ? matches.length : 0;
  }
}

