/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Atomicity — groups multiple filesystem changes into a single transaction.
 * Implementation: Transactional staging with rollback support.
 */

import * as path from 'node:path';
import type { LogService } from '../domain/logging/LogService';
import type { Filesystem } from '../domain/system/Filesystem';
import type { RollbackManager } from './validation/RollbackManager';

export type TransactionChangeType = 'WRITE' | 'DELETE' | 'RENAME';

export interface TransactionChange {
  type: TransactionChangeType;
  path: string;
  previousContent?: string;
  newContent?: string;
  oldPath?: string; // used for RENAME
}

export class TransactionManager {
  private activeTransaction: TransactionChange[] = [];
  private isTransactionActive = false;

  constructor(
    private filesystem: Filesystem,
    private rollbackManager: RollbackManager,
    private logService: LogService,
  ) {}

  /**
   * Starts a new transaction.
   */
  startTransaction(): void {
    if (this.isTransactionActive) {
      throw new Error('Transaction already in progress');
    }
    this.activeTransaction = [];
    this.isTransactionActive = true;
    this.logService.info('[TRANSACTION] Started', {}, { component: 'TransactionManager' });
  }

  /**
   * Records a write operation in the current transaction.
   */
  async stageWrite(filePath: string, content: string): Promise<void> {
    this.ensureTransaction();

    let previousContent: string | undefined;
    if (this.filesystem.exists(filePath)) {
      previousContent = this.filesystem.readFile(filePath);
      await this.rollbackManager.backupFile(filePath, previousContent, 'Transaction backup');
    }

    this.activeTransaction.push({
      type: 'WRITE',
      path: filePath,
      previousContent,
      newContent: content,
    });
  }

  /**
   * Records a delete operation in the current transaction.
   */
  async stageDelete(filePath: string): Promise<void> {
    this.ensureTransaction();

    if (this.filesystem.exists(filePath)) {
      const previousContent = this.filesystem.readFile(filePath);
      await this.rollbackManager.backupFile(
        filePath,
        previousContent,
        'Transaction backup before delete',
      );

      this.activeTransaction.push({
        type: 'DELETE',
        path: filePath,
        previousContent,
      });
    }
  }

  /**
   * Commits the current transaction, applying all changes.
   */
  async commit(): Promise<void> {
    this.ensureTransaction();

    this.logService.info(
      `[TRANSACTION] Committing ${this.activeTransaction.length} changes...`,
      { count: this.activeTransaction.length },
      { component: 'TransactionManager' },
    );

    try {
      for (const change of this.activeTransaction) {
        if (change.type === 'WRITE') {
          this.filesystem.writeFile(change.path, change.newContent!);
        } else if (change.type === 'DELETE') {
          await this.filesystem.unlink(change.path);
        }
      }
      this.logService.info(
        '[TRANSACTION] Committed successfully',
        {},
        { component: 'TransactionManager' },
      );
    } catch (error: any) {
      this.logService.error(
        `[TRANSACTION] Commit failed: ${error.message}. Rolling back...`,
        error,
        { component: 'TransactionManager' },
      );
      await this.rollback();
      throw error;
    } finally {
      this.isTransactionActive = false;
      this.activeTransaction = [];
    }
  }

  /**
   * Aborts the current transaction and rolls back any backups.
   */
  async rollback(): Promise<void> {
    this.logService.info('[TRANSACTION] Rolling back...', {}, { component: 'TransactionManager' });
    await this.rollbackManager.fullRollback();
    this.isTransactionActive = false;
    this.activeTransaction = [];
  }

  private ensureTransaction(): void {
    if (!this.isTransactionActive) {
      throw new Error('No active transaction. Call startTransaction() first.');
    }
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Implementation of code validation.
 */

import { execSync } from 'node:child_process';
import * as fs from 'node:fs';
import * as path from 'node:path';
import type { SyntaxError, ValidationRepository, ValidationResult } from '../domain/Validation';

export class TypeScriptValidator implements ValidationRepository {
  /**
   * Validates a file's content using tsc --noEmit.
   */
  async validate(filePath: string, content: string): Promise<ValidationResult> {
    const ext = path.extname(filePath);
    if (!['.ts', '.tsx', '.js', '.jsx'].includes(ext)) {
      return { isValid: true, errors: [] };
    }

    // Create a temporary file for validation
    const tmpFile = path.join(path.dirname(filePath), `.tmp_validate_${path.basename(filePath)}`);
    fs.writeFileSync(tmpFile, content);

    try {
      // Using tsc with noEmit and a few basic flags
      const command = `npx tsc ${tmpFile} --noEmit --esModuleInterop --skipLibCheck --target esnext`;
      execSync(command, { encoding: 'utf-8', stdio: 'pipe' });

      return { isValid: true, errors: [] };
    } catch (error: any) {
      const output = error.stdout || error.stderr || '';
      const errors = this.parseErrors(output, tmpFile);

      return { isValid: false, errors };
    } finally {
      if (fs.existsSync(tmpFile)) fs.unlinkSync(tmpFile);
    }
  }

  private parseErrors(output: string, fileName: string): SyntaxError[] {
    const lines = output.split('\n');
    const errors: SyntaxError[] = [];

    // Simple regex to extract line, column, and message from tsc output
    const regex = /:(\d+):(\d+) - error TS\d+: (.*)/;

    for (const line of lines) {
      const match = line.match(regex);
      if (match) {
        const lineNum = match[1] ? Number.parseInt(match[1], 10) : 0;
        const colNum = match[2] ? Number.parseInt(match[2], 10) : 0;
        const msgText = match[3] || 'Unknown error';

        errors.push({
          line: lineNum,
          column: colNum,
          message: msgText,
        });
      }
    }

    return errors;
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Worker Proxy — the main-thread bridge for background auditing.
 * Pass 7: Distributed Architectural Auditing.
 */

import * as path from 'node:path';
import { Worker } from 'node:worker_threads';
import type { IntegrityScanner } from '../domain/integrity/IntegrityScanner';
import type { LogService } from '../domain/logging/LogService';
import type { IntegrityReport, IntegrityViolation } from '../domain/memory/Integrity';

export class WorkerIntegrityAdapter implements IntegrityScanner {
  private worker: Worker;

  constructor(private logService: LogService) {
    // Resolve worker path (assuming .js after build or using ts-node/register)
    const workerPath = path.resolve(__dirname, './workers/IntegrityWorker.ts');
    this.worker = new Worker(workerPath, {
      execArgv: ['-r', 'ts-node/register'],
    });

    this.logService.info(
      '[Worker] IntegrityWorker initialized (off-thread).',
      {},
      { component: 'WorkerIntegrityAdapter' },
    );
  }

  /**
   * Scans the whole project. (Currently synchronous in worker or sharded).
   */
  async scan(projectRoot: string): Promise<IntegrityReport> {
    return new Promise((resolve, reject) => {
      this.worker.postMessage({ type: 'PROJECT', projectRoot });
      this.worker.once('message', (res) => {
        if (res.success)
          resolve({
            score: 95, // Sharded placeholder
            violations: res.violations || [],
            scannedAt: new Date().toISOString(),
          });
        else reject(new Error(res.error));
      });
    });
  }

  /**
   * Scans a single file in the background thread.
   */
  async scanFile(filePath: string, projectRoot: string): Promise<IntegrityReport> {
    return new Promise((resolve, reject) => {
      this.worker.postMessage({ type: 'FILE', filePath, projectRoot });
      this.worker.once('message', (res) => {
        if (res.success)
          resolve({
            score: res.score,
            violations: res.violations,
            scannedAt: new Date().toISOString(),
          });
        else reject(new Error(res.error));
      });
    });
  }

  /**
   * Terminates the background worker.
   */
  terminate(): void {
    this.worker.terminate();
  }
}

import * as crypto from 'node:crypto';
import * as fs from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { Worker } from 'node:worker_threads';
import type { IntegrityScanner } from '../domain/integrity/IntegrityScanner';
import type { LogService } from '../domain/logging/LogService';
import type { IntegrityReport, IntegrityViolation } from '../domain/memory/Integrity';
import { JobType } from '../domain/system/QueueProvider';
import { Core } from './database/sovereign/Core';
import { SovereignWorkerProxy } from './queue/SovereignWorkerProxy';

export interface ShardResult {
  shardId: number;
  success: boolean;
  score: number;
  violations: IntegrityViolation[];
  time: number;
  error?: string;
}

export interface ScanPartitionRequest {
  type: 'SCAN_PARTITION';
  shardId: number;
  files: string[];
  scannerType: string;
  projectRoot: string;
}

export interface PoolMetrics {
  workerCount: number;
  completedWorkers: number;
  failedWorkers: number;
  totalCPUTime: number;
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Parallelized Integrity Checks via Worker Pool or Sovereign Queue.
 *
 * Strategy 1: Local Worker Pool (Fastest, High CPU Peak)
 * Strategy 2: Sovereign Queue (Throttled, Distributed)
 */
export class WorkerPoolAdapter {
  private workers: Worker[] = [];
  private completedResults: ShardResult[] = [];
  private projectRoot: string;
  private metrics!: PoolMetrics;
  private useQueue: boolean;
  private proxy: SovereignWorkerProxy;

  constructor(
    private scanner: IntegrityScanner,
    private logService: LogService,
    useQueue = true,
  ) {
    this.useQueue = useQueue;
    const cpuCores = os.cpus().length;
    this.projectRoot = path.resolve(process.cwd(), '.');

    const broccoliQueue: any = {
      enqueue: async (job: any) => {
        const qa = await Core.getQueue();
        return qa.enqueue(job);
      },
    };
    this.proxy = new SovereignWorkerProxy(broccoliQueue, logService);

    if (!this.useQueue) {
      // Spawn workers
      const workerPath = path.resolve(__dirname, './workers/ShardedIntegrityWorker.ts');
      this.workers = Array.from(
        { length: cpuCores },
        (_, i) =>
          new Worker(workerPath, {
            workerData: { shardId: i },
            execArgv: ['-r', 'tsx'],
          }),
      );

      // Listen for messages
      this.workers.forEach((worker, i) => {
        worker.on('message', (result: ShardResult) => {
          this.handleWorkerResult(i, result);
        });

        worker.on('error', (err: Error) => {
          this.logService.error(`Worker ${i} crashed: ${err.message}`, err, {
            component: 'WorkerPoolAdapter',
            nodeId: `worker-${i}`,
          });
          this.metrics.failedWorkers++;
        });
      });
    } else {
      this.logService.info(
        'WorkerPoolAdapter initialized in Sovereign Queue mode (Throttled CPU)',
        {},
        { component: 'WorkerPoolAdapter' },
      );
    }

    this.metrics = {
      workerCount: cpuCores,
      completedWorkers: 0,
      failedWorkers: 0,
      totalCPUTime: 0,
    };
  }

  async scan(projectRoot: string): Promise<IntegrityReport> {
    const startTime = Date.now();
    this.metrics.completedWorkers = 0;
    this.metrics.failedWorkers = 0;
    this.completedResults = [];

    // Step 1: Collect files
    const projectFiles = this.getAllTsFiles(path.join(projectRoot, 'src'));
    const fileCount = projectFiles.length;

    // Step 2: Sharding
    // We use cpu count or queue concurrency for shard count
    const shardCount = this.useQueue ? 8 : this.workers.length;
    this.logService.info(
      `Sharding ${fileCount} files across ${shardCount} workers (${Math.round(fileCount / shardCount)}/worker)`,
      { fileCount, shardCount },
      { component: 'WorkerPoolAdapter' },
    );

    const partitions: string[][] = Array.from({ length: shardCount }, () => []);
    projectFiles.forEach((file, index) => {
      const partition = partitions[index % shardCount];
      if (partition) {
        partition.push(path.relative(projectRoot, file));
      }
    });

    if (this.useQueue) {
      return this.scanViaQueue(partitions, projectRoot, startTime, fileCount);
    }

    // Step 3: Execute scan partitions (Local Workers)
    const promises = partitions.map((files, shardId) => {
      return new Promise<ShardResult>((resolve) => {
        // Send message to worker (WorkerPoolAdapter.ts:145)
        const worker = this.workers[shardId];
        if (worker) {
          worker.postMessage({
            type: 'SCAN_PARTITION',
            shardId,
            files,
            scannerType: 'IntegrityScanner',
            projectRoot,
          } as ScanPartitionRequest);

          // Listen for specific shard completion
          const listener = (result: ShardResult) => {
            if (result.shardId === shardId) {
              worker.removeListener('message', listener);
              resolve(result);
            }
          };
          worker.on('message', listener);
        }
      });
    });

    const shardResults = await Promise.all(promises);
    this.postProcessResults(shardResults, startTime);

    const maxScore = Math.max(
      0,
      100 - shardResults.reduce((acc, r) => acc + r.violations.length * 5, 0),
    );
    const combinedViolations = shardResults.flatMap((r) => r.violations);

    return {
      score: maxScore,
      violations: combinedViolations,
      scannedAt: new Date().toISOString(),
      fileCount,
    };
  }

  private getAllTsFiles(dir: string, fileList: string[] = []): string[] {
    if (!fs.existsSync(dir)) return fileList;

    const walkDir = (currentPath: string) => {
      const files = fs.readdirSync(currentPath);
      for (const file of files) {
        const filePath = path.join(currentPath, file);
        if (fs.statSync(filePath).isDirectory()) {
          if (
            !file.includes('node_modules') &&
            !file.includes('.git') &&
            !file.includes('.antigravity')
          ) {
            walkDir(filePath);
          }
        } else if (file.endsWith('.ts')) {
          fileList.push(filePath);
        }
      }
    };

    walkDir(dir);
    return fileList;
  }

  /**
   * Handle worker result and track metrics
   */
  private handleWorkerResult(index: number, result: ShardResult): void {
    this.completedResults[index] = result;
    this.metrics.completedWorkers++;
  }

  /**
   * Compute final metrics from completed results
   */
  private postProcessResults(results: ShardResult[], startTime: number): void {
    const failedCount = results.filter((r) => !r.success).length;
    const totalTime = Date.now() - startTime;

    results.forEach((r) => {
      if (r.error) {
        this.logService.warn(
          `Shard ${r.shardId} failed: ${r.error}`,
          { shardId: r.shardId, error: r.error },
          { component: 'WorkerPoolAdapter' },
        );
        this.metrics.failedWorkers++;
      }
    });

    this.metrics.totalCPUTime = totalTime;
    this.logService.info(
      `Scanned ${results.length} workers in ${totalTime}ms (${Math.round(totalTime / results.length)}ms/worker)`,
      { workerCount: results.length, totalTime },
      { component: 'WorkerPoolAdapter' },
    );
    if (failedCount > 0) {
      this.logService.warn(
        `${failedCount} workers failed`,
        { failedCount },
        { component: 'WorkerPoolAdapter' },
      );
    }
  }

  getMetrics(): PoolMetrics {
    return this.metrics;
  }

  /**
   * scanViaQueue: Strategy 2 - Distributed sharding via BroccoliQ
   */
  private async scanViaQueue(
    partitions: string[][],
    projectRoot: string,
    startTime: number,
    fileCount: number,
  ): Promise<IntegrityReport> {
    const shards = partitions.map((p) => ({
      files: p,
      projectRoot,
    }));

    const results = await this.proxy.executeDistributed<any, IntegrityReport>(
      JobType.INTEGRITY_SHARD,
      shards,
      { timeoutMs: 120000 },
    );

    const shardResults: ShardResult[] = results.map((r) => ({
      shardId: r.shardId,
      success: r.success,
      score: r.payload?.score || 0,
      violations: r.payload?.violations || [],
      time: 0,
      error: r.error,
    }));

    this.postProcessResults(shardResults, startTime);

    const maxScore = Math.max(
      0,
      100 - shardResults.reduce((acc, r) => acc + r.violations.length * 5, 0),
    );
    const combinedViolations = shardResults.flatMap((r) => r.violations);

    return {
      score: maxScore,
      violations: combinedViolations,
      scannedAt: new Date().toISOString(),
      fileCount,
    };
  }
}

import { PatternAnalysisService } from '../../core/capabilities/PatternAnalysisService';
import type { FileReuseDecision } from '../../domain/context/FileReadPattern';
import type { SignatureDatabase } from '../../domain/context/FileSignatureService';

/**
 * Optimizes context by reusing file content when possible
 */
export class ContextOptimizationService {
  private patternAnalyzer: PatternAnalysisService;
  private signatureDatabase: SignatureDatabase;
  private sessionStats = {
    totalFiles: 0,
    reuseCandidates: 0,
    discardedCandidates: 0,
    averageReuseConfidence: 0,
    totalReuseCount: 0,
  };

  constructor(signatureDatabase: SignatureDatabase, config?: any) {
    this.signatureDatabase = signatureDatabase;
    this.patternAnalyzer = new PatternAnalysisService(config);
  }

  async optimizeContext(
    targetFilePaths: string[],
    existingContext: Map<string, string>,
  ): Promise<{
    reuseDecisions: FileReuseDecision[];
    reusedContext: Map<string, string>;
    discardedContext: Map<string, string>;
    optimizationReport: string;
  }> {
    // signatures should be a Map<string, FileSignature> for the analyzer
    const signatureList = this.signatureDatabase.listSignatures();
    const signatureMap = new Map(
      signatureList.map((s) => [
        s.filePath,
        {
          filePath: s.filePath,
          hash: s.hash,
          sizeBytes: s.sizeBytes,
          timestamp: s.timestamp || Date.now(),
          isOutdated: (_size?: number) => false, // Default implementation
        },
      ]),
    );

    const decisions = this.patternAnalyzer.analyzePatternAvailability(
      targetFilePaths,
      signatureMap as any,
    );
    const optimizedDecisions = this.patternAnalyzer.optimizeSession(decisions, this.sessionStats);

    const reusedContext = new Map<string, string>();
    const discardedContext = new Map<string, string>();

    for (const decision of optimizedDecisions) {
      if (decision.shouldReuse && existingContext.has(decision.filePath)) {
        reusedContext.set(decision.filePath, existingContext.get(decision.filePath)!);
      } else {
        discardedContext.set(decision.filePath, existingContext.get(decision.filePath) || '');
      }
    }

    const updatedStats = this.patternAnalyzer.updateStatistics(
      optimizedDecisions,
      this.sessionStats,
    );
    this.sessionStats = updatedStats;

    const report = this.patternAnalyzer.generateReport(optimizedDecisions, updatedStats);

    return {
      reuseDecisions: optimizedDecisions,
      reusedContext,
      discardedContext,
      optimizationReport: report,
    };
  }

  recordFileContext(filePath: string, content: string): void {
    const hash = `hash-${Date.now()}`; // Mock hash for now or use real one
    const size = Buffer.byteLength(content, 'utf8');
    this.signatureDatabase.recordSignature(filePath, {
      filePath,
      hash,
      sizeBytes: size,
      timestamp: Date.now(),
      content: content,
      source: 'context_optimization',
      originalLength: size,
      optimizedLength: size,
      wasOptimized: false,
    });
  }

  resetSession(): void {
    this.sessionStats = {
      totalFiles: 0,
      reuseCandidates: 0,
      discardedCandidates: 0,
      averageReuseConfidence: 0,
      totalReuseCount: 0,
    };
  }

  getStatistics() {
    return { ...this.sessionStats };
  }
}

/**
 * [INFRASTRUCTURE: SIGNATURE_DATABASE]
 * Principle: Storage for optimized file signatures and context sessions
 * Violations: None - implements Domain interfaces through a specialized adapter
 */

import type { FileOptimizationDecision as OptimizationDecision } from '../../domain/context/FileMetadata';
import type { FileReadResult, FileReadSource } from '../../domain/context/FileOperation';

/**
 * SignatureDatabase stores optimized file reads and manages optimization sessions
 * Enables deduplication and context management based on file signatures
 */
export class SignatureDatabase {
  // Store optimized file signatures
  private signatureCache: Map<string, FileSignature> = new Map();

  // Store active optimization sessions
  private sessions: Map<string, OptimizationSession> = new Map();

  // Current active session ID
  private currentSessionId: string | null = null;

  // Configuration
  private maxSignatures = 1000;
  private maxSessionSize: number = 512 * 1024; // 512KB

  /**
   * Start a new optimization session
   */
  startSession(sessionId: string): void {
    this.currentSessionId = sessionId;
    this.sessions.set(sessionId, {
      id: sessionId,
      signatures: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
    });
  }

  /**
   * Get current session
   */
  getSession(sessionId?: string): OptimizationSession | null {
    const id = sessionId || this.currentSessionId;
    if (!id) return null;
    return this.sessions.get(id) || null;
  }

  /**
   * End current session
   */
  endSession(): OptimizationSession | null {
    if (!this.currentSessionId) return null;

    const session = this.getSession(this.currentSessionId);
    if (!session) return null;

    session.updatedAt = Date.now();
    const endedSession = this.sessions.get(this.currentSessionId) || null;

    // Move to signature cache
    session.signatures.forEach((signature) => {
      this.signatureCache.set(signature.filePath, signature);
    });

    // Limit cache size
    this.pruneCache();

    this.currentSessionId = null;
    return endedSession;
  }

  /**
   * Record a file read result
   */
  recordSignature(filePath: string, result: FileReadResult): FileSignature {
    // Check if signature already exists
    const existing = this.signatureCache.get(filePath);

    if (existing) {
      existing.lastReadTimestamp = result.timestamp;
      existing.readCount++;
      return existing;
    }

    // Create new signature
    const signature: FileSignature = {
      filePath,
      content: result.content,
      hash: result.hash,
      sizeBytes: result.sizeBytes,
      firstReadTimestamp: result.timestamp,
      lastReadTimestamp: result.timestamp,
      readCount: 1,
      source: result.source,
      optimized: result.wasOptimized,
      optimizationReason: result.optimizationReason,
      createdAt: Date.now(),
    };

    this.signatureCache.set(filePath, signature);
    this.pruneCache();

    return signature;
  }

  /**
   * Check if a file has been optimized (exists in cache)
   */
  isOptimized(filePath: string): boolean {
    return this.signatureCache.has(filePath);
  }

  /**
   * Get signature for a file
   */
  getSignature(filePath: string): FileSignature | null {
    return this.signatureCache.get(filePath) || null;
  }

  /**
   * List all signatures (pagination)
   */
  listSignatures(limit = 100, offset = 0): FileSignature[] {
    const signatures = Array.from(this.signatureCache.values());
    return signatures.slice(offset, offset + limit);
  }

  /**
   * Generate optimization recommendations from signatures
   */
  getOptimizationRecommendations(): OptimizationRecommendation[] {
    const recommendations: OptimizationRecommendation[] = [];

    // Find files that have been optimized
    const optimizedFiles = Array.from(this.signatureCache.values()).filter((sig) => sig.optimized);

    recommendations.push({
      type: 'optimized_files',
      count: optimizedFiles.length,
      message: `Found ${optimizedFiles.length} files that were optimized with two-finger pattern`,
    });

    // Find files with multiple reads
    const multiReadFiles = Array.from(this.signatureCache.values())
      .filter((sig) => sig.readCount > 1)
      .sort((a, b) => b.readCount - a.readCount)
      .slice(0, 5);

    if (multiReadFiles.length > 0) {
      recommendations.push({
        type: 'high_read_traffic',
        count: multiReadFiles.length,
        files: multiReadFiles.map((f) => f.filePath),
        message: `High read traffic on ${multiReadFiles.length} files`,
      });
    }

    return recommendations;
  }

  /**
   * Clear all signatures (entire cache)
   */
  clearCache(): void {
    this.signatureCache.clear();
    this.sessions.clear();
    this.currentSessionId = null;
  }

  /**
   * Prune cache size
   */
  private pruneCache(): void {
    while (this.signatureCache.size > this.maxSignatures) {
      // Remove oldest signatures (by first read timestamp)
      const signatures = Array.from(this.signatureCache.values()).sort(
        (a, b) => a.firstReadTimestamp - b.firstReadTimestamp,
      );

      if (signatures.length > 0 && signatures[0]) {
        this.signatureCache.delete(signatures[0].filePath);
      } else {
        break;
      }
    }
  }

  /**
   * Generate production-grade SHA-256 content hash
   */
  private async hashContent(content: string): Promise<string> {
    try {
      const encoder = new TextEncoder();
      const data = encoder.encode(content);
      const hashBuffer = await globalThis.crypto.subtle.digest('SHA-256', data);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      return hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
    } catch (error) {
      // Fallback for non-crypto environments
      let hash = 0;
      for (let i = 0; i < content.length; i++) {
        hash = (hash << 5) - hash + content.charCodeAt(i);
        hash = (hash & hash) >>> 0;
      }
      return hash.toString(36);
    }
  }
}

/**
 * Storage of file optimizations
 */
interface FileSignature {
  filePath: string;
  content: string;
  hash: string;
  sizeBytes: number;
  firstReadTimestamp: number;
  lastReadTimestamp: number;
  readCount: number;
  source: FileReadSource;
  optimized: boolean;
  optimizationReason?: string;
  createdAt: number;
}

/**
 * Optimization session
 */
interface OptimizationSession {
