          ];
        }
        throw new Error(`No column definition for table '${tableName}'`);
      })();

      const nonIdColumns = columnDefinitions.filter((col) => col !== 'id');

      // STEP 4: Template INSERT
      const idValue = generateId(['template']);
      const templateValues = nonIdColumns.map(() => `''`).join(', ');
      const columnsStr = columnDefinitions.join(', ');

      await Schema.withTimeout(
        Schema.withDbExecute(
          db,
          CompiledQuery.raw(
            `INSERT INTO ${tableName}_new (${columnsStr}) VALUES ('${idValue}', ${templateValues})`,
          ),
        ),
        Math.min(timeoutMs, 500),
        `Template INSERT for ${tableName}_new`,
      );

      // STEP 5: Migrate data row by row
      let rowCount = 0;
      const dataResult = await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`SELECT * FROM ${tableName}`)),
        Math.min(timeoutMs, 5000),
        `SELECT * from ${tableName}`,
      );

      // Handle result format properly
      let rows: any[];
      if (Array.isArray(dataResult)) {
        rows = dataResult;
      } else if (dataResult && typeof dataResult === 'object') {
        rows = dataResult.rows || dataResult.data || Object.values(dataResult);
      } else {
        rows = [];
      }

      console.log(`[NUCLEAR PATCH] ↳ Processing ${rows.length} rows of data...`);

      for (const row of rows) {
        // Generate id from row data
        const rowKey = nonIdColumns
          .map((col: string) => {
            const val = row[col];
            return val === undefined ? '' : String(val);
          })
          .join('|');

        const rowIdValue = generateId([tableName, rowKey]);

        // Build VALUES clause
        const rowValues = nonIdColumns
          .map((col: string) => {
            const val = row[col];
            const strVal = val === undefined ? '' : String(val).replace(/'/g, "''");
            return `'${strVal}'`;
          })
          .join(', ');

        await Schema.withTimeout(
          Schema.withDbExecute(
            db,
            CompiledQuery.raw(
              `INSERT INTO ${tableName}_new (${columnsStr}) VALUES ('${rowIdValue}', ${rowValues})`,
            ),
          ),
          Math.min(timeoutMs, 1000),
          `Insert row ${rowCount} into ${tableName}_new`,
        );
        rowCount++;
      }

      // STEP 6: Delete template row
      await Schema.withTimeout(
        Schema.withDbExecute(
          db,
          CompiledQuery.raw(`DELETE FROM ${tableName}_new WHERE id = '${idValue}'`),
        ),
        Math.min(timeoutMs, 500),
        'Delete template row',
      );

      console.log(`[NUCLEAR PATCH] ✅ Inserted ${rowCount} rows to new table`);

      // STEP 7: Atomic swap (DROP old, RENAME new)
      console.log(
        `[NUCLEAR PATCH] 🔄 Swapping tables: DROP '${tableName}', RENAME '${tableName}_new' to '${tableName}'`,
      );

      // Verify data integrity
      const originalCountResult = await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`SELECT COUNT(*) as count FROM ${tableName}`)),
        Math.min(timeoutMs, 2000),
        `COUNT rows in ${tableName}`,
      );

      let originalRowCount: number;
      if (Array.isArray(originalCountResult)) {
        originalRowCount = originalCountResult[0]?.count || 0;
      } else if (typeof originalCountResult === 'object' && originalCountResult !== null) {
        originalRowCount = originalCountResult?.[0]?.count || 0;
      } else {
        originalRowCount = 0;
      }

      // Count rows in new table
      const newCountResult = await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`SELECT COUNT(*) as count FROM ${tableName}_new`)),
        Math.min(timeoutMs, 2000),
        `COUNT rows in ${tableName}_new`,
      );

      let newRowCount: number;
      if (Array.isArray(newCountResult)) {
        newRowCount = newCountResult[0]?.count || 0;
      } else if (typeof newCountResult === 'object' && newCountResult !== null) {
        newRowCount = newCountResult?.[0]?.count || 0;
      } else {
        newRowCount = 0;
      }

      if (originalRowCount !== newRowCount) {
        throw new Error(
          `Data mismatch: ${originalRowCount} rows in original but ${newRowCount} in new table`,
        );
      }
      console.log(`[NUCLEAR PATCH] ✅ Data integrity verified: ${originalRowCount} rows`);

      // Drop old table
      await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`DROP TABLE ${tableName}`)),
        Math.min(timeoutMs, 3000),
        `DROP ${tableName}`,
      );

      // Rename new to old
      await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`ALTER TABLE ${tableName}_new RENAME TO ${tableName}`)),
        Math.min(timeoutMs, 3000),
        `RENAME ${tableName}_new to ${tableName}`,
      );

      // STEP 8: Verify patch
      await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`PRAGMA table_info(${tableName})`)),
        Math.min(timeoutMs, 2000),
        'PRAGMA table_info verify',
      );

      const patchedTableInfo = await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw(`PRAGMA table_info(${tableName})`)),
        Math.min(timeoutMs, 2000),
        'PRAGMA table_info final',
      );

      let patchedColumns: any[];
      if (Array.isArray(patchedTableInfo)) {
        patchedColumns = patchedTableInfo;
      } else if (patchedTableInfo && typeof patchedTableInfo === 'object') {
        patchedColumns =
          patchedTableInfo.rows || patchedTableInfo.data || Object.values(patchedTableInfo);
      } else {
        patchedColumns = [];
      }

      if (
        !Array.isArray(patchedColumns) ||
        !new Set(patchedColumns.map((col: any) => col.name)).has('id')
      ) {
        throw new Error(`Patching failed: 'id' column still missing after migration`);
      }

      // COMMIT
      await Schema.withTimeout(
        db.executeQuery(CompiledQuery.raw('COMMIT')),
        Math.min(timeoutMs, 2000),
        'COMMIT',
      );

      const elapsedTime = ((Date.now() - startTime) / 1000).toFixed(2);
      console.log(
        `[NUCLEAR PATCH] ✓ Table '${tableName}' SUCCESSFULLY PATCHED with 'id' in ${elapsedTime}s`,
      );
      return true;
    } catch (error: any) {
      // ROLLBACK on any error (COMMIT failed)
      try {
        await Schema.withTimeout(
          db.executeQuery(CompiledQuery.raw('ROLLBACK')),
          5000,
          'ROLLBACK (emergency)',
        );
      } catch (rollbackError) {
        // Ignore rollback errors
      }

      const elapsedTime = ((Date.now() - startTime) / 1000).toFixed(2);
      console.error(
        `[NUCLEAR PATCH] ❌ FAILED to patch table '${tableName}' after ${elapsedTime}s:`,
        error.message,
      );
      throw error;
    }
  }

  /**
   * Execute database operation with explicit timeout.
   * Prevents initialization hangs during DB operations.
   */
  private static async withTimeout(
    promise: Promise<any>,
    timeoutMs: number,
    operation: string,
  ): Promise<any> {
    const timeoutPromise = new Promise((_, reject) => {
      setTimeout(() => {
        reject(
          new Error(`[NUCLEAR PATCH] ⚠️  TIMEOUT after ${timeoutMs}ms on operation: ${operation}`),
        );
      }, timeoutMs);
    });

    return Promise.race([promise, timeoutPromise]);
  }

  /**
   * Helper to safely execute database query
   */
  private static withDbExecute(db: any, compiled: CompiledQuery<any>, timeoutMs?: number) {
    if (db.execute) {
      return db.execute(compiled);
    }
    return db.executeQuery(compiled);
  }

  static async ensureSchema(dbPool: any) {
    const startTime = Date.now();
    console.log('[NUCLEAR PATCH] 🚀 Starting atomic schema hardening...');

    let totalSuccessCount = 0;
    let totalSkipCount = 0;
    let totalFailCount = 0;

    // Get all active shards to ensure comprehensive hardening
    const shards = dbPool.getActiveShards ? dbPool.getActiveShards() : ['main'];
    console.log(`[NUCLEAR PATCH] 📡 Shards detected: ${shards.join(', ')}`);

    for (const shardId of shards) {
      console.log(`[NUCLEAR PATCH] 🧵 Patching shard: '${shardId}'`);
      const db = await dbPool.getDb(shardId);
      const results: Array<{ table: string; success: boolean; elapsed: number }> = [];

      // STEP 0: Atomic table-by-table patching
      for (const tableName of Schema.SYSTEM_TABLES) {
        const tableStart = Date.now();
        try {
          const patched = await Schema.patchSingleTable(db, tableName);
          if (patched) {
            totalSuccessCount++;
          } else {
            totalSkipCount++;
          }
          results.push({
            table: tableName,
            success: patched,
            elapsed: Date.now() - tableStart,
          });
        } catch (error) {
          totalFailCount++;
          console.error(
            `[NUCLEAR PATCH] ⚠️  Table '${tableName}' failed on shard '${shardId}', continuing...`,
          );
          results.push({ table: tableName, success: false, elapsed: Date.now() - tableStart });
        }
      }

      // STEP 1: Create Hive tables (namespaced)
      const execute = async (rawSql: string) => {
        try {
          await db.executeQuery(CompiledQuery.raw(rawSql));
        } catch (e) {}
      };

      await execute(
        'CREATE TABLE IF NOT EXISTS hive_kb (id TEXT PRIMARY KEY, knowledge_key TEXT NOT NULL, knowledge_value TEXT NOT NULL, type TEXT NOT NULL, confidence REAL NOT NULL, tags TEXT NOT NULL, metadata TEXT, created_at TEXT NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_healing_proposals (id TEXT PRIMARY KEY, violation_id TEXT NOT NULL, violation TEXT NOT NULL, rationale TEXT NOT NULL, proposed_code TEXT NOT NULL, status TEXT NOT NULL, confidence REAL DEFAULT 1.0, created_at TEXT NOT NULL, applied_at TEXT)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_snapshots (id TEXT PRIMARY KEY, path TEXT NOT NULL, content TEXT NOT NULL, timestamp INTEGER NOT NULL, hash TEXT NOT NULL, mtime INTEGER)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_file_context (id TEXT PRIMARY KEY, path TEXT NOT NULL, state TEXT NOT NULL, source TEXT NOT NULL, last_read_date INTEGER, last_edit_date INTEGER, signature TEXT, external_edit_detected INTEGER DEFAULT 0)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_audit (id TEXT PRIMARY KEY, session_id TEXT, type TEXT NOT NULL, message TEXT NOT NULL, data TEXT, timestamp INTEGER NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_agent_sessions (id TEXT PRIMARY KEY, agent_id TEXT NOT NULL, status TEXT NOT NULL, start_time INTEGER NOT NULL, end_time INTEGER)',
      );

      // STEP 2: Hive tables (Joy / Analysis)
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_joy_imports (id TEXT PRIMARY KEY, source_path TEXT NOT NULL, imported_path TEXT NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_joy_history (id TEXT PRIMARY KEY, violation_count INTEGER NOT NULL, file_count INTEGER NOT NULL, timestamp INTEGER NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_metabolic_telemetry (id TEXT PRIMARY KEY, task_id TEXT, reads INTEGER NOT NULL, writes INTEGER NOT NULL, lines_added INTEGER NOT NULL, lines_deleted INTEGER NOT NULL, tokens_processed INTEGER NOT NULL, verifications_success INTEGER NOT NULL, timestamp INTEGER NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_tasks (id TEXT PRIMARY KEY, task_id TEXT NOT NULL UNIQUE, title TEXT NOT NULL, objective TEXT NOT NULL, state TEXT NOT NULL, priority INTEGER NOT NULL, vitals_heartbeat TEXT, v_token TEXT, initial_context TEXT, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL, started_at INTEGER, completed_at INTEGER, user_agent TEXT NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_llm_telemetry (id TEXT PRIMARY KEY, repo_path TEXT NOT NULL, agent_id TEXT NOT NULL, task_id TEXT, prompt_tokens INTEGER, completion_tokens INTEGER, total_tokens INTEGER, model_id TEXT, cost REAL, timestamp INTEGER NOT NULL, environment TEXT)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_joy_metrics (id TEXT PRIMARY KEY, path TEXT NOT NULL, violation_count INTEGER NOT NULL, hash TEXT NOT NULL, last_scanned INTEGER NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_joy_bypasses (id TEXT PRIMARY KEY, path TEXT NOT NULL, violation_type TEXT NOT NULL, timestamp INTEGER NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_locks (id TEXT PRIMARY KEY, resource TEXT NOT NULL, owner_id TEXT NOT NULL, lock_code TEXT NOT NULL, expires_at INTEGER NOT NULL, acquired_at INTEGER NOT NULL)',
      );

      // STEP 3: Queue tables
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_queue (id TEXT PRIMARY KEY, type TEXT NOT NULL, status TEXT NOT NULL, total_shards INTEGER NOT NULL, completed_shards INTEGER DEFAULT 0, metadata TEXT, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL)',
      );
      await execute(
        'CREATE TABLE IF NOT EXISTS hive_job_results (id TEXT PRIMARY KEY, task_id TEXT NOT NULL, shard_id INTEGER NOT NULL, status TEXT NOT NULL, payload TEXT, error TEXT, priority INTEGER DEFAULT 0, timestamp INTEGER NOT NULL)',
      );

      // STEP 4: Create indexes
      await execute(
        'CREATE INDEX IF NOT EXISTS idx_hive_telemetry_task ON hive_llm_telemetry (task_id)',
      );
      await execute(
        'CREATE INDEX IF NOT EXISTS idx_hive_metabolic_task ON hive_metabolic_telemetry (task_id)',
      );
      await execute('CREATE INDEX IF NOT EXISTS idx_hive_kb_key ON hive_kb (knowledge_key)');
    }

    // STEP 5: Final summary
    const totalElapsed = ((Date.now() - startTime) / 1000).toFixed(2);
    console.log(`[NUCLEAR PATCH] 🏁 Schema hardening complete in ${totalElapsed}s`);
    console.log(
      `[NUCLEAR PATCH] 📊 Total Summary: ${totalSuccessCount} patched, ${totalSkipCount} skipped, ${totalFailCount} failed across all shards`,
    );

    if (totalFailCount > 0) {
      console.warn(
        `[NUCLEAR PATCH] ⚠️  ${totalFailCount} table(s) failed patching. Deployment may be unstable.`,
      );
    }
  }
}

import { Core } from './Core';

export class ScoringCache {
  /**
   * Get cached scoring result by content hash.
   */
  static async getScoringCache(hash: string): Promise<any | null> {
    const db = await Core.db();
    const result = await (db as any)
      .selectFrom('scoring_cache' as any)
      .selectAll()
      .where('hash', '=', hash)
      .executeTakeFirst();

    return result ? JSON.parse((result as any).result) : null;
  }

  /**
   * Store scoring result in cache.
   */
  static async setScoringCache(hash: string, result: any): Promise<void> {
    const db = await Core.db();
    await (db as any)
      .insertInto('scoring_cache' as any)
      .values({
        hash,
        result: JSON.stringify(result),
        timestamp: Date.now(),
      })
      .onConflict((oc: any) =>
        oc.column('hash').doUpdateSet({
          result: JSON.stringify(result),
          timestamp: Date.now(),
        }),
      )
      .execute();
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Concrete implementation of the LLM provider using Anthropic SDK.
 * Implements the Domain LLMProvider interface.
 * Uses structured logging for production-grade observability.
 */

import Anthropic from '@anthropic-ai/sdk';
import type { LLMProvider, LLMResponse } from '../../../domain/LLMProvider';
import type { Agent } from '../../../domain/agent/Agent';
import type { ToolDefinition } from '../../../domain/agent/ToolDefinition';
import type { Message } from '../../../domain/context/SessionState';
import type { LogService } from '../../../domain/logging/LogService';
import { Core } from '../../database/sovereign/Core';
import { MetabolicMonitor } from '../../monitoring/MetabolicMonitor';

export class AnthropicProvider implements LLMProvider {
  private client: Anthropic;
  private monitor = MetabolicMonitor.getInstance();

  constructor(
    apiKey: string,
    private logService: LogService,
  ) {
    this.client = new Anthropic({ apiKey });
  }

  async createMessage(
    agent: Agent,
    messages: Message[],
    tools: ToolDefinition[],
    metadata?: { taskId?: string },
  ): Promise<LLMResponse> {
    const startTime = Date.now();
    const response = await this.client.beta.messages.create({
      model: agent.model || 'claude-3-7-sonnet-20250219',
      system: agent.systemPrompt,
      max_tokens: agent.def.maxTokens || 4096,
      temperature: agent.def.temperature,
      messages: messages.map((m) => ({
        role: m.role as 'user' | 'assistant',
        content:
          typeof m.content === 'string'
            ? m.content
            : (m.content.map((block) => {
                if (block.type === 'text') return { type: 'text', text: block.text };
                if (block.type === 'image')
                  return {
                    type: 'image',
                    source: {
                      type: 'base64',
                      media_type: block.mimeType as any,
                      data: block.image,
                    },
                  };
                if (block.type === 'tool_use')
                  return {
                    type: 'tool_use',
                    id: block.id,
                    name: block.name,
                    input: block.input,
                  };
                if (block.type === 'tool_result')
                  return {
                    type: 'tool_result',
                    tool_use_id: block.tool_use_id,
                    content: block.content,
                    is_error: block.is_error,
                  };
                return { type: 'text', text: `[Unsupported block: ${block.type}]` };
              }) as any),
      })),
      tools: tools.map((t) => ({
        name: t.name,
        description: t.description,
        input_schema: t.inputSchema,
      })),
      betas: ['computer-use-2024-10-22'],
    });

    const completionTime = Date.now();

    // Log telemetry to BroccoliDB asynchronously
    this.logTelemetry(response, agent.id, completionTime - startTime, metadata?.taskId).catch(
      (err) => {
        this.logService.error(
          '[TELEMETRY] Failed to log telemetry data',
          { error: (err as Error).message, agentId: agent.id },
          { component: 'AnthropicProvider' },
        );
      },
    );

    const reasoning = response.content
      .filter((c: any) => c.type === 'thinking')
      .map((c: any) => ({
        text: c.thinking,
        type: 'text',
      }));

    const content = response.content.filter((c: any) => c.type !== 'thinking');

    const usage = {
      input_tokens: response.usage.input_tokens,
      output_tokens: response.usage.output_tokens,
    };

    // Instrument MetabolicMonitor
    this.monitor.recordTokens(usage.input_tokens + usage.output_tokens);

    return {
      content: content as any,
      usage,
      reasoning: reasoning.length > 0 ? reasoning : undefined,
    };
  }

  private async logTelemetry(response: any, agentId: string, duration: number, taskId?: string) {
    try {
      const db = await Core.db();
      const usage = response.usage;
      const modelId = response.model;

      const promptTokens = usage?.input_tokens ?? 0;
      const completionTokens = usage?.output_tokens ?? 0;
      const totalTokens = promptTokens + completionTokens;

      // Cost calculation for Claude 3.7 Sonnet
      const inputCost = (promptTokens / 1_000_000) * 3.0;
      const outputCost = (completionTokens / 1_000_000) * 15.0;
      const totalCost = inputCost + outputCost;

      await (db as any)
        .insertInto('hive_llm_telemetry' as any)
        .values({
          id: globalThis.crypto.randomUUID(),
          repo_path: process.cwd(),
          agent_id: agentId,
          task_id: taskId ?? null,
          prompt_tokens: promptTokens,
          completion_tokens: completionTokens,
          total_tokens: totalTokens,
          model_id: modelId,
          cost: totalCost,
          timestamp: Date.now(),
          environment: JSON.stringify({ duration, platform: process.platform }),
        } as any)
        .execute();
    } catch (error) {
      // Fail silently to not disrupt the main flow
    }
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Concrete implementation of the LLM provider using Cloudflare Workers AI.
 * Contains both Domain LLMProvider and Core LLMAdapter implementations.
 */

import { OpenAI } from 'openai';
import type { LLMProvider, LLMResponse } from '../../../domain/LLMProvider';
import type { Agent } from '../../../domain/agent/Agent';
import type {
  Message as AdapterMessage,
  ApiStream,
  LLMAdapter,
  ModelInfo,
} from '../../../domain/agent/LLMProviderAdapter';
import { PromptStrategy } from '../../../domain/agent/LLMProviderAdapter';
import type { ToolDefinition } from '../../../domain/agent/ToolDefinition';
import type { Message, MessageBlock } from '../../../domain/context/SessionState';
import type { LogService } from '../../../domain/logging/LogService';
import { Core } from '../../database/sovereign/Core';
import { MetabolicMonitor } from '../../monitoring/MetabolicMonitor';

export interface CloudflareConfig {
  accountId: string;
  apiToken: string;
  model?: string;
  logService: LogService;
}

/**
 * CloudflareProvider
 *
 * Domain-level provider for use with DietCode Agents.
 */
export class CloudflareProvider implements LLMProvider {
  private client: OpenAI;
  private monitor = MetabolicMonitor.getInstance();
  private model: string;
  private logService: LogService;

  constructor(config: CloudflareConfig) {
    this.model = config.model || '@cf/moonshotai/kimi-k2.5';
    this.logService = config.logService;

    this.client = new OpenAI({
      apiKey: config.apiToken,
      baseURL: `https://api.cloudflare.com/client/v4/accounts/${config.accountId}/ai/v1`,
    });
  }

  async createMessage(
    agent: Agent,
    messages: Message[],
    tools: ToolDefinition[],
    metadata?: { taskId?: string },
  ): Promise<LLMResponse> {
    const startTime = Date.now();
    const modelId = agent.model || this.model;

    try {
      const response = await this.client.chat.completions.create({
        model: modelId,
        messages: this.mapMessagesToOpenAI(agent.systemPrompt, messages),
        tools:
          tools.length > 0
            ? tools.map((t) => ({
                type: 'function',
                function: {
                  name: t.name,
                  description: t.description,
                  parameters: t.inputSchema,
                },
              }))
            : undefined,
        temperature: agent.def.temperature,
        max_tokens: agent.def.maxTokens || 4096,
      });

      const completionTime = Date.now();
      const choice = response.choices?.[0];
      if (!choice) {
        throw new Error('Cloudflare API returned no choices');
      }

      const message = choice.message;
      const content: MessageBlock[] = [];

      if (message.content) {
        content.push({ type: 'text', text: message.content });
      }

      if (message.tool_calls) {
        for (const tc of message.tool_calls) {
          content.push({
            type: 'tool_use',
            id: tc.id,
            name: tc.function.name,
            input: JSON.parse(tc.function.arguments),
          });
        }
      }

      const usage = {
        input_tokens: response.usage?.prompt_tokens ?? 0,
        output_tokens: response.usage?.completion_tokens ?? 0,
      };

      this.monitor.recordTokens(usage.input_tokens + usage.output_tokens);

      this.logTelemetry(response, agent.id, completionTime - startTime, metadata?.taskId).catch(
        (err) => {
          this.logService.error(
            '[TELEMETRY] Failed to log Cloudflare telemetry',
            { error: (err as Error).message, agentId: agent.id },
            { component: 'CloudflareProvider' },
          );
        },
      );

      return {
        content,
        usage,
      };
    } catch (error: any) {
      this.logService.error(
        `[CLOUDFLARE] API Error: ${error.message}`,
        { model: modelId },
        { component: 'CloudflareProvider' },
      );
      throw error;
    }
  }

  private mapMessagesToOpenAI(system: string, messages: Message[]): any[] {
    const mapped: any[] = [{ role: 'system', content: system }];

    for (const m of messages) {
      if (typeof m.content === 'string') {
        mapped.push({ role: m.role, content: m.content });
      } else {
        const textContent = m.content
          .filter((b) => b.type === 'text')
          .map((b) => (b as any).text)
          .join('\n');

        const toolCalls = m.content
          .filter((b) => b.type === 'tool_use')
          .map((b) => ({
            id: (b as any).id,
            type: 'function',
            function: {
              name: (b as any).name,
              arguments: JSON.stringify((b as any).input),
            },
          }));

        const toolResults = m.content
          .filter((b) => b.type === 'tool_result')
          .map((b) => ({
            role: 'tool',
            tool_call_id: (b as any).tool_use_id,
            content: (b as any).content,
          }));

        if (textContent || toolCalls.length > 0) {
          mapped.push({
            role: m.role,
            content: textContent || null,
            tool_calls: toolCalls.length > 0 ? toolCalls : undefined,
          });
        }

        if (toolResults.length > 0) {
          mapped.push(...toolResults);
        }
      }
    }
    return mapped;
  }

  private async logTelemetry(response: any, agentId: string, duration: number, taskId?: string) {
    try {
      const db = await Core.db();
      const usage = response.usage;
      const modelId = response.model;
      const promptTokens = usage?.prompt_tokens ?? 0;
      const model = response.model;
      const repoPath = process.cwd();

      await (db as any)
        .insertInto('hive_llm_telemetry' as any)
        .values({
          id: globalThis.crypto.randomUUID(),
          repo_path: repoPath,
          agent_id: agentId,
          task_id: taskId ?? null,
          prompt_tokens: usage.prompt_tokens,
          completion_tokens: usage.completion_tokens,
          total_tokens: usage.prompt_tokens + usage.completion_tokens,
          model_id: model,
          cost: 0, // Cloudflare Workers AI is often flat-rate or included
          timestamp: Date.now(),
          environment: JSON.stringify({
            duration,
            platform: process.platform,
            provider: 'cloudflare',
          }),
        } as any)
        .execute();
    } catch (error) {
      // Silent fail
    }
  }
}

/**
 * CloudflareAdapter
 *
 * Core-level adapter for registration and multi-provider orchestration.
 */
export class CloudflareAdapter implements LLMAdapter {
  private client: OpenAI;
  private model: string;

  constructor(config: Omit<CloudflareConfig, 'logService'>) {
    this.model = config.model || '@cf/moonshotai/kimi-k2.5';
    this.client = new OpenAI({
      apiKey: config.apiToken,
      baseURL: `https://api.cloudflare.com/client/v4/accounts/${config.accountId}/ai/v1`,
    });
  }

  createMessage(system: string, messages: AdapterMessage[], _tools?: any[]): ApiStream {
    const self = this;
    return {
      async *[Symbol.asyncIterator]() {
        const stream = await self.client.chat.completions.create({
          model: self.model,
          messages: [
            { role: 'system', content: system },
            ...messages.map((m) => ({
              role: m.role as any,
              content: m.content as string,
            })),
          ],
          stream: true,
        });

        for await (const chunk of stream) {
          const content = chunk.choices?.[0]?.delta?.content || '';
          if (content) yield content;
        }
      },
    } as any;
  }

  getModelInfo(): ModelInfo {
    return {
      id: this.model,
      name: `Cloudflare ${this.model}`,
      maxTokens: 256000,
      supportsPromptCache: true,
      supportsReasoning: true,
      supportsStreaming: true,
      costPerThousandTokens: {
        input: 0.0006,
        output: 0.003,
      },
    };
  }

  getThinkingBudgetTokenLimit(): number {
    return 0;
  }

  getPromptStrategy(): PromptStrategy {
    return PromptStrategy.OPENAI;
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Cohere embedding provider implementation
 *
 * Implements the EmbeddingService interface for Cohere embeddings.
 * Supports multi-lingual and optimized models.
 */

import type { EmbeddingService } from '../../../domain/agent/EmbeddingService';
import type {
  ApiStream,
  LLMAdapter,
  Message,
  ModelInfo,
} from '../../../domain/agent/LLMProviderAdapter';
import { PromptStrategy } from '../../../domain/agent/LLMProviderAdapter';
import type { ToolDefinition } from '../../../domain/agent/ToolDefinition';

/**
 * Cohere Embedding Adapter configuration
 */
export interface CohereEmbeddingConfig {
  apiKey: string;
  model: 'embed-english-v3.0' | 'embed-multilingual-v3.0' | 'embed-english-light-v3.0';
  batchSize?: number;
  timeoutMs?: number;
}

/**
 * Cohere Embedding Adapter
 *
 * Generates embeddings using Cohere's embedding models.
 * Supports multi-lingual (english, multilingual) and optimized models.
 *
 * Implements both EmbeddingService for RAG and LLMAdapter for the registry.
 */
export class CohereEmbeddingAdapter implements EmbeddingService, LLMAdapter {
  private apiKey: string;
  private model: string;
  private batchSize: number;
  private dimension: number;

  constructor(config: CohereEmbeddingConfig) {
    this.apiKey = config.apiKey;
    this.model = config.model;
    this.batchSize = config.batchSize || 100; // Cohere recommends 100 for best performance

    // Set dimension based on model
    switch (this.model) {
      case 'embed-english-v3.0':
      case 'embed-english-light-v3.0':
        this.dimension = 1024;
        break;
      case 'embed-multilingual-v3.0':
        this.dimension = 1024;
        break;
      default:
        this.dimension = 1024;
    }
  }

  /**
   * Generate an embedding for a single text chunk
   */
  async generateEmbedding(text: string): Promise<number[]> {
    if (!text || text.trim().length === 0) {
      throw new Error('Cannot generate embedding from empty text');
    }

    try {
      const response = await fetch('https://api.cohere.ai/v1/embed', {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: this.model,
          texts: [text],
        }),
      });

      if (!response.ok) {
        const error = await response.text();
        throw new Error(`Cohere API error ${response.status}: ${error}`);
      }

      const data = (await response.json()) as any;

      return data.embeddings[0];
    } catch (error: any) {
      throw new Error(`Cohere embedding generation failed: ${error.message}`);
    }
  }

  /**
   * Generate embeddings for multiple text chunks in batch
   */
  async generateBatchEmbeddings(texts: string[]): Promise<number[][]> {
    if (!texts || texts.length === 0) {
      return [];
    }

    const cleanedTexts = texts.filter((t) => t && t.trim().length > 0);

    // Send in batches if it's larger than the limit
    const batches: string[][] = [];
    for (let i = 0; i < cleanedTexts.length; i += this.batchSize) {
      batches.push(cleanedTexts.slice(i, i + this.batchSize));
    }

    const allEmbeddings: number[][] = [];

    for (const batch of batches) {
      try {
        const response = await fetch('https://api.cohere.ai/v1/embed', {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            model: this.model,
            texts: batch,
          }),
        });

        if (!response.ok) {
          const error = await response.text();
          throw new Error(`Cohere API error ${response.status}: ${error}`);
        }

        const data = (await response.json()) as any;
        allEmbeddings.push(...data.embeddings);
      } catch (error: any) {
        throw new Error(`Cohere batch embedding generation failed: ${error.message}`);
      }
    }

    return allEmbeddings;
  }

  /**
   * Get the dimension of generated embeddings
   */
  getDimension(): number {
    return this.dimension;
  }

  /**
   * Check if this service supports a given provider
   */
  isProviderSupported(providerId: string): boolean {
    return providerId.toLowerCase() === 'cohere';
  }

  /**
   * Get the provider ID used by this service
   */
  getProviderId(): string {
    return 'cohere';
  }

  /**
   * Get the current model being used
   */
  getModel(): string {
    return this.model;
  }

  /**
   * Get model metadata
   */
  getModelInfo(): ModelInfo {
    return {
      id: this.model,
      name: `Cohere ${this.model}`,
      maxTokens: 4096,
      supportsPromptCache: false,
      supportsReasoning: false,
      supportsStreaming: false,
    };
  }

  /**
   * Message creation (not supported)
   */
  createMessage(_system: string, _messages: Message[], _tools?: ToolDefinition[]): ApiStream {
    throw new Error('Message creation not supported in embedding adapter');
  }

  /**
   * Embedding (maps to generateEmbedding)
   */
  async embedText(text: string): Promise<number[]> {
    return this.generateEmbedding(text);
  }

  /**
   * Thinking budget (not applicable)
   */
  getThinkingBudgetTokenLimit(): number {
    return 0;
  }

  /**
   * Prompt strategy
   */
  getPromptStrategy(): PromptStrategy {
    return PromptStrategy.COHERE;
  }
}

