import { OpenAI } from 'openai';
import type { EmbeddingService } from '../../../domain/agent/EmbeddingService';
import type {
  ApiStream,
  LLMAdapter,
  Message,
  ModelInfo,
} from '../../../domain/agent/LLMProviderAdapter';
import { PromptStrategy } from '../../../domain/agent/LLMProviderAdapter';
import type { ToolDefinition } from '../../../domain/agent/ToolDefinition';

/**
 * OpenAI Embedding Adapter configuration
 */
export interface OpenAIEmbeddingConfig {
  apiKey: string;
  model: 'text-embedding-3-small' | 'text-embedding-3-large' | 'text-embedding-ada-002';
  organizationId?: string;
  timeoutMs?: number;
}

/**
 * OpenAI Embedding Adapter
 *
 * Generates embeddings using OpenAI's embedding models.
 * Supports batch generation for efficiency and rate limit adherence.
 *
 * Implements both EmbeddingService for RAG and LLMAdapter for the registry.
 */
export class OpenAIEmbeddingAdapter implements EmbeddingService, LLMAdapter {
  private client: OpenAI;
  private model: string;
  private dimension: number;

  constructor(config: OpenAIEmbeddingConfig) {
    this.model = config.model;

    const openaiConfig: any = {
      apiKey: config.apiKey,
      organization: config.organizationId,
      timeout: config.timeoutMs || 30000,
    };

    this.client = new OpenAI(openaiConfig);

    // Set dimension based on model
    switch (this.model) {
      case 'text-embedding-3-small':
        this.dimension = 1536;
        break;
      case 'text-embedding-3-large':
        this.dimension = 3072;
        break;
      case 'text-embedding-ada-002':
        this.dimension = 1536;
        break;
      default:
        this.dimension = 1536;
    }
  }

  /**
   * Generate an embedding for a single text chunk
   */
  async generateEmbedding(text: string): Promise<number[]> {
    if (!text || text.trim().length === 0) {
      throw new Error('Cannot generate embedding from empty text');
    }

    try {
      const result = await this.client.embeddings.create({
        model: this.model,
        input: text,
      });

      const embedding = result.data[0]?.embedding;
      if (!embedding) {
        throw new Error('OpenAI returned empty embedding data');
      }

      return embedding;
    } catch (error: any) {
      throw new Error(`OpenAI embedding generation failed: ${error.message}`);
    }
  }

  /**
   * Generate embeddings for multiple text chunks in batch
   */
  async generateBatchEmbeddings(texts: string[]): Promise<number[][]> {
    if (!texts || texts.length === 0) {
      return [];
    }

    if (texts.length === 1 && texts[0]) {
      return [await this.generateEmbedding(texts[0])];
    }

    const cleanTexts = texts.filter((t) => t && t.trim().length > 0);

    try {
      const result = await this.client.embeddings.create({
        model: this.model,
        input: cleanTexts,
      });

      if (!result.data || result.data.length === 0) {
        throw new Error('OpenAI returned empty batch embedding data');
      }

      return result.data.map((point: any) => point.embedding);
    } catch (error: any) {
      throw new Error(`OpenAI batch embedding generation failed: ${error.message}`);
    }
  }

  /**
   * Get the dimension of generated embeddings
   */
  getDimension(): number {
    return this.dimension;
  }

  /**
   * Check if this service supports a given provider
   */
  isProviderSupported(providerId: string): boolean {
    return providerId.toLowerCase() === 'openai';
  }

  /**
   * Get the provider ID used by this service
   */
  getProviderId(): string {
    return 'openai';
  }

  /**
   * Get the current model being used
   */
  getModel(): string {
    return this.model;
  }

  /**
   * Stub for message creation (not supported by embedding adapter)
   */
  createMessage(_system: string, _messages: Message[], _tools?: ToolDefinition[]): ApiStream {
    throw new Error('OpenAIEmbeddingAdapter does not support message creation');
  }

  /**
   * Get model metadata
   */
  getModelInfo(): ModelInfo {
    return {
      id: this.model,
      name: `OpenAI ${this.model}`,
      maxTokens: 8191,
      supportsPromptCache: false,
      supportsReasoning: false,
      supportsStreaming: false,
    };
  }

  /**
   * Generate embeddings (satisfied by generateEmbedding)
   */
  async embedText(text: string): Promise<number[]> {
    return this.generateEmbedding(text);
  }

  /**
   * Thinking budget (not applicable)
   */
  getThinkingBudgetTokenLimit(): number {
    return 0;
  }

  /**
   * Prompt strategy
   */
  getPromptStrategy(): PromptStrategy {
    return PromptStrategy.OPENAI;
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Persistent Audit Logging — sinks logs into modular Sovereign infrastructure.
 * Implementation: LogService adapter.
 */

import type { LogEntry, LogMetadata } from '../../domain/logging/LogEntry';
import { LogLevel } from '../../domain/logging/LogLevel';
import type { LogService } from '../../domain/logging/LogService';
import { Core } from '../database/sovereign/Core';

export class SovereignLogAdapter implements LogService {
  private minLevel: LogLevel = LogLevel.INFO;
  private currentSessionId: string | null = null;

  constructor(sessionId?: string) {
    if (sessionId) this.currentSessionId = sessionId;
  }

  setSessionId(sessionId: string): void {
    this.currentSessionId = sessionId;
  }

  error(message: string, data?: unknown, metadata?: LogMetadata): void {
    this.log(LogLevel.ERROR, message, data, metadata);
  }

  warn(message: string, data?: unknown, metadata?: LogMetadata): void {
    this.log(LogLevel.WARN, message, data, metadata);
  }

  info(message: string, data?: unknown, metadata?: LogMetadata): void {
    this.log(LogLevel.INFO, message, data, metadata);
  }

  debug(message: string, data?: unknown, metadata?: LogMetadata): void {
    this.log(LogLevel.DEBUG, message, data, metadata);
  }

  private log(level: LogLevel, message: string, data?: unknown, metadata?: LogMetadata): void {
    if (level < this.minLevel) return;

    // Console output for immediate visibility
    const timestamp = new Date().toISOString();
    console.log(`[${timestamp}] [${level}] ${message}`, data || '');

    // Persistent Audit Log
    void this.persistAuditLog(level, message, data, metadata);
  }

  private async persistAuditLog(
    level: LogLevel,
    message: string,
    data?: unknown,
    metadata?: LogMetadata,
  ): Promise<void> {
    try {
      const db = await Core.db();
      const id = globalThis.crypto.randomUUID();

      await (db as any)
        .insertInto('audit_log' as any)
        .values({
          id,
          sessionId: this.currentSessionId,
          type: level,
          message,
          data: data ? JSON.stringify(data) : null,
          timestamp: Date.now(),
        })
        .execute();
    } catch (error) {
      // Fail silently to prevent logging loops if DB is down
      console.error('❌ Failed to persist audit log:', error);
    }
  }

  logEntry(entry: LogEntry): void {
    this.log(entry.level, entry.message, entry.data, entry.metadata);
  }

  setMinLevel(level: LogLevel): void {
    this.minLevel = level;
  }

  getMinLevel(): LogLevel {
    return this.minLevel;
  }
}

/**
 * [LAYER: CORE]
 * Principle: Active Integrity Guard — detecting "The Unseen Edit."
 * Pass 5: Supreme Sovereign Hardening.
 */

import * as crypto from 'node:crypto';
import * as fs from 'node:fs';
import { Core } from '../database/sovereign/Core';

export class ActiveIntegrityScanner {
  /**
   * Verifies that the file on disk matches the last known state in the database.
   * Detects external edits performed outside the Sovereign Protocol.
   */
  async verifyFileIntegrity(filePath: string): Promise<{ clear: boolean; reason?: string }> {
    if (!fs.existsSync(filePath)) return { clear: true };

    const db = await Core.db();
    const context = (await (db as any)
      .selectFrom('file_context' as any)
      .select(['signature', 'path'])
      .where('path', '=', filePath)
      .executeTakeFirst()) as any;

    if (!context || !context.signature) {
      // First time seeing this file, record it
      const content = fs.readFileSync(filePath, 'utf8');
      const signature = this.calculateHash(content);
      await this.recordFileState(filePath, signature);
      return { clear: true };
    }

    const currentContent = fs.readFileSync(filePath, 'utf8');
    const currentSignature = this.calculateHash(currentContent);

    if (currentSignature !== context.signature) {
      // External Edit Detected!
      await (db as any)
        .updateTable('file_context' as any)
        .set({ externalEditDetected: 1 })
        .where('path', '=', filePath)
        .execute();

      return {
        clear: false,
        reason:
          'External Edit Detected: File content does not match last known Sovereign signature.',
      };
    }

    return { clear: true };
  }

  /**
   * Records the current sovereign signature of a file.
   */
  async recordFileState(filePath: string, signature: string): Promise<void> {
    const db = await Core.db();
    await (db as any)
      .insertInto('file_context' as any)
      .values({
        path: filePath,
        state: 'SOVEREIGN',
        source: 'INTERNAL',
        signature,
        lastReadDate: Date.now(),
        externalEditDetected: 0,
      })
      .onConflict((oc: any) =>
        oc.column('path').doUpdateSet({
          signature,
          externalEditDetected: 0,
          lastReadDate: Date.now(),
        }),
      )
      .execute();
  }

  private calculateHash(content: string): string {
    return crypto.createHash('sha256').update(content).digest('hex');
  }
}

/**
 * [LAYER: INFRASTRUCTURE]
 * Principle: Real-Time Metabolic Observation — instruments the environment.
 * Implements Pass 17: Metabolic Live-Monitor (v6.0).
 */

import * as crypto from 'node:crypto';
/**
 * MetabolicMonitor: Singleton service for environment-wide instrumentation.
 * Tracks I/O operations, token consumption, and verification signals.
 */
import { Core } from '../database/sovereign/Core';

export interface BrainMetrics {
  tokensProcessed: number;
  verificationsSuccess: number;
  linesAdded: number;
  linesDeleted: number;
  reads: number;
  writes: number;
}

export class MetabolicMonitor {
  private static instance: MetabolicMonitor;
  private currentTaskId: string | null = null;

  private metrics: BrainMetrics = {
    tokensProcessed: 0,
    verificationsSuccess: 0,
    linesAdded: 0,
    linesDeleted: 0,
    reads: 0,
    writes: 0,
  };

  private hotspots: Map<string, number> = new Map();

  private constructor() {
    // Pass 17: Background Metabolic Flush Interval (30s)
    setInterval(() => {
      if (this.currentTaskId && Core.isAvailable()) {
        this.flushToDatabase(this.currentTaskId).catch((err) => {
          // Silent fail in interval to avoid spamming console during tests
        });
      }
    }, 30000);
  }

  /**
   * Sets the active task ID for metabolic tracking.
   */
  public setTaskId(taskId: string): void {
    this.currentTaskId = taskId;
  }

  /**
   * Access the global metabolic monitor instance.
   */
  public static getInstance(): MetabolicMonitor {
    if (!MetabolicMonitor.instance) {
      MetabolicMonitor.instance = new MetabolicMonitor();
    }
    return MetabolicMonitor.instance;
  }

  /**
   * Persists the current metabolic window to the database.
   */
  public async flushToDatabase(taskId: string): Promise<void> {
    const db = await Core.db();
    const metrics = this.getMetrics();

    // Pass 17: Zero-Wait Telemetry Persistence
    await (db as any)
      .insertInto('hive_metabolic_telemetry' as any)
      .values({
        id: crypto.randomUUID(),
        task_id: taskId,
        tokens_processed: metrics.tokensProcessed,
        verifications_success: metrics.verificationsSuccess,
        lines_added: metrics.linesAdded,
        lines_deleted: metrics.linesDeleted,
        reads: metrics.reads,
        writes: metrics.writes,
        timestamp: Date.now(),
      })
      .execute();

    this.resetMetrics();
  }

  // --- Instrumentation Hooks ---

  public recordRead(path?: string): void {
    this.metrics.reads++;
    if (path) {
      this.hotspots.set(path, (this.hotspots.get(path) || 0) + 1);
    }
  }

  public recordWrite(path?: string, linesAdded = 0, linesDeleted = 0): void {
    this.metrics.writes++;
    this.metrics.linesAdded += linesAdded;
    this.metrics.linesDeleted += linesDeleted;
    if (path) {
      this.hotspots.set(path, (this.hotspots.get(path) || 0) + 2); // Writes weighted double
    }
  }

  public recordTokens(count: number): void {
    this.metrics.tokensProcessed += count;
  }

  public recordVerification(success: boolean): void {
    if (success) {
      this.metrics.verificationsSuccess++;
    }
  }

  /**
   * Identifies the file with the most metabolic activity in the current window.
   */
  public getHotspot(): string | null {
    let top = null;
    let max = 0;
    for (const [path, count] of this.hotspots.entries()) {
      if (count > max) {
        max = count;
        top = path;
      }
    }
    return top;
  }

  // --- Observation Interface ---

  /**
   * Captures the current metabolic state as a snapshot.
   */
  public getMetrics(): BrainMetrics {
    return { ...this.metrics };
  }

  /**
   * Clears the current window (used after a task or checkpoint flush).
   */
  public resetMetrics(): void {
    this.metrics = {
      tokensProcessed: 0,
      verificationsSuccess: 0,
      linesAdded: 0,
      linesDeleted: 0,
      reads: 0,
      writes: 0,
    };
    this.hotspots.clear();
  }

  /**
   * Calculates the current doubt signal (Read:Write ratio).
   */
  public getDoubtSignal(): number {
    return this.metrics.reads / (this.metrics.writes || 1);
  }
}

