  console.log(`${COLORS.cyan}${COLORS.bold}🛡️  TOOL SECURITY VERIFICATION SUITE${COLORS.reset}`);
  console.log(`${COLORS.cyan}${'='.repeat(50)}${COLORS.reset}\n`);

  const checks: VerificationCheck[] = [];

