  // Phase 6: Summary & Reporting
  console.log(`\n${COLORS.magenta}PHASE 6: VERIFICATION SUMMARY${COLORS.reset}`);
  console.log('────────────────────────────────────────────');

  const passed = checks.filter((c) => c.passed).length;
